int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile a[i], we can add min_val to it
            // as long as a[i] + min_val <= k
            // The number of times is (k - a[i]) / min_val
            total_operations += (k - a[i]) / min_val;
        }
        std::cout << total_operations << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> result_a(n);
        std::vector<int> result_b(n);

        for (int i = 0; i < n; ++i) {
            result_a[a[i].original_index] = a[i].value;
            result_b[a[i].original_index] = b[i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << result_a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << result_b[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of any permutation p, let's call it p_rev,
    // has the same set of adjacent sums as p.
    // If p = [p_1, p_2, ..., p_n], then p_rev = [p_n, p_{n-1}, ..., p_1].
    // The adjacent sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The adjacent sums for p_rev are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These two sets of sums are identical, just in reverse order.
    // Sorting them will result in the same fingerprint.
    // Since n >= 2, p_rev will always be different from p unless n=1 (which is not allowed)
    // or p is a palindrome (e.g., [1,2,1] which is not a permutation, or [1] which is n=1).
    // For any permutation of length n >= 2, reversing it will produce a different permutation.
    // For example, if p = [1,2], p_rev = [2,1]. Different.
    // If p = [1,2,3], p_rev = [3,2,1]. Different.
    // If p = [1,3,2], p_rev = [2,3,1]. Different.
    // The only case where p == p_rev is if p is a palindrome.
    // A permutation cannot be a palindrome unless n=1 (e.g., [1]) or n=0.
    // For n >= 2, a permutation cannot be a palindrome because it would imply
    // p_1 = p_n, p_2 = p_{n-1}, etc. But all elements must be distinct.
    // For example, if n=2, p=[1,2]. p_1=1, p_2=2. If p was a palindrome, p_1=p_2, which is not allowed.
    // Thus, reversing any permutation of length n >= 2 always yields a different permutation.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

