int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of a_i * (i-1) can exceed int
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Start with initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 (index i) to pile 1 (index 0) is i days.
            long long cost_per_haybale = i; 

            // If we have enough days to move at least one haybale from this pile
            if (d >= cost_per_haybale) {
                // Calculate how many haybales we can move from this pile
                // We have a[i] haybales in this pile.
                // We have d days remaining.
                // Each haybale costs cost_per_haybale days.
                long long haybales_to_move = std::min((long long)a[i], d / cost_per_haybale);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile,
                // nor from any further piles (as they are even further away).
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

