void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool toggle_for_half = false; // Used for elements equal to T/2

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use 2.0 for floating point division to handle T being odd
            p[i] = 0; // Assign to white (c)
        } else if (a[i] > T / 2.0) {
            p[i] = 1; // Assign to black (d)
        } else { // a[i] == T/2.0, i.e., 2*a[i] == T
            // For elements equal to T/2, alternate their assignment
            // This ensures that if there are multiple T/2 elements,
            // they are split as evenly as possible between c and d.
            // For example, if T=6, a=[3,3,3], then p=[0,1,0] or [1,0,1]
            // This minimizes pairs of (3,3) in the same array.
            p[i] = toggle_for_half ? 1 : 0;
            toggle_for_half = !toggle_for_half;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

