    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    int max_overall_val = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Only consider off-diagonal elements for max_overall_val
                if (a[i][j] > max_overall_val) {
                    max_overall_val = a[i][j];
                }
            }
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_row_val = 0;
        for (int j = 0; j < n; ++j) {
            if (i != j) { // Only consider off-diagonal elements for max_row_val
                if (a[i][j] > max_row_val) {
                    max_row_val = a[i][j];
                }
            }
        }
        if (max_row_val == max_overall_val) {
            p[i] = n; // If max_row_val is the overall maximum, p[i] must be n
        } else {
            p[i] = max_row_val; // Otherwise, p[i] is max_row_val
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // min_suffix stores the minimum price encountered from the current position to the end of the array.
    // We initialize it with the last element's price.
    int min_suffix = a[n - 1];

    // Iterate from the second to last element backwards.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is a new minimum
            // or equal to the current minimum in the suffix.
            // In either case, it becomes the new minimum for the suffix starting from i.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

