    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int k = 1; k < n; ++k) {
        // The area of the top k pieces combined is k * (TotalArea / n)
        // Area_k = k * (0.5 * h / n)
        // Also, Area_k = 0.5 * x_k^2 / h
        // So, k * (0.5 * h / n) = 0.5 * x_k^2 / h
        // k * h / n = x_k^2 / h
        // x_k^2 = k * h^2 / n
        // x_k = sqrt(k * h^2 / n)
        // x_k = h * sqrt(k / n)
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
