int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The numbers from 1 to k+1 will be used to generate k distinct differences.

    // Generate the first k+1 elements to produce k distinct differences.
    // This sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // The differences will be k, k-1, k-2, ..., 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (ascending)
            std::cout << left++;
        } else { // Odd index, take from right (descending)
            std::cout << right--;
        }
        if (i < n - 1) {
            std::cout << " ";
        }
    }

    // The remaining elements (from k+2 to n) can be appended in increasing order.
    // This will only introduce a difference of 1, which is already present (if k >= 1).
    for (int i = k + 2; i <= n; ++i) {
        std::cout << " " << i;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if we have already added more '(' than ')'
            // This ensures the balance property for the prefix
            // and helps maintain regularity.
            // The condition `result.length() - (k - close_needed) > 0`
            // means `count_open_in_result > count_close_in_result`.
            // `result.length()` is the current length of the result string.
            // `(k - close_needed)` is the number of characters already added to result.
            // `k - close_needed` is the total length of the result string if we add this ')'
            // `result.length()` is the current length of the result string.
            // `k - close_needed` is the number of characters already added to result.
            // The number of open brackets in result is `result.length() - (k/2 - open_needed_original)`.
            // The number of close brackets in result is `(k/2 - close_needed_original)`.
            // A simpler way to think about it:
            // `result.length()` is the number of characters already picked.
            // `open_needed` is the remaining open brackets to pick.
            // `close_needed` is the remaining close brackets to pick.
            // The number of open brackets picked so far is `k/2 - open_needed`.
            // The number of close brackets picked so far is `k/2 - close_needed`.
            // We can add a ')' if `(k/2 - open_needed) > (k/2 - close_needed)`.
            // This simplifies to `open_needed < close_needed`.
            if (open_needed < close_needed) { // This means we have picked more '(' than ')' so far
                result += ')';
                close_needed--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

