        return;
    }

    // Find the rightmost peak for the first decreasing sequence
    // This is the first index `i` from the right such that `a[i] > a[i+1]`
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // Now `a[p], a[p+1], ..., a[n-1]` is non-decreasing.
    // `p` is the first index of this suffix.
    // If `p > 0`, then `a[p-1] < a[p]` is false, so `a[p-1] > a[p]` must be true.
    // This means `p` is the start of the first non-decreasing suffix from the right.

    // Find the rightmost peak for the second decreasing sequence
    // This is the first index `i` from the right such that `a[i] < a[i+1]`
    // starting from `p`
    int q = p;
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }
    // Now `a[q], a[q+1], ..., a[p-1]` is non-increasing.
    // `q` is the first index of this suffix.
    // If `q > 0`, then `a[q-1] > a[q]` must be true.

    std::cout << q << std::endl;
}

