#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, min_idx and max_idx are already set to pos[1].
        // The segment is [pos[1], pos[1]], length 1, max 1. So 1 is beautiful.
        // For m > 1, we need to include m.
        // Update min_idx and max_idx to cover the range [1, m].
        if (m > 1) {
            min_idx = std::min(min_idx, pos[m]);
            max_idx = std::max(max_idx, pos[m]);
        }

        // Check if the current segment [min_idx, max_idx] satisfies the conditions for m.
        // 1. The maximum element in p[min_idx...max_idx] must be m.
        //    This is guaranteed by how min_idx and max_idx are updated:
        //    they always span the minimum range containing 1, 2, ..., m.
        //    Any element outside this range is either > m (not allowed) or
        //    is not 1..m (not allowed).
        // 2. The length of the segment must be m.
        //    Length is max_idx - min_idx + 1.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

