#include <iomanip>

void solve() {
    double d;
    std::cin >> d;

    if (d == 0) {
        std::cout << "Y 0.000000000 0.000000000\n";
        return;
    }

    // For real solutions, d^2 - 4d >= 0
    // d(d - 4) >= 0
    // Since d >= 0, this means d - 4 >= 0, so d >= 4.
    // Or d = 0, which is handled above.
    if (d < 4) {
        std::cout << "N\n";
        return;
    }

    // a^2 - d*a + d = 0
    // a = (d +/- sqrt(d^2 - 4d)) / 2
    double discriminant = d * d - 4 * d;
    double sqrt_discriminant = std::sqrt(discriminant);

    double a1 = (d + sqrt_discriminant) / 2.0;
    double b1 = d - a1; // b = d - a

    // We need a and b to be non-negative.
    // Since d >= 4, d is positive.
    // sqrt(d^2 - 4d) is real and non-negative.
    // d + sqrt(d^2 - 4d) is positive, so a1 is positive.
    // For b1 = d - a1 to be non-negative:
    // d - (d + sqrt(d^2 - 4d)) / 2 >= 0
    // (2d - d - sqrt(d^2 - 4d)) / 2 >= 0
    // (d - sqrt(d^2 - 4d)) / 2 >= 0
    // d >= sqrt(d^2 - 4d)
    // d^2 >= d^2 - 4d (since both sides are non-negative, we can square)
    // 0 >= -4d
    // 4d >= 0
    // This is true since d >= 4.
    // So, a1 and b1 are always non-negative when d >= 4.

    std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
}

