#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> left_min_val(n);
    left_min_val[0] = 0; // a_1' must be at least 0
    for (int i = 1; i < n; ++i) {
        left_min_val[i] = left_min_val[i-1] + 1;
    }

    std::vector<long long> right_min_val(n);
    right_min_val[n-1] = 0; // a_n' must be at least 0
    for (int i = n - 2; i >= 0; --i) {
        right_min_val[i] = right_min_val[i+1] + 1;
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) { // k is 0-indexed peak index
        // Check if a_k can be the peak
        // For the left part: a_0' < a_1' < ... < a_k'
        // We need a_i >= left_min_val[i] for i <= k
        // For the right part: a_k' > a_{k+1}' > ... > a_{n-1}'
        // We need a_i >= right_min_val[i] for i >= k

        // The peak element a_k' must satisfy both conditions:
        // a_k' >= left_min_val[k] (from left side requirement)
        // a_k' >= right_min_val[k] (from right side requirement)
        // So, a_k' must be at least max(left_min_val[k], right_min_val[k])
        // And we must be able to achieve this with the original a[k]:
        // a[k] >= max(left_min_val[k], right_min_val[k])

        if (a[k] < left_min_val[k] || a[k] < right_min_val[k]) {
            continue; // a[k] is too small to be a peak at this position
        }

        // Check if all elements to the left can be made strictly increasing up to a_k'
        bool left_ok = true;
        for (int i = 0; i < k; ++i) {
            if (a[i] < left_min_val[i]) {
                left_ok = false;
                break;
            }
        }
        if (!left_ok) continue;

        // Check if all elements to the right can be made strictly decreasing from a_k'
        bool right_ok = true;
        for (int i = k + 1; i < n; ++i) {
            if (a[i] < right_min_val[i]) {
                right_ok = false;
                break;
            }
        }
        if (!right_ok) continue;

        possible = true;
        break;
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

