    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // (n-1)/2 for 0-indexed array

    // First, make the median element equal to s
    operations += std::abs(a[mid_idx] - s);
    a[mid_idx] = s; // Conceptually change it for subsequent checks

    // Elements to the left of median (smaller half)
    // These elements must be <= s. If any is > s, it must be decreased to s.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of median (larger half)
    // These elements must be >= s. If any is < s, it must be increased to s.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

