}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The i-th element of the sorted B array (b_elements[i].value)
    // should be paired with the (m-1-i)-th element of the sorted A array (a_elements[m-1-i].value).
    // The result A' should be ordered according to the original indices of B.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_elements[i] is the i-th smallest B value.
        // Its original position was b_elements[i].original_index.
        // It should be paired with the (m-1-i)-th smallest A value, which is a_elements[m-1-i].value.
        result_a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

