    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (the 'larger' elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (the 'smaller' elements)
        // We want to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, we can advance j.
        // If a[j] is not greater than a[i], we need a larger element, so increment j.
        // We must ensure j is within bounds.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        // If we found such an element a[j] and j is still within bounds
        if (j < n) {
            count++;
            j++; // Move to the next element for the next comparison
        } else {
            // If j reached the end, it means no more elements can be placed
            // to be strictly greater than the remaining a[i]'s.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 == 1) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: if N=2, taking N/2 leaves 1, taking 1 leaves 1. Both give 1.
                          // Chanek takes 1, opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1;
            } else if ((n / 2) % 2 == 1) { // N/2 is odd. If Chanek takes N/2, opponent faces odd N.
                                          // Opponent will take 1. This is good for Chanek.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N/2 is even. If Chanek takes N/2, opponent faces even N.
                     // Opponent might take N/4. This is bad for Chanek.
                     // So Chanek takes 1.
                chanek_coins += 1;
                n -= 1;
            }
        }

        if (n == 0) break; // Game ends if N becomes 0

        // Opponent's turn (same logic, but we don't care about opponent's coins, just N)
        if (n % 2 == 1) {
            n -= 1;
        } else {
            if (n == 2) {
                n -= 1;
            } else if ((n / 2) % 2 == 1) {
                n /= 2;
            } else {
                n -= 1;
            }
        }
    }
    return chanek_coins;
}

