// Function to check if a sub-array is a permutation
// It checks if all numbers from 1 to length are present exactly once.
// This is equivalent to checking if the maximum element is 'length'
// and all elements are distinct.
bool is_permutation(const std::vector<int>& arr, int start_idx, int length) {
    if (length == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                     // For this problem, l1, l2 >= 1.
    }
    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix_max and suffix_max
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    // Precompute prefix_is_perm and suffix_is_perm
    std::vector<bool> prefix_is_perm(n + 1, false); // prefix_is_perm[k] means a[0...k-1] is a perm of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool current_prefix_valid = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[k-1];
        if (val <= 0 || val > k || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        if (current_prefix_valid) {
            seen_prefix[val] = true;
            current_max_prefix = std::max(current_max_prefix, val);
            if (current_max_prefix == k) {
                prefix_is_perm[k] = true;
            }
        }
    }

    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[k] means a[n-k...n-1] is a perm of length k
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool current_suffix_valid = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[n-k];
        if (val <= 0 || val > k || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        if (current_suffix_valid) {
            seen_suffix[val] = true;
            current_max_suffix = std::max(current_max_suffix, val);
            if (current_max_suffix == k) {
                suffix_is_perm[k] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 can be from 1 to n-1
        int l2 = n - l1;

        // Check if prefix a[0...l1-1] is a permutation of length l1
        // Check if suffix a[l1...n-1] is a permutation of length l2
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
