void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum and X = current_xor_sum.
    // We want S' = 2 * X', where S' = S + sum(b_i) and X' = X ^ xor(b_i).

    // Strategy: Append at most 3 elements.
    // It's always possible to make S' = 2 * X' by appending at most 3 elements.
    // Let's try to append two elements first.
    // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2).
    // A simple choice for b1 and b2:
    // Let b1 = X. Then X ^ b1 = X ^ X = 0.
    // The equation becomes S + X + b2 = 2 * (0 ^ b2) = 2 * b2.
    // S + X = b2.
    // So, if we append X and S + X, the new sum is S + X + (S + X) = 2S + 2X.
    // The new XOR sum is X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
    // We need 2S + 2X = 2 * (S + X), which is true.
    // So, appending X and S + X always works.
    // The problem states that appended elements don't have to be different.
    // If X = 0, we append 0 and S.
    // If S + X can be very large, up to 10^9 * 10^5 + 10^9 = 10^14 + 10^9, which fits in long long.
    // The maximum value for a_i is 10^9.
    // The maximum sum for n=10^5 is 10^5 * 10^9 = 10^14.
    // The maximum XOR sum is around 2^30 (since a_i <= 10^9 < 2^30).
    // So S + X can be up to 10^14 + 2^30, which fits in long long.
    // The problem states b_i <= 10^18, so this is fine.

    // Output 2 elements: current_xor_sum and current_sum + current_xor_sum.
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

