void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Rule 1: If s[i] is '0', then w[i-x] (if exists) must be '0'
    // and w[i+x] (if exists) must be '0'.
    // We use this to set '0's in our candidate w.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Rule 2: Verify if the constructed w can produce s.
    // For each s[i], check if it can be '1' based on our w.
    // If s[i] is '1', but our w cannot make it '1', then no solution exists.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool can_be_one = false;
            // Check w[i-x]
            if (i - x >= 0 && w[i - x] == '1') {
                can_be_one = true;
            }
            // Check w[i+x]
            if (i + x < n && w[i + x] == '1') {
                can_be_one = true;
            }

            if (!can_be_one) {
                std::cout << -1 << std::endl;
                return;
            }
        }
    }

    std::cout << w << std::endl;
}

