// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end());
    return pattern;
}

// Function to normalize a pattern string to 18 characters
// by padding with '0's from the left.
std::string normalize_pattern(const std::string& s) {
    std::string normalized = s;
    if (normalized.length() < 18) {
        normalized = std::string(18 - normalized.length(), '0') + normalized;
    }
    return normalized;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[normalize_pattern(pattern)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[normalize_pattern(pattern)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            std::cout << counts[normalize_pattern(s)] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long power_of_2 = 1; // Represents 2^b_count
    const long long MOD = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count++;
            power_of_2 = (power_of_2 * 2) % MOD; // Update 2^b_count
        } else { // s[i] == 'a'
            // If an 'a' is encountered, it needs to move past all 'b's to its right.
            // Each 'b' it moves past generates a new 'b'.
            // The number of steps for this 'a' is 2^b_count - 1 (if b_count > 0)
            // or 0 (if b_count == 0).
            // The problem statement implies that if there are no 'b's to the right,
            // no 'ab' substring is formed by this 'a' and it doesn't contribute steps.
            // If b_count > 0, this 'a' will form 'ab' with the rightmost 'b'.
            // This 'ab' will be replaced by 'bba'. The 'a' effectively moves past one 'b'
            // and generates a new 'b'. This process repeats for all b_count 'b's.
            // The total steps for this 'a' is 2^b_count.
            // After this 'a' moves past all 'b's, it effectively disappears from the 'ab' context,
            // and all 'b's to its right (including the newly generated ones) remain.
            // The number of 'b's to the right of the current 'a' doubles for future 'a's.

            // The number of steps for this 'a' is the current power_of_2 (which is 2^b_count).
            total_steps = (total_steps + power_of_2) % MOD;

            // After this 'a' is processed, it effectively moves to the right of all 'b's.
            // The number of 'b's that future 'a's (to the left) will encounter doubles.
            // This is because each existing 'b' effectively becomes two 'b's due to this 'a' passing it.
            // So, b_count effectively doubles.
            // This is equivalent to resetting b_count to 0 and power_of_2 to 1,
            // because this 'a' has been "resolved" and its contribution is added.
            // The 'b's that were to its right are now effectively "doubled" for the next 'a's.
            // This is implicitly handled by the power_of_2 logic.
            // When an 'a' is processed, it consumes the 'b's to its right.
            // The number of 'b's available for the *next* 'a' (to its left) is reset.
            // This is the key insight: an 'a' "uses up" the 'b's to its right.
            // So, after processing an 'a', the count of 'b's for the next 'a' starts fresh.
            b_count = 0;
            power_of_2 = 1;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

