#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items from the right is total_sum - prefix_sum[i]
        // which is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for imbalanced counts
        if (i > j) { // More items from left than right
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            current_energy += (long long)(j - i - 1) * Qr;
        }
        // If i == j or |i-j| == 1, no extra penalty is added by this logic.
        // The problem states "If the previous action was the same (left-hand), then the robot spends extra Ql energy units"
        // This implies that if we take k items from left and m items from right,
        // and k > m, then the last k-m items must have been taken from the left.
        // If k > m+1, then at least k-m-1 times we took left item after left item.
        // Example: L L L R R. k=3, m=2. k-m=1. No extra penalty.
        // Example: L L L L R R. k=4, m=2. k-m=2. One extra penalty. (L L) L L R R.
        // The (i-j-1) or (j-i-1) factor correctly accounts for this.
        // If i=j, no penalty.
        // If i=j+1, no penalty (i-j-1 = 0).
        // If i=j+2, one penalty (i-j-1 = 1).
        // This logic is correct for the "extra Ql/Qr" part.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

