#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last1 = '0'; // Last digit placed in color 1
        char last2 = '0'; // Last digit placed in color 2
        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            char d_i = s[i];
            if (d_i < (char)('0' + pivot_digit)) {
                // Must be color 1
                if (d_i >= last1) {
                    result[i] = '1';
                    last1 = d_i;
                } else {
                    current_possible = false;
                    break;
                }
            } else if (d_i > (char)('0' + pivot_digit)) {
                // Must be color 2
                if (d_i >= last2) {
                    result[i] = '2';
                    last2 = d_i;
                } else {
                    current_possible = false;
                    break;
                }
            } else { // d_i == pivot_digit
                // Can be either color 1 or color 2
                // Prioritize color 2 if possible, to keep last1 small
                if (d_i >= last2) {
                    result[i] = '2';
                    last2 = d_i;
                } else if (d_i >= last1) {
                    result[i] = '1';
                    last1 = d_i;
                } else {
                    current_possible = false;
                    break;
                }
            }
        }

        if (current_possible) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

