// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x is a divisor of p and x is not divisible by q.
        // This means x must be p / (some factor of p) such that p / (some factor of p) is not divisible by q.
        // Or, more directly, x must be p / (some factor of q) such that x is not divisible by q.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak.
        // If x is divisible by q, then x must have at least a_i factors of f_i for all i.
        // To make x not divisible by q, we need to remove enough factors of some f_j from p
        // such that the resulting x has fewer than a_j factors of f_j.
        // To maximize x, we want to remove the minimum necessary factors.
        // This means for each prime factor f_j of q, we try to divide p by f_j until it's no longer divisible by q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q
            // This means current_p / factor^k is not divisible by q
            // We want to find the largest current_p / factor^k that is not divisible by q
            // We can do this by repeatedly dividing current_p by 'factor'
            // and checking if the result is still divisible by q.
            // The first time it's not divisible by q, that's a candidate for max_x.
            // Or, more efficiently, divide p by 'factor' until the exponent of 'factor' in p
            // is less than the exponent of 'factor' in q.
            // Let's find the exponent of 'factor' in q.
            long long temp_q = q;
            int count_factor_in_q = 0;
            while (temp_q > 0 && temp_q % factor == 0) {
                count_factor_in_q++;
                temp_q /= factor;
            }

            // Now, divide p by 'factor' until its exponent is less than count_factor_in_q.
            // We want to find the largest x = p / factor^k such that x % q != 0.
            // This means we need to remove at least one 'factor' from p more than what's needed
            // to make its exponent equal to count_factor_in_q - 1.
            // Example: p = 12, q = 6. q_prime_factors = {2, 3}.
            // For factor = 2: count_factor_in_q = 1 (6 = 2^1 * 3^1).
            // We need to divide p by 2 until its exponent of 2 is 0.
            // p = 12 = 2^2 * 3^1.
            // x = 12 / 2 = 6. 6 % 6 == 0. Not valid.
            // x = 12 / 2^2 = 3. 3 % 6 != 0. Valid.
            //
            // For factor = 3: count_factor_in_q = 1.
            // We need to divide p by 3 until its exponent of 3 is 0.
            // p = 12 = 2^2 * 3^1.
            // x = 12 / 3 = 4. 4 % 6 != 0. Valid.
            // Max of {3, 4} is 4.

            long long current_x_candidate = p;
            while (current_x_candidate % factor == 0 && current_x_candidate % q == 0) {
                current_x_candidate /= factor;
            }
            max_x = std::max(max_x, current_x_candidate);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
