int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;

        // Initialize bounds for the reachable region
        // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5]
        // So, we can use these as initial bounds.
        // For x-coordinates:
        // min_x_target: smallest X a robot can reach (if it can only move right)
        // max_x_target: largest X a robot can reach (if it can only move left)
        // For y-coordinates:
        // min_y_target: smallest Y a robot can reach (if it can only move up)
        // max_y_target: largest Y a robot can reach (if it can only move down)

        // Initial range for X: [-10^5, 10^5]
        long long min_x_target = -100000;
        long long max_x_target = 100000;

        // Initial range for Y: [-10^5, 10^5]
        long long min_y_target = -100000;
        long long max_y_target = 100000;

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0: cannot move left (x_c - 1). This means target X must be >= current x.
            // So, the minimum possible X for the target point is x.
            if (f1 == 0) {
                min_x_target = std::max(min_x_target, x);
            }

            // f3 = 0: cannot move right (x_c + 1). This means target X must be <= current x.
            // So, the maximum possible X for the target point is x.
            if (f3 == 0) {
                max_x_target = std::min(max_x_target, x);
            }

            // f4 = 0: cannot move down (y_c - 1). This means target Y must be >= current y.
            // So, the minimum possible Y for the target point is y.
            if (f4 == 0) {
                min_y_target = std::max(min_y_target, y);
            }

            // f2 = 0: cannot move up (y_c + 1). This means target Y must be <= current y.
            // So, the maximum possible Y for the target point is y.
            if (f2 == 0) {
                max_y_target = std::min(max_y_target, y);
            }
        }

        // Check if the intersection of all reachable regions is non-empty
        if (min_x_target <= max_x_target && min_y_target <= max_y_target) {
            // If it's non-empty, any point within [min_x_target, max_x_target] x [min_y_target, max_y_target] is a valid target.
            // We can pick (min_x_target, min_y_target) as one such point.
            std::cout << 1 << " " << min_x_target << " " << min_y_target << "\n";
        } else {
            // If the intersection is empty, no such point exists.
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        if (b_minus_1 % 2 == 0) {
            sum_r_val = (b_minus_1 / 2) % MOD * (b % MOD) % MOD;
        } else {
            sum_r_val = (b % MOD) / 2 % MOD * (b_minus_1 % MOD) % MOD;
        }
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_k_term = b * (a * (a+1) / 2) + a

    long long sum_k_val;
    long long a_mod = a % MOD;
    long long b_mod = b % MOD;

    long long a_times_a_plus_1_div_2;
    if (a % 2 == 0) {
        a_times_a_plus_1_div_2 = (a / 2) % MOD * ((a + 1) % MOD) % MOD;
    } else {
        a_times_a_plus_1_div_2 = ((a + 1) / 2) % MOD * (a % MOD) % MOD;
    }

    long long term1 = (b_mod * a_times_a_plus_1_div_2) % MOD;
    long long term2 = a_mod;
    sum_k_val = (term1 + term2) % MOD;

    // Total sum = sum_r_val * sum_k_val
    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_first_char = 0; k_first_char < L; ++k_first_char) {
        char observed_t0 = s[k_first_char];

        // Find all possible k values that result in this observed_t0
        // These are the indices `i` such that `s[i] == observed_t0`
        const std::vector<int>& possible_k_values = char_indices[observed_t0 - 'a'];

        if (possible_k_values.size() == 1) {
            // If only one k can produce this t[0], Vasya wins immediately for this t[0]
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k values are possible, Vasya needs to choose p
        // to maximize the win probability for this t[0].
        // The win probability for a given t[0] and chosen p is
        // (number of k's uniquely determined by t[0] and t[p]) / (total number of k's for this t[0])

        int max_wins_for_t0 = 0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            std::vector<std::vector<int>> groups_by_t_p(26);
            for (int k_val : possible_k_values) {
                char observed_tp = s[(k_val + p) % L];
                groups_by_t_p[observed_tp - 'a'].push_back(k_val);
            }

            int current_p_wins = 0;
            for (int c = 0; c < 26; ++c) {
                if (groups_by_t_p[c].size() == 1) {
                    current_p_wins++;
                }
            }
            max_wins_for_t0 = std::max(max_wins_for_t0, current_p_wins);
        }
        total_win_prob += static_cast<double>(max_wins_for_t0) / possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

