#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0 to 9), we track two values:
    // what the bit becomes if the initial input bit is 0
    // what the bit becomes if the initial input bit is 1
    // These are stored as a pair (value_if_input_0, value_if_input_1)
    // Initially, if input bit is 0, it's 0. If input bit is 1, it's 1.
    std::vector<std::pair<int, int>> bit_states(10);
    for (int i = 0; i < 10; ++i) {
        bit_states[i] = {0, 1}; // {initial_0_becomes, initial_1_becomes}
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_of_val = (val >> i) & 1;
            int current_0_state = bit_states[i].first;
            int current_1_state = bit_states[i].second;

            if (op_char == '&') {
                bit_states[i].first = current_0_state & bit_of_val;
                bit_states[i].second = current_1_state & bit_of_val;
            } else if (op_char == '|') {
                bit_states[i].first = current_0_state | bit_of_val;
                bit_states[i].second = current_1_state | bit_of_val;
            } else if (op_char == '^') {
                bit_states[i].first = current_0_state ^ bit_of_val;
                bit_states[i].second = current_1_state ^ bit_of_val;
            }
        }
    }

    // Now, bit_states[i] contains the final transformation for bit i:
    // {0_becomes_X, 1_becomes_Y}
    // We need to find constants A, B, C such that:
    // (x & A | B ^ C) or (x | A & B ^ C) etc.
    // This can be simplified to at most 3 operations:
    // x & A | B ^ C
    // Let's find the effective A, B, C for the three operations.
    //
    // For each bit i:
    // If input bit is 0, output bit is bit_states[i].first
    // If input bit is 1, output bit is bit_states[i].second

    // We want to find A_final, B_final, C_final such that:
    // (0 & A_final | B_final ^ C_final) == bit_states[i].first
    // (1 & A_final | B_final ^ C_final) == bit_states[i].second

    // Let's try to construct the three constants for AND, OR, XOR.
    // Initialize them to values that don't change the input:
    // AND with 1023 (all 1s)
    // OR with 0
    // XOR with 0
    int final_and_const = 1023; // All bits 1
    int final_or_const = 0;     // All bits 0
    int final_xor_const = 0;    // All bits 0

    for (int i = 0; i < 10; ++i) {
        int zero_becomes = bit_states[i].first;
        int one_becomes = bit_states[i].second;

        // We need to find a combination of (x_i & A_i | B_i ^ C_i)
        // that matches (zero_becomes, one_becomes) for each bit i.
        // There are 4 possible (zero_becomes, one_becomes) pairs:
        // (0,0): output is always 0, regardless of input.
        // (0,1): output is same as input.
        // (1,0): output is inverse of input.
        // (1,1): output is always 1, regardless of input.

        if (zero_becomes == 0 && one_becomes == 0) {
            // Output is always 0.
            // This means:
            // x & 0 -> 0
            // x | 0 -> x
            // x ^ 1 -> ~x
            // To make output 0:
            // Set AND bit to 0: final_and_const &= ~(1 << i);
            // Or set OR bit to 0 and XOR bit to 0: final_or_const &= ~(1 << i); final_xor_const &= ~(1 << i);
            // The simplest way to force a bit to 0 is `& 0`.
            final_and_const &= ~(1 << i); // Set i-th bit of AND constant to 0
        } else if (zero_becomes == 0 && one_becomes == 1) {
            // Output is same as input.
            // This means:
