            // x | 0 -> x
            // x ^ 0 -> x
            // No change needed for this bit for AND, OR, XOR constants (1, 0, 0).
            // final_and_const already has 1 at this bit.
            // final_or_const already has 0 at this bit.
            // final_xor_const already has 0 at this bit.
        } else if (zero_becomes == 1 && one_becomes == 0) {
            // Output is inverse of input.
            // This means:
            // x & 0 -> 0
            // x | 1 -> 1
            // x ^ 1 -> ~x
            // The simplest way to invert a bit is `^ 1`.
            final_xor_const |= (1 << i); // Set i-th bit of XOR constant to 1
        } else if (zero_becomes == 1 && one_becomes == 1) {
            // Output is always 1.
            // This means:
            // x & 1 -> x
            // x | 1 -> 1
            // x ^ 0 -> x
            // The simplest way to force a bit to 1 is `| 1`.
            final_or_const |= (1 << i); // Set i-th bit of OR constant to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If AND constant is not all 1s
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If OR constant is not all 0s
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If XOR constant is not all 0s
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        long long good_substrings_count = 0;

        // Iterate through all possible starting positions l
        for (int l = 0; l < n; ++l) {
            // Case 1: Substring starts with '0'
            // If s[l] is '0', then f(s_l...s_r) can be 0.
            // If f(s_l...s_r) = 0, then the length r-l+1 must be 0, which is impossible for a non-empty substring.
            // So, if s[l] is '0', f(s_l...s_r) must be positive.
            // The smallest positive value for f(s_l...s_r) is 1.
            // If f(s_l...s_r) = 1, then the substring must be '1'.
            // If s[l] is '0', then any substring starting at l will have f(s_l...s_r) = f(s_{l+k}...s_r) for some k.
            // We need to find the first '1' in the substring to determine its value.
            // Let's find the first '1' from index l.
            int first_one_idx = -1;
            for (int k = l; k < n; ++k) {
                if (s[k] == '1') {
                    first_one_idx = k;
                    break;
                }
            }

            if (first_one_idx == -1) {
                // All characters from l to n-1 are '0'.
                // f(s_l...s_r) will always be 0.
                // Length r-l+1 will always be positive.
                // So, no good substrings can be formed starting at l if all are '0's.
                continue;
            }

            // Now we know s[first_one_idx] is '1'.
            // The actual binary value starts from s[first_one_idx].
            // The number of leading zeros before s[first_one_idx] is `num_leading_zeros = first_one_idx - l`.

            // Iterate through possible ending positions r, starting from first_one_idx
            long long current_val = 0;
            for (int r = first_one_idx; r < n; ++r) {
                current_val = (current_val << 1) | (s[r] - '0');

                // Check for overflow or if value exceeds max possible length
                // Max length is n, so current_val cannot exceed n + max_leading_zeros_to_consider
                // Max leading zeros to consider is around 18-20 for current_val to be around 2e5.
                // If current_val is already > n + 20, then it's too large.
                // A safe upper bound for current_val is n + 60 (max_leading_zeros_to_consider for 2^60).
                // But we only care about current_val up to n.
                // If current_val > n + 60, it's definitely too large.
                if (current_val > n + 60) { // 60 is a safe upper bound for max_leading_zeros_to_consider
                                            // because 2^18 is ~2.6e5, 2^19 is ~5.2e5.
                                            // If current_val is 2e5, then max_leading_zeros is 18.
                                            // So n + 18 is a tighter bound. n + 60 is very safe.
                    break; 
                }

                // The length of the substring s[l...r] is (r - l + 1).
                // The value f(s_l...s_r) is current_val.
                // The condition is (r - l + 1) == current_val.
                // However, the value `current_val` is calculated from `s[first_one_idx...r]`.
                // The actual value `f(s_l...s_r)` is `current_val`.
                // The length `r - l + 1` must be equal to `current_val`.
                // The number of leading zeros is `first_one_idx - l`.
                // So, `r - l + 1 = current_val` is the condition.
                // This means `r - first_one_idx + 1 + (first_one_idx - l) = current_val`.
                // `length_from_first_one + num_leading_zeros = current_val`.

                long long length_from_first_one = r - first_one_idx + 1;
                long long num_leading_zeros = first_one_idx - l;

                if (current_val == length_from_first_one + num_leading_zeros) {
                    good_substrings_count++;
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance
    int initial_balance = 0;
    for (int i = 0; i < 2 * n; ++i) {
        if (a[i] == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // If initial balance is 0, no jars need to be eaten.
    if (initial_balance == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Store balances for prefixes of the left side (jars n-1 down to 0)
    // and suffixes of the right side (jars n up to 2n-1)
    // Map: balance_change -> number_of_jars_eaten
    std::map<int, int> left_balances;
    left_balances[0] = 0; // Eating 0 jars from left gives balance change 0

    int current_balance_change = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_balance_change++;
        } else {
            current_balance_change--;
        }
        // We want to find the minimum jars eaten for a given balance change.
        // Since we iterate from 0 jars eaten upwards, the first time we see a balance_change
        // will correspond to the minimum jars eaten.
        if (left_balances.find(current_balance_change) == left_balances.end()) {
            left_balances[current_balance_change] = (n - i);
        }
    }

    std::map<int, int> right_balances;
    right_balances[0] = 0; // Eating 0 jars from right gives balance change 0

    current_balance_change = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_balance_change++;
        } else {
            current_balance_change--;
        }
        if (right_balances.find(current_balance_change) == right_balances.end()) {
            right_balances[current_balance_change] = (i - n + 1);
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible jars

    // Iterate through all possible balance changes from the left side
    for (auto const& [left_bal_change, left_jars_eaten] : left_balances) {
        // We need initial_balance - left_bal_change - right_bal_change = 0
        // So, right_bal_change must be initial_balance - left_bal_change
        int required_right_bal_change = initial_balance - left_bal_change;

        if (right_balances.count(required_right_bal_change)) {
            int right_jars_eaten = right_balances[required_right_bal_change];
            min_jars_eaten = std::min(min_jars_eaten, left_jars_eaten + right_jars_eaten);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

