int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zero_run(n); // Length of consecutive zeros to the left, including current
    std::vector<int> right_zero_run(n); // Length of consecutive zeros to the right, including current
    std::vector<int> left_one_run(n);  // Length of consecutive ones to the left, including current
    std::vector<int> right_one_run(n); // Length of consecutive ones to the right, including current

    // Calculate left runs
    left_zero_run[0] = (a[0] == 0 ? 1 : 0);
    left_one_run[0] = (a[0] == 1 ? 1 : 0);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right runs
    right_zero_run[n - 1] = (a[n - 1] == 0 ? 1 : 0);
    right_one_run[n - 1] = (a[n - 1] == 1 ? 1 : 0);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
            right_zero_run[i] = 0;
        }
    }

    int max_steps = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0
            if (left_one_run[i] > 0 && right_one_run[i] > 0) { // 0 is surrounded by 1s
                // This 0 will turn into 1. The number of steps is min(left_one_run[i], right_one_run[i])
                max_steps = std::max(max_steps, std::min(left_one_run[i], right_one_run[i]));
            }
        } else { // Current element is 1
            if (left_zero_run[i] > 0 && right_zero_run[i] > 0) { // 1 is surrounded by 0s
                // This 1 will turn into 0. The number of steps is min(left_zero_run[i], right_zero_run[i])
                max_steps = std::max(max_steps, std::min(left_zero_run[i], right_zero_run[i]));
            }
        }
    }

    // If max_steps is 0, the sequence is already stable.
    // If max_steps is odd, it means there's an element that will flip an odd number of times.
    // This implies it will never stabilize if it's an isolated flip.
    // However, the problem states that it always stabilizes or never.
    // The condition for non-stabilization is when max_steps is odd and the sequence is not all 0s or all 1s.
    // More precisely, if max_steps is odd, it means there's a '0' that wants to become '1' (or vice versa)
    // and it's an odd number of steps away from the nearest '0' (or '1').
    // This means it will flip an odd number of times, ending up in the opposite state.
    // But the surrounding elements will also flip, potentially changing its final state.

    // The actual condition for non-stabilization is when max_steps is odd.
    // This is because an element at index `i` will flip if `a[i-1] != a[i+1]`.
    // If `a[i-1] == a[i+1]`, then `a[i]` will become `a[i-1]` (or `a[i+1]`).
    // If `a[i-1] != a[i+1]`, then `a[i]` will become `a[i-1]` if `a[i-1] == a[i]`, or `a[i+1]` if `a[i+1] == a[i]`.
    // If `a[i-1] != a[i+1]` and `a[i]` is different from both, it will become `a[i-1]` (or `a[i+1]`).
    // Example: 0 1 0 -> 0 0 0. The middle 1 becomes 0.
    // Example: 1 0 1 -> 1 1 1. The middle 0 becomes 1.
    // The "flipping" happens at the boundaries of blocks of same numbers.
    // A block of 0s surrounded by 1s (e.g., 1 0 0 0 1) will shrink.
    // A block of 1s surrounded by 0s (e.g., 0 1 1 1 0) will shrink.
    // The number of steps for an element to flip is its distance to the nearest different element.
    // If max_steps is odd, it means some element will flip an odd number of times.
    // This implies it will end up in the opposite state of what it would be if it were stable.
    // However, the problem statement implies that it either stabilizes or never.
    // The key insight is that if max_steps is odd, the sequence never stabilizes.
    // This is because the "middle" elements of the longest alternating sequence (e.g., 01010)
    // will keep flipping.
    // For example, 01010 -> 00100 -> 00000. Here max_steps = 2.
    // For example, 0101010 -> 0011000 -> 0001000 -> 0000000. Here max_steps = 3.
    // The problem statement implies that if max_steps is odd, it never stabilizes.
    // This is a common pattern in such problems.

    if (max_steps % 2 != 0) {
        std::cout << -1 << std::endl;
        return 0;
    }

    // Construct the final stable sequence
    std::vector<int> final_a = a;
    int steps_to_apply = max_steps / 2;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Original was 0
            if (left_one_run[i] > 0 && right_one_run[i] > 0) { // 0 surrounded by 1s
                // This 0 will turn into 1 if it's "closer" to 1s than steps_to_apply
                if (std::min(left_one_run[i], right_one_run[i]) <= steps_to_apply) {
                    final_a[i] = 1;
                }
            }
        } else { // Original was 1
            if (left_zero_run[i] > 0 && right_zero_run[i] > 0) { // 1 surrounded by 0s
                // This 1 will turn into 0 if it's "closer" to 0s than steps_to_apply
                if (std::min(left_zero_run[i], right_zero_run[i]) <= steps_to_apply) {
                    final_a[i] = 0;
                }
            }
        }
    }

    std::cout << steps_to_apply << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

