struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Calculate the maximum possible initial value for each a[i]
    // based on type 2 operations.
    // For each type 2 operation (l, r, m_i), and for each j in [l, r],
    // a_initial[j] + sum_of_d_affecting_j_up_to_this_op <= m_i.
    // This means a_initial[j] <= m_i - sum_of_d_affecting_j_up_to_this_op.
    // We want to find the largest possible a_initial[j] that satisfies all constraints.
    // So, a_initial[j] <= min(m_i - sum_of_d_affecting_j_up_to_this_op) over all relevant type 2 ops.

    std::vector<long long> initial_a(n, LLONG_MAX); // Initialize with a very large value

    std::vector<long long> current_add(n, 0); // Cumulative sum of d for each index
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_add[j] += op.val;
            }
        } else { // type 2
            for (int j = op.l; j <= op.r; ++j) {
                initial_a[j] = std::min(initial_a[j], op.val - current_add[j]);
            }
        }
    }

    // If any initial_a[j] is still LLONG_MAX, it means it was not constrained by any type 2 operation.
    // We can set it to 0, as it will satisfy the |a_i| <= 10^9 constraint.
    // The problem statement says "all numbers in his array didn't exceed 10^9 in their absolute value".
    // This implies the initial values.
    // A value of 0 is safe.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> current_array_values = initial_a;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_array_values[j] += op.val;
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_array_values[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check initial values constraints
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not be reached if the logic for initial_a[j] = 0 for unconstrained
            // and the problem constraints on m_i are respected.
            // m_i is up to 5*10^7. current_add[j] can be up to 5000 * 10^4 = 5*10^7.
            // So initial_a[j] can be around 5*10^7 - (-5*10^7) = 10^8, which is within 10^9.
            // Or -5*10^7 - (5*10^7) = -10^8.
            // So the values should be within 10^9.
            // This check is mostly for robustness.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_reduction = children[i].v;
        long long cumulative_d_reduction = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            children[j].p -= cumulative_d_reduction;

            if (current_v_reduction > 0) {
                children[j].p -= current_v_reduction;
                current_v_reduction = std::max(0LL, current_v_reduction - 1);
            }

            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_d_reduction += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

