// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) which is 2*10^5 * 10^9 = 2*10^14.
// x will always be within [0, n+1] or so, so int is fine for x.

// This function simulates the program for a given initial a_1 value.
// It returns the final y value or -1 if it doesn't terminate.
long long simulate(int n, const std::vector<long long>& a_full, int initial_a1) {
    long long x = 1;
    long long y = 0;

    // We need to modify a_full[0] for each run.
    // Since a_full is const, we'll use a local copy or adjust indices.
    // Let's adjust indices: a_full[0] will be a_1, a_full[1] will be a_2, etc.
    // So, a_full[x-1] is the value for a_x.

    // The problem states a_1, a_2, ..., a_n.
    // The input is a_2, ..., a_n.
    // We are given a_1 = i for each run.
    // Let's use 1-based indexing for a internally to match problem statement.
    // So, a[1] will be initial_a1, a[2] will be a_full[0], a[3] will be a_full[1], etc.
    // This means a_x corresponds to a_full[x-2] for x >= 2, and a_full[x-1] if we store a_1 at index 0.
    // Let's use a vector `a_values` where `a_values[k]` stores `a_{k+1}`.
    // So `a_values[0]` is `a_1`, `a_values[1]` is `a_2`, etc.
    // `a_values[x-1]` is `a_x`.

    // To avoid recomputing for states already visited, we can use dynamic programming or memoization.
    // The state is (x, parity_of_step).
    // Parity_of_step: 0 for step 2, 1 for step 3.
    // Let's define dp[x][0] as the (delta_x, delta_y) if we start at x and execute step 2.
    // Let's define dp[x][1] as the (delta_x, delta_y) if we start at x and execute step 3.
    // However, the problem states "step 2, then step 3, step 2, then step 3".
    // So, we always execute step 2, then step 3.
    // The state is just `x`.
    // `dp[x]` stores `(final_x, final_y)` if we start at `x` and execute the full (step 2, step 3) cycle until termination.
    // Or, more simply, `dp[x]` stores `(next_x, total_y_added)` from `x` until termination.

    // We need to compute this for each starting `a_1`.
    // The values `a_2, ..., a_n` are fixed. Only `a_1` changes.
    // This suggests that for `x > 1`, the behavior might be independent of `a_1`.
    // Let's precompute results for `x > 1`.

    // `memo[x]` stores a pair: `{final_x_offset, final_y_added}` starting from `x`.
    // `final_x_offset` is `final_x - x`.
    // `final_y_added` is the total `y` added.
    // We also need to detect cycles.
    // `visited[x]` stores the current path being explored to detect cycles.
    // `memo[x].first = -2` means not computed.
    // `memo[x].first = -1` means currently computing (cycle detected if re-entered).
    // `memo[x].first = -3` means terminates in a cycle (non-terminating).

    // The `a` values are 1-indexed in the problem.
    // `a_values[0]` is `a_1`, `a_values[1]` is `a_2`, ..., `a_values[n-1]` is `a_n`.
    // So `a_x` is `a_values[x-1]`.

    std::vector<long long> a_values(n);
    a_values[0] = initial_a1;
    for (int k = 0; k < n - 1; ++k) {
        a_values[k + 1] = a_full[k];
    }

    // `memo[i]` stores the result for starting at `x = i+1`.
    // `memo[i].first` is the final `x` value, `memo[i].second` is the total `y` added.
    // `memo[i].first = -1` indicates non-terminating.
    // `memo[i].first = -2` indicates not yet computed.
    std::vector<std::pair<long long, long long>> memo(n + 1, {-2, 0});
    std::vector<bool> visiting(n + 1, false); // To detect cycles

    // Function to compute result for a given starting x
    // Returns {final_x, total_y_added}
    // If non-terminating, returns {-1, 0}
    std::function<std::pair<long long, long long>(long long)> solve = 
        [&](long long current_x) -> std::pair<long long, long long> {

        if (current_x <= 0 || current_x > n) {
            return {current_x, 0}; // Terminated
        }

        if (memo[current_x].first != -2) {
            return memo[current_x]; // Already computed
        }

        if (visiting[current_x]) {
            return memo[current_x] = {-1, 0}; // Cycle detected, non-terminating
        }

        visiting[current_x] = true;

        long long val_ax = a_values[current_x - 1];

        // Step 2: x = x + a_x, y = y + a_x
        long long x_after_step2 = current_x + val_ax;
        long long y_added_step2 = val_ax;

        // Check termination after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            visiting[current_x] = false;
            return memo[current_x] = {x_after_step2, y_added_step2};
        }

        // Step 3: x = x - a_x_after_step2, y = y + a_x_after_step2
        long long val_ax_after_step2 = a_values[x_after_step2 - 1];
        long long x_after_step3 = x_after_step2 - val_ax_after_step2;
        long long y_added_step3 = val_ax_after_step2;

        // Recursively solve for the next state
        std::pair<long long, long long> next_result = solve(x_after_step3);

        visiting[current_x] = false;

        if (next_result.first == -1) {
            return memo[current_x] = {-1, 0}; // Non-terminating
        } else {
            return memo[current_x] = {next_result.first, y_added_step2 + y_added_step3 + next_result.second};
        }
    };

    std::pair<long long, long long> result = solve(1);

    if (result.first == -1) {
        return -1;
    } else {
        return y + result.second;
    }
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n - 1);
    for (int i = 0; i < n - 1; ++i) {
        std::cin >> a_suffix[i];
    }

    // Precompute results for x > 1.
    // This is a bit tricky because a_1 changes.
    // The `solve` function above is designed to be called once per `a_1`.
    // The problem constraints (N=2e5) mean N calls to `simulate` with N*logN or N complexity is too slow.
    // N * N is 4e10, too slow.
    // N * log N is 2e5 * 18 = 3.6e6, feasible.
    // N * constant is 2e5, feasible.

    // The key observation is that for any x > 1, the value a_x is fixed (from a_suffix).
    // Only a_1 changes.
    // So, if we start at x=1, we use a_1.
    // Then we go to x_after_step2 = 1 + a_1.
    // Then we go to x_after_step3 = x_after_step2 - a_{x_after_step2}.
    // If x_after_step3 is 1, we have a cycle involving a_1.
    // If x_after_step3 is > 1, then the subsequent path is independent of a_1.

    // Let's define `dp[x]` as the pair `{final_x, total_y_added}` starting from `x` and executing the full (step 2, step 3) cycle until termination.
    // `dp[x].first = -1` means non-terminating.
    // `dp[x].first = -2` means not yet computed.
    // `dp[x].first = -3` means currently computing (cycle detected).

    std::vector<std::pair<long long, long long>> dp(n + 1, {-2, 0});

    // `a_values_fixed` stores a_2, ..., a_n at indices 1, ..., n-1.
    // `a_values_fixed[0]` is unused.
    std::vector<long long> a_values_fixed(n + 1);
    for (int k = 0; k < n - 1; ++k) {
        a_values_fixed[k + 2] = a_suffix[k];
    }

    // Function to compute dp values for x > 1
    // This function will be called for x from n down to 2.
    // It computes dp[current_x] assuming dp values for larger x are already computed or will be computed.
    // Returns {final_x, total_y_added}
    // If non-terminating, returns {-1, 0}
    std::function<std::pair<long long, long long>(long long)> compute_dp = 
        [&](long long current_x) -> std::pair<long long, long long> {

        if (current_x <= 0 || current_x > n) {
            return {current_x, 0}; // Terminated
        }

        if (dp[current_x].first != -2) {
            return dp[current_x]; // Already computed or in cycle
        }

        // Mark as currently computing to detect cycles
        dp[current_x].first = -3; 

        long long val_ax = a_values_fixed[current_x]; // a_x

        // Step 2: x = x + a_x, y = y + a_x
        long long x_after_step2 = current_x + val_ax;
        long long y_added_step2 = val_ax;

        // Check termination after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            return dp[current_x] = {x_after_step2, y_added_step2};
        }

        // Step 3: x = x - a_x_after_step2, y = y + a_x_after_step2
        long long val_ax_after_step2 = a_values_fixed[x_after_step2]; // a_{x_after_step2}
        long long x_after_step3 = x_after_step2 - val_ax_after_step2;
        long long y_added_step3 = val_ax_after_step2;

        // Recursively solve for the next state
        std::pair<long long, long long> next_result = compute_dp(x_after_step3);

        if (next_result.first == -3) { // Cycle detected
            return dp[current_x] = {-1, 0}; // Non-terminating
        } else if (next_result.first == -1) {
            return dp[current_x] = {-1, 0}; // Non-terminating
        } else {
            return dp[current_x] = {next_result.first, y_added_step2 + y_added_step3 + next_result.second};
        }
    };

    // Compute dp values for x from n down to 2.
    // This order helps ensure that when compute_dp(current_x) is called,
    // any x_after_step3 > current_x would have already been computed.
    // If x_after_step3 < current_x, it will be computed recursively.
    // If x_after_step3 == current_x, it's a cycle.
    for (int i = 2; i <= n; ++i) {
        if (dp[i].first == -2) { // If not yet computed
            compute_dp(i);
        }
    }

    // Now, for each i (1 <= i <= n-1), we run the program with a_1 = i.
    for (int initial_a1 = 1; initial_a1 < n; ++initial_a1) {
        long long current_x = 1;
        long long current_y = 0;

        long long val_a1 = initial_a1;

        // Step 2: x = x + a_1, y = y + a_1
        long long x_after_step2 = current_x + val_a1;
        long long y_added_step2 = val_a1;

        // Check termination after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << current_y + y_added_step2 << "\n";
            continue;
        }

        // Step 3: x = x - a_x_after_step2, y = y + a_x_after_step2
        long long val_ax_after_step2 = a_values_fixed[x_after_step2]; // a_{x_after_step2}
        long long x_after_step3 = x_after_step2 - val_ax_after_step2;
        long long y_added_step3 = val_ax_after_step2;

        // Now we are at x_after_step3, and y has increased by y_added_step2 + y_added_step3.
        // We need to find the result from x_after_step3.
        std::pair<long long, long long> result_from_x_after_step3;

        if (x_after_step3 == 1) {
            // This means we are back to x=1. This forms a cycle.
            // The problem states "it may never terminate".
            // If x_after_step3 is 1, and we started with a_1, we will repeat the same steps.
            // This is a non-terminating cycle.
            result_from_x_after_step3 = {-1, 0};
        } else {
            // Use the precomputed dp value.
            result_from_x_after_step3 = dp[x_after_step3];
        }

        if (result_from_x_after_step3.first == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + y_added_step2 + y_added_step3 + result_from_x_after_step3.second << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s or all 2s)
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (long long)a[n - 2].value + a[n - 1].value - ((long long)a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences
    // This case is optimal when h is relatively small.
    // We try to put a[0] in one subsequence and a[1] in another.
    // The smallest possible sum is a[0] + a[1].
    // If a[0] and a[1] are in different subsequences, min_f = a[0] + a[1] + h.
    // If a[0] and a[1] are in the same subsequence, min_f = a[0] + a[1].
    //
    // The largest possible sum is a[n-2] + a[n-1].
    // If a[n-2] and a[n-1] are in different subsequences, max_f = a[n-2] + a[n-1] + h.
    // If a[n-2] and a[n-1] are in the same subsequence, max_f = a[n-2] + a[n-1].

    // Consider a partition where a[0] is in subsequence 1, and a[1]...a[n-1] are in subsequence 2.
    // This is a specific partition strategy that often works well.
    //
    // Subsequence 1: {a[0]}
    // Subsequence 2: {a[1], a[2], ..., a[n-1]}
    //
    // Possible f values:
    // 1. a[i] + a[j] for i, j >= 1 (both in subseq 2)
    //    Min: a[1] + a[2]
    //    Max: a[n-2] + a[n-1]
    // 2. a[0] + a[i] + h for i >= 1 (a[0] in subseq 1, a[i] in subseq 2)
    //    Min: a[0] + a[1] + h
    //    Max: a[0] + a[n-1] + h
    //
    // Overall min_f for this partition: min(a[1]+a[2], a[0]+a[1]+h)
    // Overall max_f for this partition: max(a[n-2]+a[n-1], a[0]+a[n-1]+h)
    //
    // This specific partition strategy is not necessarily optimal.
    // The key insight is that if h is small, we want to avoid the +h penalty for small sums.
    // If h is large, we want to avoid the +h penalty for large sums.

    // Let's consider the partition where a[0] is in group 1, and a[1]...a[n-1] are in group 2.
    // This is a common strategy for minimizing range.
    //
    // min_f_val:
    //   - a[1] + a[2] (if n >= 3, both in group 2)
    //   - a[0] + a[1] + h (a[0] in group 1, a[1] in group 2)
    //   So, min_f = min(a[1] + a[2], a[0] + a[1] + h) if n >= 3.
    //   If n=2, only a[0]+a[1]+h is possible.
    //
    // max_f_val:
    //   - a[n-2] + a[n-1] (both in group 2)
    //   - a[0] + a[n-1] + h (a[0] in group 1, a[n-1] in group 2)
    //   So, max_f = max(a[n-2] + a[n-1], a[0] + a[n-1] + h)
    //
    // Goodness = max_f - min_f

    long long min_f_val_case2;
    if (n == 2) {
        min_f_val_case2 = (long long)a[0].value + a[1].value + h;
    } else {
        min_f_val_case2 = std::min((long long)a[1].value + a[2].value, (long long)a[0].value + a[1].value + h);
    }

    long long max_f_val_case2 = std::max((long long)a[n - 2].value + a[n - 1].value, (long long)a[0].value + a[n - 1].value + h);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

// Function to check if a given 'x' (maximum operations) is feasible
bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The previous element in the modified array must be at least this value

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: current_a is already >= prev_val
        // We need to ensure (current_a + k) % m >= prev_val for some k <= x.
        // The smallest possible value for (current_a + k) % m is current_a itself (when k=0).
        // If current_a >= prev_val, we can potentially keep current_a as is (k=0).
        // We must check if current_a can be made smaller than prev_val by adding x.
        // If current_a + x < m and current_a + x < prev_val, then we cannot make it >= prev_val.
        // This means if current_a >= prev_val, we can always choose k=0, and it satisfies the condition.
        // The only exception is if current_a + x would wrap around and become smaller than prev_val.
        // But we want to make it non-decreasing, so we prefer to keep it as small as possible but >= prev_val.
        // So if current_a >= prev_val, we can just set the current element to current_a.
        // The only constraint is that current_a + x must be >= prev_val.
        // If current_a + x >= m, then it wraps around.
        // If current_a + x < m, then we must have current_a >= prev_val.
        // If current_a >= prev_val, we can use 0 operations on a[i] and keep it a[i].
        // This is valid as long as a[i] + x doesn't wrap around and become less than prev_val.
        // More precisely, if a[i] >= prev_val, we can choose 0 operations.
        // The value becomes a[i]. This is valid.
        // The only way this fails is if a[i] + x < m AND a[i] + x < prev_val.
        // But if a[i] >= prev_val, then a[i] + x >= prev_val. So this is not an issue.
        // So if a[i] >= prev_val, we can always make it a[i] (0 operations).
        // The only time we *must* increment is if a[i] < prev_val.

        // Let's re-evaluate. We need to find b_i such that b_i >= prev_val and b_i = (a_i + k) % m for some 0 <= k <= x.
        // If a_i >= prev_val:
        //   We can choose k=0, then b_i = a_i. This satisfies b_i >= prev_val.
        //   This is always a valid choice. So we set prev_val = a_i.
        // If a_i < prev_val:
        //   We must increment a_i.
        //   We need (a_i + k) % m >= prev_val.
        //   The smallest value (a_i + k) % m can take while being >= prev_val is prev_val itself.
        //   This requires (a_i + k) % m = prev_val.
        //   This means a_i + k = prev_val OR a_i + k = prev_val + m.
        //   If a_i + k = prev_val, then k = prev_val - a_i.
        //   If a_i + k = prev_val + m, then k = prev_val + m - a_i.
        //   We need to find if there exists a k in [0, x] such that (a_i + k) % m >= prev_val.
        //   Consider the range of values [a_i, (a_i + x) % m] (possibly wrapping around).
        //   If a_i + x < m:
        //     The possible values are [a_i, a_i + x].
        //     We need to find if there's a value in this range that is >= prev_val.
        //     Since a_i < prev_val, we need a_i + x >= prev_val.
        //     If a_i + x < prev_val, then we cannot make it >= prev_val. So it's impossible.
        //     If a_i + x >= prev_val, then we can choose k = prev_val - a_i. This k is <= x.
        //     So we can set b_i = prev_val.
        //   If a_i + x >= m (i.e., it wraps around):
        //     The possible values are [a_i, m-1] U [0, (a_i + x) % m].
        //     Since a_i < prev_val, we need to find a value >= prev_val.
        //     The range [a_i, m-1] contains values >= prev_val if prev_val <= m-1.
        //     The range [0, (a_i + x) % m] contains values >= prev_val if prev_val <= (a_i + x) % m.
        //     Since a_i < prev_val, we must use operations.
        //     If we can reach prev_val by adding k <= x, then we can set b_i = prev_val.
        //     This means (a_i + k) % m = prev_val.
        //     The smallest k to achieve this is prev_val - a_i (if prev_val >= a_i) or prev_val + m - a_i (if prev_val < a_i).
        //     Since we are in the case a_i < prev_val, the smallest k is prev_val - a_i.
        //     If prev_val - a_i <= x, then we can achieve prev_val. So we set b_i = prev_val.
        //     If prev_val - a_i > x, then we cannot reach prev_val without exceeding x operations.
        //     In this case, the smallest value we can achieve that is >= prev_val is not possible.
        //     The values we can achieve are (a_i + k) % m for k in [0, x].
        //     If a_i + x < m, then the range is [a_i, a_i + x]. If prev_val is not in this range, it's impossible.
        //     Specifically, if a_i + x < prev_val, it's impossible.
        //     If a_i + x >= m, then the range of values is [a_i, m-1] U [0, (a_i + x) % m].
        //     Since a_i < prev_val, we need to find a value >= prev_val.
        //     If prev_val is in [a_i, m-1], then we can achieve it.
        //     If prev_val is not in [a_i, m-1] (i.e., prev_val > m-1, which is impossible, or prev_val < a_i, which is the current case),
        //     then we must use the wrapped-around part.
        //     The wrapped-around part is [0, (a_i + x) % m].
        //     If prev_val is in this range, then we can achieve it.
        //     So, if a_i < prev_val:
        //       We need to check if we can make a_i into something >= prev_val using at most x operations.
        //       The values we can obtain are (a_i + k) % m for k in [0, x].
        //       If a_i + x < m:
        //         The values are in [a_i, a_i + x].
        //         To satisfy b_i >= prev_val, we need a_i + x >= prev_val.
        //         If a_i + x < prev_val, it's impossible.
        //         Otherwise, we can set b_i = prev_val.
        //       If a_i + x >= m:
        //         The values are in [a_i, m-1] U [0, (a_i + x) % m].
        //         Since a_i < prev_val, we must use operations.
        //         We can always achieve any value in [0, (a_i + x) % m] by adding k <= x.
        //         We can also achieve any value in [a_i, m-1] by adding k <= x.
        //         Since a_i < prev_val, we need to reach prev_val.
        //         The number of operations needed to reach prev_val is (prev_val - a_i + m) % m.
        //         If (prev_val - a_i + m) % m <= x, then we can achieve prev_val.
        //         So we set b_i = prev_val.
        //         Otherwise, it's impossible.

        // Simplified logic:
        // We want to find b_i such that b_i >= prev_val and b_i = (a_i + k) % m for some 0 <= k <= x.
        // If a_i >= prev_val:
        //   We can choose k=0, so b_i = a_i. This is valid.
        //   We update prev_val = a_i.
        // Else (a_i < prev_val):
        //   We must increment a_i.
        //   We need to check if we can reach prev_val or something larger.
        //   The number of increments needed to reach prev_val is `diff = (prev_val - a_i + m) % m`.
        //   If `diff` is 0, it means `prev_val == a_i`, which contradicts `a_i < prev_val`.
        //   So `diff` is `prev_val - a_i` (if `prev_val > a_i`) or `prev_val - a_i + m` (if `prev_val < a_i`).
        //   Since `a_i < prev_val`, `diff = prev_val - a_i`.
        //   If `diff <= x`, it means we can increment `a_i` by `diff` times to reach `prev_val`.
        //   So we can set `b_i = prev_val`.
        //   If `diff > x`, it means we cannot reach `prev_val` by incrementing `a_i` at most `x` times.
        //   In this case, the maximum value we can reach is `(a_i + x) % m`.
        //   If `(a_i + x) % m` is still less than `prev_val`, then it's impossible.
        //   This happens if `a_i + x < m` and `a_i + x < prev_val`.
        //   If `a_i + x >= m` (wraps around), then `(a_i + x) % m` will be a small value.
        //   If `(a_i + x) % m` is less than `prev_val`, it's impossible.
        //   So, if `a_i < prev_val`:
        //     If `a_i + x < m`:
        //       If `a_i + x < prev_val`, then impossible. Return false.
        //       Else (`a_i + x >= prev_val`), we can set `b_i = prev_val`.
        //     Else (`a_i + x >= m`, wraps around):
        //       We can reach any value in `[a_i, m-1]` and `[0, (a_i + x) % m]`.
        //       Since `a_i < prev_val`, we need to reach `prev_val`.
        //       The number of operations needed to reach `prev_val` is `prev_val - a_i`.
        //       If `prev_val - a_i <= x`, we can reach `prev_val`. So `b_i = prev_val`.
        //       Else (`prev_val - a_i > x`), we cannot reach `prev_val`.
        //       The values we can reach are `a_i, a_i+1, ..., m-1, 0, 1, ..., (a_i+x)%m`.
        //       If `prev_val` is in `[a_i, m-1]`, then `prev_val - a_i <= x` must hold.
        //       If `prev_val` is in `[0, (a_i+x)%m]`, then `prev_val - a_i + m <= x` must hold.
        //       This is getting complicated. Let's simplify.

        // For each a_i, we want to find b_i such that:
        // 1. b_i >= prev_val
        // 2. b_i = (a_i + k) % m for some 0 <= k <= x
        // We want to choose the smallest possible b_i that satisfies these conditions, to make it easier for subsequent elements.

        // If a_i >= prev_val:
        //   We can choose k=0, so b_i = a_i. This satisfies b_i >= prev_val.
        //   This is the smallest possible b_i we can make that is >= prev_val.
        //   So, we set prev_val = a_i.
        // Else (a_i < prev_val):
        //   We must increment a_i.
        //   We need to find k in [0, x] such that (a_i + k) % m >= prev_val.
        //   Consider the value `a_i + x`.
        //   If `a_i + x < m`:
        //     The values we can form are `a_i, a_i+1, ..., a_i+x`.
        //     Since `a_i < prev_val`, we need `a_i+x >= prev_val`.
        //     If `a_i+x < prev_val`, then no value in `[a_i, a_i+x]` is >= `prev_val`. Impossible.
        //     Return false.
        //     Otherwise (`a_i+x >= prev_val`), we can choose `k = prev_val - a_i`. This `k` is <= `x`.
        //     So we can set `b_i = prev_val`.
        //     Update `prev_val = prev_val`.
        //   Else (`a_i + x >= m`, meaning it wraps around):
        //     The values we can form are `a_i, ..., m-1, 0, ..., (a_i+x)%m`.
        //     Since `a_i < prev_val`, we must use operations.
        //     We need to check if `prev_val` can be reached.
        //     The number of operations to reach `prev_val` from `a_i` is `prev_val - a_i`.
        //     If `prev_val - a_i <= x`:
        //       We can reach `prev_val` using `prev_val - a_i` operations.
        //       So we set `b_i = prev_val`.
        //       Update `prev_val = prev_val`.
        //     Else (`prev_val - a_i > x`):
