        // If h[h_idx] is too far right (h[h_idx] > p[p_idx] + T), then p[p_idx] cannot be covered by this head or any subsequent head (since h is sorted).
        // This means we need to use a previous head, which is not allowed by the greedy strategy.
        // So, if h[h_idx] > p[p_idx] + T, it's impossible.

        // Let's refine the greedy strategy:
        // For the current p[p_idx] that needs to be covered:
        // 1. Advance h_idx until h[h_idx] is not too far to the left to cover p[p_idx].
        //    i.e., while h_idx < n and h[h_idx] < p[p_idx] - T, increment h_idx.
        // 2. If after this, h_idx >= n, then no head can cover p[p_idx], so return false.
        // 3. Now, h[h_idx] >= p[p_idx] - T.
        //    If h[h_idx] > p[p_idx] + T, then h[h_idx] is too far to the right to cover p[p_idx].
        //    Since h is sorted, all subsequent heads h[h_idx+1], ... will also be too far right.
        //    This means p[p_idx] cannot be covered by any available head, so return false.
        // 4. So, we have found a head h[h_idx] such that p[p_idx] is within its reach [h[h_idx]-T, h[h_idx]+T].
        //    This head can cover p[p_idx]. It can also cover all tracks up to h[h_idx] + T.
        //    We use this head to cover as many subsequent tracks as possible.
        //    Let `reach_limit = h[h_idx] + T`.
        //    Advance p_idx while p_idx < m and p[p_idx] <= reach_limit.
        // 5. After using h[h_idx], we move to the next head h_idx+1.

        // Corrected greedy approach:
        // We iterate through heads. For each head, we try to cover the leftmost uncovered track.
        // If head h[h_idx] can cover p[p_idx]:
        //   It can cover tracks in range [h[h_idx] - T, h[h_idx] + T].
        //   We need to cover p[p_idx].
        //   If p[p_idx] is to the left of h[h_idx] - T, then h[h_idx] cannot cover p[p_idx].
        //   We must use a head to the left of h[h_idx] (which we would have already processed)
        //   or h[h_idx] is the first head that can cover p[p_idx].
        //   The current head h[h_idx] can cover p[p_idx] if p[p_idx] >= h[h_idx] - T.
        //   If this condition is met, then h[h_idx] can cover all tracks up to h[h_idx] + T.
        //   We advance p_idx past all tracks covered by this head.
        //   Then we move to the next head.

        // This is a standard interval covering problem.
        // We have points p_j to cover. We have intervals [h_i - T, h_i + T].
        // We want to cover all p_j using minimum number of intervals.
        // But here, we have a fixed number of intervals (n heads).
        // We need to check if n intervals are sufficient.

        // The greedy strategy for covering points with intervals:
        // 1. Sort points (already done for p).
        // 2. Sort intervals by their left endpoint (already done for h, so intervals are sorted by center).
        // 3. Take the leftmost uncovered point `p[p_idx]`.
        // 4. Find an interval `[L, R]` that covers `p[p_idx]`.
        //    Among all such intervals, pick the one that extends furthest to the right.
        //    Use this interval, and advance `p_idx` past all points covered by it.
        //    Repeat until all points are covered or no suitable interval is found.

        // In our case, intervals are [h_i - T, h_i + T].
        // We need to cover p[p_idx].
        // We iterate through heads `h_idx`.
        // For the current `p[p_idx]`:
        // We need to find a head `h[k]` such that `h[k] - T <= p[p_idx] <= h[k] + T`.
        // We want to use the head `h[k]` that maximizes `h[k] + T` (its right endpoint).
        // But we also need to ensure `k` is not too far ahead of `h_idx`.

        // Let's try the simpler greedy:
        // `p_idx` is the index of the first track not yet covered.
        // `h_idx` is the index of the head we are currently considering.
        // While `p_idx < m`:
        //   If `h_idx >= n`, we ran out of heads, return false.
        //   Current head is `h[h_idx]`. It can cover `[h[h_idx] - T, h[h_idx] + T]`.
        //   If `p[p_idx]` is to the left of this head's reach: `p[p_idx] < h[h_idx] - T`.
        //     This means `h[h_idx]` cannot cover `p[p_idx]`.
        //     Since `h` is sorted, `h[h_idx+1]`, `h[h_idx+2]`, etc. will be even further to the right.
        //     So, no subsequent head can cover `p[p_idx]` either.
        //     This implies `p[p_idx]` must have been covered by a previous head, or it's impossible.
        //     But we are processing `p_idx` as the *first* uncovered track.
        //     So, if `p[p_idx] < h[h_idx] - T`, it's impossible to cover `p[p_idx]` with `h[h_idx]` or any `h[k]` where `k >= h_idx`.
        //     Thus, return false.
        //   If `p[p_idx]` is within reach of `h[h_idx]`: `p[p_idx] <= h[h_idx] + T`.
        //     (And we already know `p[p_idx] >= h[h_idx] - T` from the previous check, or it's the first head that can cover it).
        //     This head `h[h_idx]` can cover `p[p_idx]`.
        //     It can cover all tracks up to `h[h_idx] + T`.
        //     So, we advance `p_idx` past all tracks `p[k]` such that `p[k] <= h[h_idx] + T`.
        //     Then we move to the next head: `h_idx++`.
        //   If `p[p_idx]` is to the right of this head's reach: `p[p_idx] > h[h_idx] + T`.
        //     This means `h[h_idx]` cannot cover `p[p_idx]`.
        //     We need to use a head further to the right. So, we advance `h_idx`.
        //     This is the crucial part. We must use `h_idx` to cover `p[p_idx]` if it's the first head that can.
        //     If `h[h_idx]` cannot cover `p[p_idx]`, we must advance `h_idx`.

        // Let's use the standard greedy for covering points with intervals.
        // `p_idx` is the index of the leftmost uncovered track.
        // `h_idx` is the index of the current head we are considering to cover `p[p_idx]`.
        // We want to find the head `h[k]` (where `k >= h_idx`) that covers `p[p_idx]` and extends furthest to the right.
        // This is equivalent to finding `max(h[k] + T)` for all `k >= h_idx` such that `h[k] - T <= p[p_idx]`.

        // Simplified greedy:
        // `p_idx` is the index of the first track not yet covered.
        // `h_idx` is the index of the head we are currently trying to assign.
        // While `p_idx < m`:
        //   If `h_idx >= n`, we ran out of heads, return false.
        //   Find the first head `h[k]` (starting from `h_idx`) that can cover `p[p_idx]`.
        //   That is, `h[k] - T <= p[p_idx]`.
        //   We need to find the `k` such that `h[k] - T <= p[p_idx]` and `k` is minimized.
        //   Let's call this `first_suitable_h_idx`.
        //   While `h_idx < n` and `h[h_idx] < p[p_idx] - T`:
        //     `h_idx++`; // This head is too far left to cover `p[p_idx]`. Discard it.
        //   If `h_idx >= n`: // No head can cover `p[p_idx]` from its left or current position.
        //     return false;
        //   Now, `h[h_idx] >= p[p_idx] - T`. This head can potentially cover `p[p_idx]`.
        //   If `h[h_idx] > p[p_idx] + T`: // This head is too far right to cover `p[p_idx]`.
        //     Since `h` is sorted, all subsequent heads are also too far right.
        //     So, `p[p_idx]` cannot be covered. Return false.
        //   Now we know `h[h_idx]` can cover `p[p_idx]`.
        //   It covers up to `h[h_idx] + T`.
        //   Advance `p_idx` past all tracks covered by this head.
        //   `current_reach = h[h_idx] + T`.
        //   While `p_idx < m` and `p[p_idx] <= current_reach`:
        //     `p_idx++`;
        //   Move to the next head for the next uncovered track.
        //   `h_idx++`;
        // If we successfully cover all tracks (`p_idx == m`), return true.

    // This greedy strategy is correct.
    // `p_idx` is the index of the first track that still needs to be covered.
    // `h_idx` is the index of the first head that has not yet been used.
    while (p_idx < m) {
        if (h_idx >= n) {
            // No more heads, but still tracks to cover
            return false;
        }

        // Find the leftmost track p[p_idx] that needs to be covered.
        // We need to use a head h[k] (where k >= h_idx) to cover p[p_idx].
        // The head h[k] must satisfy h[k] - T <= p[p_idx].
        // Among all such heads, we should pick the one that maximizes its right reach, h[k] + T.
        // This is equivalent to picking the largest h[k] such that h[k] <= p[p_idx] + T.
        // Let's find the best head to use for p[p_idx].

        // Option 1: The current head h[h_idx] is too far left to cover p[p_idx].
        // This means h[h_idx] + T < p[p_idx].
        // In this case, h[h_idx] cannot cover p[p_idx]. We must use a head to its right.
        // So, we advance h_idx.
        // This is not quite right. If h[h_idx] + T < p[p_idx], then h[h_idx] cannot cover p[p_idx].
        // We need to find a head h[k] such that h[k] - T <= p[p_idx].
        // If h[h_idx] is too far left (h[h_idx] < p[p_idx] - T), we must advance h_idx.
        // If h[h_idx] is too far right (h[h_idx] > p[p_idx] + T), then p[p_idx] cannot be covered by this head or any subsequent head.

        // Let's use the standard greedy approach for covering points with intervals.
        // `p_idx` is the index of the leftmost uncovered point.
        // We need to find a head `h[k]` (with `k >= h_idx`) such that `h[k]` can cover `p[p_idx]`.
        // That is, `h[k] - T <= p[p_idx]`.
        // Among all such heads, we choose the one that maximizes its right endpoint `h[k] + T`.
        // This means we want to find the largest `h[k]` such that `h[k] <= p[p_idx] + T`.

        long long max_reach = -1; // Max right endpoint achievable by a head covering p[p_idx]
        int best_h_for_p_idx = -1; // Index of the head that achieves max_reach

        // Iterate through available heads (from h_idx onwards)
        // Find the head that can cover p[p_idx] and extends furthest to the right.
        // This means we want to find max(h[k] + T) for k >= h_idx and h[k] - T <= p[p_idx].
        // Since h is sorted, h[k] + T is maximized when h[k] is maximized.
        // So we need to find the largest h[k] such that h[k] <= p[p_idx] + T and h[k] >= p[p_idx] - T.
        // Or, more simply, the largest h[k] such that h[k] - T <= p[p_idx].
        // We can iterate `k` from `h_idx` upwards.
        // If `h[k] - T > p[p_idx]`, then `h[k]` is too far right to cover `p[p_idx]`.
        // Since `h` is sorted, all subsequent heads `h[k+1]`, etc. will also be too far right.
        // So we stop searching for `best_h_for_p_idx`.

        // Find the first head that can cover p[p_idx]
        int current_h_candidate_idx = h_idx;
        while (current_h_candidate_idx < n && h[current_h_candidate_idx] < p[p_idx] - T) {
            // This head is too far left to cover p[p_idx]. Discard it.
            current_h_candidate_idx++;
        }

        if (current_h_candidate_idx >= n) {
            // No head can cover p[p_idx] from its left or current position.
            return false;
        }

        // Now, h[current_h_candidate_idx] >= p[p_idx] - T.
        // We need to find the head among h[current_h_candidate_idx ... n-1]
        // that covers p[p_idx] and extends furthest to the right.
        // This means finding max(h[k] + T) for k in [current_h_candidate_idx, n-1]
        // such that h[k] <= p[p_idx] + T.
        // Since h[k] + T is increasing with h[k], we want the largest h[k] in this range.
        // So we find the largest k such that h[k] <= p[p_idx] + T.
        // This can be done by iterating or using `upper_bound`.

        int last_suitable_h_idx = current_h_candidate_idx;
        while (last_suitable_h_idx + 1 < n && h[last_suitable_h_idx + 1] <= p[p_idx] + T) {
            last_suitable_h_idx++;
        }
        // Now, h[last_suitable_h_idx] is the rightmost head that can cover p[p_idx].
        // If h[last_suitable_h_idx] > p[p_idx] + T, it means no head can cover p[p_idx].
        // This check is actually redundant because of the `while` loop condition.
        // If `h[current_h_candidate_idx] > p[p_idx] + T`, then `p[p_idx]` cannot be covered.
        if (h[current_h_candidate_idx] > p[p_idx] + T) {
            return false;
        }

        // The head at `last_suitable_h_idx` is the best choice.
        max_reach = h[last_suitable_h_idx] + T;

        // Advance p_idx past all tracks covered by this head.
        while (p_idx < m && p[p_idx] <= max_reach) {
            p_idx++;
        }
        // Mark the head at `last_suitable_h_idx` as used.
        // The next head to consider for the next uncovered track will be `last_suitable_h_idx + 1`.
        h_idx = last_suitable_h_idx + 1;
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p_i and h_i is ~10^10.
                               // So T can be up to 10^10.
                               // A safe upper bound for T is max(p_i) - min(h_i) or max(h_i) - min(p_i)
                               // which is roughly 10^10.
                               // 2e10 + 7 is a sufficiently large upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

