#include <iostream>
#include <vector>
#include <algorithm> // Not strictly needed for this solution, but good practice for permutations

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem asks for a *different* permutation p' with the same fingerprint.
        // Reversing the permutation p always produces a permutation p' with the same fingerprint.
        // If p is a palindrome (e.g., [1,2,1] which is not a permutation, or [1,2,3,2,1] not a permutation),
        // then reversing it would yield the same permutation.
        // However, a permutation of length n consists of distinct integers from 1 to n.
        // For n >= 2, a permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2).
        // For example, if p_1 = p_n, then p_1 and p_n are the same element, but they must be distinct.
        // So, p_1 != p_n for any permutation of length n >= 2.
        // This means reversing a permutation of length n >= 2 always yields a different permutation.
        // Example: [1,2] reversed is [2,1]. Different.
        // Example: [1,2,3] reversed is [3,2,1]. Different.
        // Example: [2,1,6,5,4,3] reversed is [3,4,5,6,1,2]. Different.

        // So, simply print the reversed permutation.
        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

