#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long haybales_in_pile1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
        int pile_index = i + 1; // Convert 0-indexed i to 1-indexed pile number
        int cost_per_haybale = i; // Cost to move one haybale from pile (i+1) to pile 1 is i days

        if (cost_per_haybale == 0) { // Should not happen for i >= 1
            continue;
        }

        // Calculate how many haybales can be moved from this pile given remaining days
        long long haybales_movable_by_days = remaining_days / cost_per_haybale;

        // The actual number of haybales we can move is limited by a[i] and available days
        long long haybales_to_move = std::min((long long)a[i], haybales_movable_by_days);

        haybales_in_pile1 += haybales_to_move;
        remaining_days -= haybales_to_move * cost_per_haybale;

        if (remaining_days <= 0) {
            break; // No more days left
        }
    }

    std::cout << haybales_in_pile1 << std::endl;
}

