#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags `has_one` and `has_minus_one` reflect the state of a[0...i]
            // before considering a[i] itself.
            // If a[i] is 1 or -1, it contributes to the flags for elements before it.
            // But for elements after it, it's already processed.
            // So, we update flags for elements *before* index i.
            if (a[i] == 1) has_one = true;
            if (a[i] == -1) has_minus_one = true;
            continue;
        }

        // If a[i] != b[i], we need to change a[i].
        // This change must come from a[k] where k < i.
        // The current a[i] value is fixed for operations on a[j] where j > i.
        // So, we need to check if we can reach b[i] from a[i] using a[k] (k < i).

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_one) { // Can only increase if there's a '1' at an earlier index
                possible = false;
                break;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_minus_one) { // Can only decrease if there's a '-1' at an earlier index
                possible = false;
                break;
            }
        }

        // If a[i] is 1 or -1, it contributes to the flags for elements before it.
        // But for elements after it, it's already processed.
        // So, we update flags for elements *before* index i.
        if (a[i] == 1) has_one = true;
        if (a[i] == -1) has_minus_one = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

