        int last_r_pos = -1; // Represents the last position where an 'R' was encountered, or -1 for cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at cell i+1 (1-indexed).
                // The previous 'R' (or start) was at last_r_pos+1 (1-indexed).
                // The distance between these two points is (i+1) - (last_r_pos+1) = i - last_r_pos.
                max_dist = std::max(max_dist, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // The last 'R' was at cell last_r_pos+1.
        // The target is cell n+1.
        // The distance is (n+1) - (last_r_pos+1) = n - last_r_pos.
        max_dist = std::max(max_dist, n - last_r_pos);

        std::cout << max_dist << "\n";
    }
