#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This is the first part of the "valley" structure.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // If p is 0, the entire array is non-decreasing.
    // If p is n-1, the last two elements are a[n-2] < a[n-1].
    // If p is 1, a[0] >= a[1] is false, so a[0] < a[1].
    // If p is 0, a[0] is the first element.

    // Now, p is the first index from the right such that a[p-1] < a[p] (if p > 0).
    // The suffix a[p...n-1] is non-decreasing.
    // We need to find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This is the second part of the "valley" structure.
    int q = p;
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }

    // The elements a[q...n-1] form a "good" array.
    // The prefix to erase has length `q`.
    std::cout << q << std::endl;
}

