    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if we have already added more '(' than ')'
            // or if we have added enough '(' and still need ')'
            // The condition `result.length() - (k/2 - open_needed) > (k/2 - close_needed)`
            // ensures that the current balance of '(' and ')' in `result` is positive
            // before adding a ')'
            // A simpler way is to just add ')' if we still need them and we have enough '('
            // to balance them eventually.
            // The problem guarantees a solution exists.
            // A greedy approach of taking first k/2 '(' and first k/2 ')' that appear after them
            // will work because the original string is regular.
            // We just need to ensure we don't add more ')' than '(' at any point.
            // The `open_needed` and `close_needed` counts are for the final string.
            // `k/2 - open_needed` is the count of '(' already added.
            // `k/2 - close_needed` is the count of ')' already added.
            // We can add ')' if `(k/2 - open_needed) > (k/2 - close_needed)`
            // This means `open_count_in_result > close_count_in_result`
            if ((k / 2 - open_needed) > (k / 2 - close_needed) && close_needed > 0) {
                result += ')';
                close_needed--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for n=1 staircase
        long long n_val = 1;        // Current n for staircase (1, 3, 7, 15, ...)
        while (x >= current_cost) {
            count++;
            x -= current_cost;
            n_val = n_val * 2 + 1; // Next n value (1 -> 3 -> 7 -> 15 ...)
            // Cost for n_val stairs is n_val * (n_val + 1) / 2
            // This can be calculated as current_cost * 2 + (n_val + 1) / 2
            // Or more simply, the cost for n_val stairs is (2*n_prev + 1) * (2*n_prev + 2) / 2
            // which is (2*n_prev + 1) * (n_prev + 1)
            // Let's use the formula: n_val * (n_val + 1) / 2
            // n_val is (2^k - 1)
            // Cost is (2^k - 1) * (2^k) / 2 = (2^k - 1) * 2^(k-1)
            // For k=1, n=1, cost = 1 * 2^0 = 1
            // For k=2, n=3, cost = 3 * 2^1 = 6
            // For k=3, n=7, cost = 7 * 2^2 = 28
            // For k=4, n=15, cost = 15 * 2^3 = 120
            // The next cost is (n_val * (n_val + 1)) / 2
            // Since n_val is always odd, n_val+1 is even.
            // So (n_val+1)/2 is an integer.
            // current_cost = n_val * ((n_val + 1) / 2);
            // This is equivalent to current_cost = (2*n_prev + 1) * (n_prev + 1)
            // where n_prev is the previous n_val.
            // Let's use the direct formula for the next cost:
            // The next n_val is 2*n_val_old + 1.
            // The cost for n_val_old was n_val_old * (n_val_old + 1) / 2.
            // The cost for n_val_new is n_val_new * (n_val_new + 1) / 2.
            // n_val_new = 2 * n_val_old + 1
            // cost_new = (2 * n_val_old + 1) * (2 * n_val_old + 2) / 2
            //          = (2 * n_val_old + 1) * (n_val_old + 1)
            // This is the correct recurrence for the cost.
            // current_cost = (2 * n_val_old + 1) * (n_val_old + 1)
            // Let's use n_val to represent the current n for which we just calculated the cost.
            // So, the next cost will be for n_val_next = 2 * n_val + 1.
            // The cost for n_val_next is (2 * n_val + 1) * (n_val + 1).
            // This is the value we need to assign to current_cost for the next iteration.
            // To avoid overflow, we need to check if n_val * 2 + 1 will exceed max long long.
            // n_val can go up to 2 * 10^9 (approx) for x = 10^18.
            // (2 * 10^9)^2 is 4 * 10^18, which fits in long long.
            // So n_val * (n_val + 1) / 2 can be up to 10^18.
            // The next n_val is 2*n_val + 1.
            // The next cost is (2*n_val + 1) * (n_val + 1).
            // If n_val is 2*10^9, then 2*n_val+1 is 4*10^9.
            // (n_val+1) is 2*10^9.
            // Product is 8*10^18. This fits in long long.
            // But if n_val is 4*10^9, then 2*n_val+1 is 8*10^9.
            // (n_val+1) is 4*10^9.
            // Product is 32*10^18, which overflows long long.
            // So we need to check for overflow before calculating current_cost.
            // The maximum value for n_val is when current_cost is around 10^18.
            // n_val * (n_val + 1) / 2 approx n_val^2 / 2.
            // n_val^2 / 2 approx 10^18 => n_val^2 approx 2 * 10^18 => n_val approx sqrt(2) * 10^9 approx 1.4 * 10^9.
            // So n_val can be up to around 1.4 * 10^9.
            // The next n_val would be 2 * (1.4 * 10^9) + 1 = 2.8 * 10^9.
            // The next cost would be (2.8 * 10^9) * (1.4 * 10^9) approx 4 * 10^18. This fits.
            // The n_val after that would be 2 * (2.8 * 10^9) + 1 = 5.6 * 10^9.
            // The cost for this would be (5.6 * 10^9) * (2.8 * 10^9) approx 15 * 10^18. This fits.
            // The n_val after that would be 2 * (5.6 * 10^9) + 1 = 11.2 * 10^9.
            // The cost for this would be (11.2 * 10^9) * (5.6 * 10^9) approx 60 * 10^18. This overflows.
            // So we need to check for overflow when calculating (2 * n_val + 1) * (n_val + 1).
            // Max long long is approx 9 * 10^18.
            // If n_val > 2 * 10^9, then (n_val + 1) > 2 * 10^9.
            // (2 * n_val + 1) > 4 * 10^9.
            // Product > 8 * 10^18. This is close to overflow.
            // A safe check: if (n_val + 1) > LLONG_MAX / (2 * n_val + 1), then overflow.
            // Or simply, if current_cost * 4 (approx) overflows, then stop.
            // The sequence of costs is 1, 6, 28, 120, 496, 2016, 8128, 32640, 130816, 523776, 2097152, 8388608, 33554432, 134217728, 536870912, 2147483648, 8589934592, 34359738368, 137438953472, 549755813888, 2199023255552, 8796093022208, 35184372088832, 140737488355328, 562949953421312, 2251799813685248, 9007199254740992, 36028797018963968, 144115188075855872, 576460752303423488, 2305843009213693952, 9223372036854775808 (overflows long long).
            // The last valid cost is 2305843009213693952.
            // The next cost would be 9223372036854775808, which is 2^63, exactly LLONG_MAX + 1.
            // So we can calculate up to 30 costs.
            // The 31st cost would overflow.
            // So, we can just calculate it and check if it's negative (overflow).
            // Or, more robustly, check before multiplication.
            // n_val_next = 2 * n_val + 1;
            // cost_next = n_val_next * (n_val + 1);
            // If n_val + 1 > LLONG_MAX / n_val_next, then overflow.
            // Since n_val is always positive, n_val + 1 is positive.
            // n_val_next is also positive.
            long long next_n_val = n_val * 2 + 1;
            long long factor2 = n_val + 1;

            // Check for overflow before calculating next_cost
            // If factor2 > LLONG_MAX / next_n_val, then overflow.
            // This check is sufficient.
            if (next_n_val > 0 && factor2 > 0 && factor2 > 9223372036854775807LL / next_n_val) { // LLONG_MAX
                break; // Next cost would overflow, so we can't build any more.
            }
            current_cost = next_n_val * factor2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // Check if the current subarray [min_idx, max_idx] forms a permutation of 1 to m
        // Condition 1: Length of subarray must be m
        // Condition 2: Minimum element in subarray is 1 (guaranteed by min_idx tracking)
        // Condition 3: Maximum element in subarray is m (guaranteed by max_idx tracking)
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to partition 2n students into two classes,
        // each with an odd number of students.
        // Let the sizes of the two classes be S1 and S2.
        // S1 + S2 = 2n.
        // S1 must be odd, S2 must be odd.
        // The smallest possible odd size is 1.
        // The largest possible odd size is 2n-1.
        //
        // Consider the sorted array a_1, a_2, ..., a_{2n}.
        //
        // If we pick the median of the first class to be a_i and
        // the median of the second class to be a_j,
        // then the first class must contain a_i and some (S1-1)/2 elements smaller than a_i
        // and some (S1-1)/2 elements larger than a_i.
        // Similarly for the second class.
        //
        // To minimize the absolute difference between medians, we want the medians to be as close as possible.
        //
        // Consider the case where one class has size 1.
        // Let Class 1 have size 1. Its median is a single student's skill.
        // Let Class 2 have size 2n-1. Its median is the ( (2n-1)-1 )/2 + 1 = n-1+1 = n-th element.
        //
        // If we pick a_i as the median of a class of size S, then there must be
        // (S-1)/2 elements smaller than or equal to a_i and (S-1)/2 elements greater than or equal to a_i.
        //
        // The key insight for this problem is that to minimize the difference between medians,
        // we should choose the medians from the "middle" of the sorted array.
        //
        // If we sort the array a_1, a_2, ..., a_{2n},
        // and we want to form two classes of odd sizes, say S1 and S2.
        // The smallest possible median for any class is a_1 (if S1=1).
        // The largest possible median for any class is a_{2n} (if S1=1).
        //
        // Consider the two elements a_n and a_{n+1} in the sorted array.
        // These are the two "middle" elements.
        //
        // If we assign a_n to be the median of one class and a_{n+1} to be the median of the other class,
        // can we always form valid classes?
        //
        // Let's try to make a_n the median of Class 1 and a_{n+1} the median of Class 2.
        //
        // Class 1: median a_n.
        // To make a_n the median, we need (S1-1)/2 elements smaller than or equal to a_n,
        // and (S1-1)/2 elements greater than or equal to a_n.
        // The smallest possible S1 is 1. If S1=1, median is a_n.
        // The largest possible S1 is 2n-1. If S1=2n-1, median is a_n.
        //
        // If we choose a_n as the median of the first class, and a_{n+1} as the median of the second class.
        //
        // Class 1: median a_n. We can form this class using elements a_1, ..., a_n, ..., a_{2n-1}.
        // For example, take a_n as the median. We need (S1-1)/2 elements before a_n and (S1-1)/2 elements after a_n.
        //
        // Class 2: median a_{n+1}. We can form this class using elements a_2, ..., a_{n+1}, ..., a_{2n}.
        //
        // The crucial observation is that the problem asks for the minimum possible absolute difference.
        // The smallest possible median for any class is $a_1$ (if the class size is 1).
        // The largest possible median for any class is $a_{2n}$ (if the class size is 1).
        //
        // Consider the elements $a_n$ and $a_{n+1}$ from the sorted array.
        // We can always form a class of size $2k+1$ where $a_n$ is the median,
        // by picking $k$ elements from $a_1, \dots, a_{n-1}$ and $k$ elements from $a_{n+1}, \dots, a_{2n}$.
        // Similarly for $a_{n+1}$.
        //
        // The minimum possible difference will be achieved when the two medians are adjacent in the sorted array.
        // Specifically, the minimum difference is achieved by taking $a_n$ and $a_{n+1}$ as the medians.
        //
        // Let's prove this.
        // Suppose we have two classes, C1 and C2, with medians M1 and M2 respectively.
        // Let the sorted array of all students be $a'_1, \dots, a'_{2n}$.
        //
        // M1 must be some $a'_i$ and M2 must be some $a'_j$.
        //
        // For M1 to be the median of C1 (size $S_1 = 2k_1+1$), there must be $k_1$ elements in C1 less than or equal to M1,
        // and $k_1$ elements in C1 greater than or equal to M1.
        // Similarly for M2 (size $S_2 = 2k_2+1$).
        //
        // The total number of elements less than or equal to $a'_n$ is $n$.
        // The total number of elements greater than or equal to $a'_{n+1}$ is $n$.
        //
        // If we choose $M_1 = a'_n$ and $M_2 = a'_{n+1}$:
        // We can form C1 with $a'_n$ as median. For example, take $a'_n$ itself (size 1).
        // We can form C2 with $a'_{n+1}$ as median. For example, take $a'_{n+1}$ itself (size 1).
        // This leaves $2n-2$ students. We can distribute them such that C1 and C2 remain odd sized.
        //
        // More generally, we can construct the classes as follows:
        // Class 1: $a'_1, a'_2, \dots, a'_n$. This class has $n$ elements. If $n$ is odd, $a'_{(n+1)/2}$ is the median.
        // If $n$ is even, this is not a valid class size.
        //
        // The problem states that each class must have an odd number of students.
        // The total number of students is $2n$.
        //
        // Consider the elements $a_n$ and $a_{n+1}$ from the sorted array.
        // We can form a class C1 with $a_n$ as its median.
        // We can form a class C2 with $a_{n+1}$ as its median.
        //
        // For example, let C1 consist of $a_1, a_2, \dots, a_n$. This is $n$ elements.
        // Let C2 consist of $a_{n+1}, a_{n+2}, \dots, a_{2n}$. This is $n$ elements.
        // This partition is only valid if $n$ is odd.
        // If $n$ is odd, then $a_{(n+1)/2}$ is the median of C1, and $a_{n+(n+1)/2}$ is the median of C2.
        // This is not $a_n$ and $a_{n+1}$.
        //
        // The problem is simpler than that.
        // The minimum difference is always achieved by taking $a_n$ and $a_{n+1}$ as the medians.
        //
        // Why?
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$ be their sizes.
        // $S_1+S_2 = 2n \implies 2k_1+1 + 2k_2+1 = 2n \implies 2(k_1+k_2+1) = 2n \implies k_1+k_2+1 = n$.
        //
        // For $M_1$ to be the median of $C_1$, there must be $k_1$ elements in $C_1$ less than $M_1$ and $k_1$ elements greater than $M_1$.
        // For $M_2$ to be the median of $C_2$, there must be $k_2$ elements in $C_2$ less than $M_2$ and $k_2$ elements greater than $M_2$.
        //
        // Without loss of generality, assume $M_1 \le M_2$.
        //
        // The $k_1$ elements smaller than $M_1$ must come from $a'_1, \dots, a'_{M_1-1}$.
        // The $k_2$ elements smaller than $M_2$ must come from $a'_1, \dots, a'_{M_2-1}$.
        //
        // The total number of elements less than or equal to $M_1$ in $C_1$ is $k_1+1$.
        // The total number of elements less than or equal to $M_2$ in $C_2$ is $k_2+1$.
        //
        // Consider the $n$ smallest elements $a'_1, \dots, a'_n$.
        // At most $k_1+1$ of these can be in $C_1$ (if $M_1 \le a'_n$).
        // At most $k_2+1$ of these can be in $C_2$ (if $M_2 \le a'_n$).
        //
        // The total number of elements in $C_1$ that are $\le M_1$ is $k_1+1$.
        // The total number of elements in $C_2$ that are $\le M_2$ is $k_2+1$.
        //
        // The total number of elements $\le M_1$ across both classes is at most $k_1+1 + S_2$.
        // The total number of elements $\le M_2$ across both classes is at most $S_1 + k_2+1$.
        //
        // This is a known result for this type of problem.
        // When you have $2n$ items and you need to partition them into two odd-sized groups,
        // the minimum difference between their medians is always $a_{n+1} - a_n$ after sorting.
        //
        // This is because you can always construct such a partition.
        // Let $M_1 = a_n$ and $M_2 = a_{n+1}$.
        // We need to form two classes $C_1$ and $C_2$ such that $M_1$ is the median of $C_1$ and $M_2$ is the median of $C_2$.
        //
        // Let $C_1 = \{a_n\}$. This is a class of size 1, median $a_n$.
        // Let $C_2 = \{a_{n+1}\}$. This is a class of size 1, median $a_{n+1}$.
        //
        // We are left with $2n-2$ students: $a_1, \dots, a_{n-1}$ and $a_{n+2}, \dots, a_{2n}$.
        // We need to distribute these $2n-2$ students into $C_1$ and $C_2$ such that both classes remain odd-sized.
        //
        // We can add $k$ pairs of students $(x, y)$ where $x < M_1$ and $y > M_1$ to $C_1$ to keep $M_1$ as median.
        // We can add $k'$ pairs of students $(x', y')$ where $x' < M_2$ and $y' > M_2$ to $C_2$ to keep $M_2$ as median.
        //
        // The simplest way to see this is that $a_n$ is the $n$-th element and $a_{n+1}$ is the $(n+1)$-th element.
        // If we take $a_n$ as the median of one class and $a_{n+1}$ as the median of the other,
        // we can always construct the classes.
        //
        // For example, let $C_1$ be $\{a_1, a_2, \dots, a_n, a_{n+2}, \dots, a_{2n-1}\}$. This is $n + (n-2) = 2n-2$ elements. This is even. Not allowed.
        //
        // The correct construction is:
        // Class 1: $a_1, a_2, \dots, a_n$. This has $n$ elements.
        // Class 2: $a_{n+1}, a_{n+2}, \dots, a_{2n}$. This has $n$ elements.
        // This partition is only valid if $n$ is odd.
        // If $n$ is odd, median of C1 is $a_{(n+1)/2}$. Median of C2 is $a_{n+(n+1)/2}$.
        // This is not $a_n$ and $a_{n+1}$.
        //
        // The problem is simpler: the minimum difference is always $a_{n+1} - a_n$.
        // This is because $a_n$ is the largest possible median for a class that contains only elements from $a_1, \dots, a_n$.
        // And $a_{n+1}$ is the smallest possible median for a class that contains only elements from $a_{n+1}, \dots, a_{2n}$.
        //
        // Let's consider the elements $a_1, \dots, a_n$ and $a_{n+1}, \dots, a_{2n}$.
        //
        // We can form Class 1 with $a_n$ as its median.
        // We can form Class 2 with $a_{n+1}$ as its median.
        //
        // To make $a_n$ the median of $C_1$:
        // We need $k_1$ elements smaller than $a_n$ and $k_1$ elements larger than $a_n$.
        // We can pick $a_1, \dots, a_{n-1}$ (these are $n-1$ elements) as candidates for smaller elements.
        // We can pick $a_{n+1}, \dots, a_{2n}$ (these are $n$ elements) as candidates for larger elements.
        //
        // To make $a_{n+1}$ the median of $C_2$:
        // We need $k_2$ elements smaller than $a_{n+1}$ and $k_2$ elements larger than $a_{n+1}$.
        // We can pick $a_1, \dots, a_n$ (these are $n$ elements) as candidates for smaller elements.
        // We can pick $a_{n+2}, \dots, a_{2n}$ (these are $n-1$ elements) as candidates for larger elements.
        //
        // The crucial part is that we can always construct a valid partition where $a_n$ and $a_{n+1}$ are the medians.
        //
        // Consider the partition:
        // Class 1: $\{a_1, a_2, \dots, a_n\}$
        // Class 2: $\{a_{n+1}, a_{n+2}, \dots, a_{2n}\}$
        // This partition is only valid if $n$ is odd.
        // If $n$ is odd, median of C1 is $a_{(n+1)/2}$. Median of C2 is $a_{n+(n+1)/2}$.
        // This is not $a_n$ and $a_{n+1}$.
        //
        // The problem is simpler. The minimum difference is always $a_{n+1} - a_n$.
        // This is because $a_n$ is the largest possible median for a class that contains only elements from $a_1, \dots, a_n$.
        // And $a_{n+1}$ is the smallest possible median for a class that contains only elements from $a_{n+1}, \dots, a_{2n}$.
        //
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // $M_1$ must be some $a_i$ and $M_2$ must be some $a_j$.
        //
        // The total number of elements is $2n$.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        // $k_1+k_2+1 = n$.
        //
        // The elements $a_1, \dots, a_n$ are the first $n$ elements.
        // The elements $a_{n+1}, \dots, a_{2n}$ are the last $n$ elements.
        //
        // Consider the $n$ elements $a_1, \dots, a_n$.
        // At most $k_1+1$ of these can be in $C_1$ if $M_1 \le a_n$.
        // At most $k_2+1$ of these can be in $C_2$ if $M_2 \le a_n$.
        //
        // The total number of elements less than or equal to $a_n$ is $n$.
        // The total number of elements greater than or equal to $a_{n+1}$ is $n$.
        //
        // If $M_1$ is the median of $C_1$, then $C_1$ has $k_1$ elements $\le M_1$ and $k_1$ elements $\ge M_1$.
        // If $M_2$ is the median of $C_2$, then $C_2$ has $k_2$ elements $\le M_2$ and $k_2$ elements $\ge M_2$.
        //
        // Suppose $M_1 < a_n$. Then $M_1$ is one of $a_1, \dots, a_{n-1}$.
        // Suppose $M_2 > a_{n+1}$. Then $M_2$ is one of $a_{n+2}, \dots, a_{2n}$.
        //
        // If we choose $M_1 = a_n$ and $M_2 = a_{n+1}$, we can always construct the classes.
        //
        // Let $C_1 = \{a_1, \dots, a_{k_1}, a_n, a_{n+2}, \dots, a_{n+1+k_1}\}$.
        // This is not general enough.
        //
        // The simplest argument is that $a_n$ is the largest possible median for a class whose elements are all $\le a_n$.
        // And $a_{n+1}$ is the smallest possible median for a class whose elements are all $\ge a_{n+1}$.
        //
        // The problem is that the elements can be mixed.
        //
        // The key is that the $n$-th element $a_n$ and the $(n+1)$-th element $a_{n+1}$ are the "split point" of the sorted array.
        //
        // Consider the $n$ smallest elements $a_1, \dots, a_n$.
        // Consider the $n$ largest elements $a_{n+1}, \dots, a_{2n}$.
        //
        // We can form a class $C_1$ with median $a_n$.
        // We can form a class $C_2$ with median $a_{n+1}$.
        //
        // For $C_1$ to have median $a_n$, it must contain $a_n$, $k_1$ elements $\le a_n$ (excluding $a_n$), and $k_1$ elements $\ge a_n$ (excluding $a_n$).
        // For $C_2$ to have median $a_{n+1}$, it must contain $a_{n+1}$, $k_2$ elements $\le a_{n+1}$ (excluding $a_{n+1}$), and $k_2$ elements $\ge a_{n+1}$ (excluding $a_{n+1}$).
        //
        // We have $n-1$ elements $a_1, \dots, a_{n-1}$ that are strictly less than $a_n$.
        // We have $n-1$ elements $a_{n+2}, \dots, a_{2n}$ that are strictly greater than $a_{n+1}$.
        //
        // We can assign $a_n$ to $C_1$ and $a_{n+1}$ to $C_2$.
        // We need to distribute the remaining $2n-2$ elements.
        //
        // Let $k_1 = 0, k_2 = n-1$.
        // $C_1 = \{a_n\}$. Median is $a_n$. Size 1 (odd).
        // $C_2 = \{a_1, \dots, a_{n-1}, a_{n+1}, a_{n+2}, \dots, a_{2n}\}$.
        // This class $C_2$ has size $(n-1) + 1 + (n-1) = 2n-1$ (odd).
        // The elements of $C_2$ are $a_1, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n}$.
        // Sorted, these are $a_1, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n}$.
        // The median of $C_2$ (size $2n-1$) is the $n$-th element.
        // The $n$-th element in the sorted list of $C_2$ is $a_{n+1}$.
        // So, this partition is valid.
        // The medians are $a_n$ and $a_{n+1}$.
        // The difference is $|a_{n+1} - a_n|$.
        //
        // Can we achieve a smaller difference?
        // Suppose we have medians $M_1$ and $M_2$ such that $|M_1 - M_2| < |a_{n+1} - a_n|$.
        // This implies $M_1$ and $M_2$ must be "closer" than $a_n$ and $a_{n+1}$.
        //
        // If $M_1$ and $M_2$ are both $\le a_n$, then all elements of $C_1$ and $C_2$ are $\le a_n$.
        // But we only have $n$ such elements.
        // $C_1$ needs $k_1+1$ elements $\le M_1$. $C_2$ needs $k_2+1$ elements $\le M_2$.
        // Total elements needed $\le \max(M_1, M_2)$ is $(k_1+1) + (k_2+1) = k_1+k_2+2 = n+1$.
        // This is a contradiction, as we only have $n$ elements $a_1, \dots, a_n$.
        // So, it's impossible for both medians to be $\le a_n$.
        //
        // Similarly, it's impossible for both medians to be $\ge a_{n+1}$.
        //
        // Therefore, one median must be $\le a_n$ and the other must be $\ge a_{n+1}$.
        // Let $M_1 \le a_n$ and $M_2 \ge a_{n+1}$.
        // Then $|M_1 - M_2| = M_2 - M_1 \ge a_{n+1} - a_n$.
        //
        // So the minimum possible difference is indeed $a_{n+1} - a_n$.
        //
        // The indices are 0-based in C++ vectors.
        // So $a_n$ is `a[n-1]` and $a_{n+1}$ is `a[n]`.
        // The difference is `a[n] - a[n-1]`.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
