void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak"; // Box 1: (-inf, -1]
    std::string ans2 = "Tidak"; // Box 2: (-1, 0)
    std::string ans3 = "Tidak"; // Box 3: (0, 1)
    std::string ans4 = "Tidak"; // Box 4: [1, inf)

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    } else {
        // Case 1: Final product is positive
        // This happens if the total count of initial negative numbers (A+B) is even.
        // Let's consider the parity of A+B.
        // If A+B is even:
        //   - If there's at least one toy in Box 3 or Box 4 (C+D > 0),
        //     we can potentially make the magnitude > 1 or < 1.
        //   - If all toys are in Box 1 or Box 2 (C+D == 0), then A+B must be even.
        //     If A > 0, we can make magnitude > 1. If A == 0, then B must be even and > 0,
        //     we can make magnitude < 1.

        // Can be positive and magnitude >= 1 (Box 4)
        // Condition for positive: (A+B) is even.
        // Condition for magnitude >= 1:
        //   - At least one toy in Box 1 (A > 0)
        //   - At least one toy in Box 4 (D > 0)
        //   - Or, if A=0, D=0, then all toys are in B and C.
        //     If B=0, C=0, then A=0, D=0, impossible (total_toys > 0).
        //     If B=0, C>0, then (A+B) is even (0). C>0.
        //       If C=1, total_toys=1, handled.
        //       If C>1, we can make magnitude < 1.
        //     If B>0, C=0, then (A+B) is even (B is even). B>0.
        //       We can make magnitude < 1.
        //     If B>0, C>0, then (A+B) is even (B is even).
        //       We can make magnitude < 1.
        // So, for magnitude >= 1, we need A > 0 or D > 0.
        // If (A+B) is even AND (A > 0 OR D > 0), then Box 4 is possible.
        if ((A + B) % 2 == 0 && (A > 0 || D > 0)) {
            ans4 = "Ya";
        }

        // Can be positive and magnitude < 1 (Box 3)
        // Condition for positive: (A+B) is even.
        // Condition for magnitude < 1:
        //   - At least one toy in Box 2 (B > 0)
        //   - At least one toy in Box 3 (C > 0)
        //   - Or, if B=0, C=0, then all toys are in A and D.
        //     If A=0, D=0, impossible.
        //     If A=0, D>0, then (A+B) is even (0). D>0.
        //       If D=1, total_toys=1, handled.
        //       If D>1, we can make magnitude >= 1.
        //     If A>0, D=0, then (A+B) is even (A is even). A>0.
        //       We can make magnitude >= 1.
        //     If A>0, D>0, then (A+B) is even.
        //       We can make magnitude >= 1.
        // So, for magnitude < 1, we need B > 0 or C > 0.
        // If (A+B) is even AND (B > 0 OR C > 0), then Box 3 is possible.
        if ((A + B) % 2 == 0 && (B > 0 || C > 0)) {
            ans3 = "Ya";
        }

        // Case 2: Final product is negative
        // This happens if the total count of initial negative numbers (A+B) is odd.
        // If (A+B) is odd:
        //   - If there's at least one toy in Box 1 or Box 4 (A+D > 0),
        //     we can potentially make the magnitude > 1.
        //   - If there's at least one toy in Box 2 or Box 3 (B+C > 0),
        //     we can potentially make the magnitude < 1.
        //   - If all toys are in Box 1 or Box 2 (C+D == 0), then A+B must be odd.
        //     If A > 0, we can make magnitude > 1. If A == 0, then B must be odd and > 0,
        //     we can make magnitude < 1.
        //   - If all toys are in Box 3 or Box 4 (A+B == 0), then A+B must be odd, impossible.
        //     So, if A+B is odd, there must be at least one toy in Box 1 or Box 2.

        // Can be negative and magnitude >= 1 (Box 1)
        // Condition for negative: (A+B) is odd.
        // Condition for magnitude >= 1:
        //   - At least one toy in Box 1 (A > 0)
        //   - At least one toy in Box 4 (D > 0)
        // If (A+B) is odd AND (A > 0 OR D > 0), then Box 1 is possible.
        if ((A + B) % 2 == 1 && (A > 0 || D > 0)) {
            ans1 = "Ya";
        }

        // Can be negative and magnitude < 1 (Box 2)
        // Condition for negative: (A+B) is odd.
        // Condition for magnitude < 1:
        //   - At least one toy in Box 2 (B > 0)
        //   - At least one toy in Box 3 (C > 0)
        // If (A+B) is odd AND (B > 0 OR C > 0), then Box 2 is possible.
        if ((A + B) % 2 == 1 && (B > 0 || C > 0)) {
            ans2 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

