#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_req: minimum possible value for a[i] if it's part of an increasing sequence starting from 0.
    // a[0] >= 0, a[1] >= 1, a[2] >= 2, ...
    // So, a[i] must be at least i.
    std::vector<long long> prefix_min_req(n);
    for (int i = 0; i < n; ++i) {
        prefix_min_req[i] = i;
    }

    // Calculate suffix_min_req: minimum possible value for a[i] if it's part of a decreasing sequence ending at 0.
    // ..., a[n-3] >= 2, a[n-2] >= 1, a[n-1] >= 0.
    // So, a[i] must be at least (n-1-i).
    std::vector<long long> suffix_min_req(n);
    for (int i = 0; i < n; ++i) {
        suffix_min_req[i] = (n - 1 - i);
    }

    // Check if there exists a peak k (0-indexed) such that:
    // 1. a[i] >= prefix_min_req[i] for all i <= k
    // 2. a[i] >= suffix_min_req[i] for all i >= k
    // This implicitly covers a[k] >= k and a[k] >= (n-1-k).
    // The strict inequalities a_i < a_{i+1} and a_i > a_{i+1} are satisfied by the minimal construction.
    // For example, if a_i >= i and a_{i+1} >= i+1, we can always choose values x, y such that x < y, x <= a_i, y <= a_{i+1}.
    // The smallest possible values are 0, 1, 2, ..., k-1, k, k-1, ..., 1, 0.
    // So we need a[i] >= i for i <= k and a[i] >= (n-1-i) for i >= k.
    // The peak element a[k] must satisfy a[k] >= k AND a[k] >= (n-1-k).
    // This is equivalent to a[k] >= max(k, n-1-k).
    // The condition for a sharpened array is that there exists a k such that
    // a_0 < a_1 < ... < a_k and a_k > a_{k+1} > ... > a_{n-1}.
    // This means we need to be able to make a_i = i for i <= k and a_i = n-1-i for i >= k.
    // So, for each i, we need a[i] >= i if i <= k, and a[i] >= n-1-i if i >= k.
    // This is equivalent to checking if a[i] >= i for the increasing part and a[i] >= (n-1-i) for the decreasing part.
    // The peak element a[k] must satisfy both conditions.
    // So, for a given k, we need to check if a[i] >= i for 0 <= i <= k AND a[i] >= (n-1-i) for k <= i < n.
    // This is equivalent to checking if a[i] >= i for 0 <= i < n AND a[i] >= (n-1-i) for 0 <= i < n.
    // No, this is not correct. The conditions are for *different* parts of the array.
    // For a chosen k, we need:
    // For 0 <= i <= k: a[i] >= i
    // For k <= i < n: a[i] >= (n-1-i)
    // The element a[k] must satisfy both: a[k] >= k AND a[k] >= (n-1-k).
    // This is the condition for a valid peak.

    // We can find the maximum possible 'left_reach' and 'right_reach'.
    // left_reach[i] = true if a[0]...a[i] can form an increasing sequence 0, 1, ..., i.
    // right_reach[i] = true if a[i]...a[n-1] can form a decreasing sequence i-(n-1), ..., 1, 0.
    // (i.e., a[i] >= n-1-i, a[i+1] >= n-1-(i+1), ..., a[n-1] >= 0)

    std::vector<bool> can_reach_from_left(n);
    can_reach_from_left[0] = (a[0] >= 0);
    for (int i = 1; i < n; ++i) {
        can_reach_from_left[i] = (can_reach_from_left[i-1] && a[i] >= i);
    }

    std::vector<bool> can_reach_from_right(n);
    can_reach_from_right[n-1] = (a[n-1] >= 0);
    for (int i = n - 2; i >= 0; --i) {
        can_reach_from_right[i] = (can_reach_from_right[i+1] && a[i] >= (n - 1 - i));
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (can_reach_from_left[k] && can_reach_from_right[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

