int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (from sorted 'a')
    int right_ptr = 0; // Pointer for positions in the original sorted array 'a'

    while (right_ptr < n) {
        // We are trying to find an element a[left_ptr]
        // to place at position right_ptr such that a[left_ptr] > a[right_ptr].
        // Since both arrays are sorted, if a[left_ptr] > a[right_ptr],
        // then a[left_ptr+1], a[left_ptr+2], ... will also be > a[right_ptr].
        // To maximize matches, we should use the smallest possible a[left_ptr]
        // that satisfies the condition.
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[left_ptr] is not greater than a[right_ptr],
            // we cannot use a[left_ptr] for this position (right_ptr).
            // We must try a larger element for a[left_ptr].
            // So, we advance left_ptr.
            left_ptr++;
        }
        // Ensure left_ptr does not exceed array bounds
        // If left_ptr reaches n, it means we have exhausted all available elements
        // to place, so we can stop.
        if (left_ptr == n) {
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

