// Function to check if a prefix of length `len` is a permutation
bool is_permutation_prefix(const std::vector<int>& a, int len, const std::vector<int>& max_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_prefix[len - 1] != len) return false; // Max element must be equal to length

    // Check for distinctness using frequency array
    // This check is already precomputed in `is_prefix_distinct`
    // We just need to ensure that the count of each number from 1 to len is 1.
    // The `is_prefix_distinct` array already tells us if all numbers up to `len` are distinct.
    // The `max_prefix` array tells us if the max element is `len`.
    // Together, these two conditions are sufficient.
    // If max_prefix[len-1] == len, it means all numbers from 1 to len are present
    // and no number greater than len is present.
    // If is_prefix_distinct[len-1] is true, it means all numbers in the prefix are distinct.
    // Combining these, if max_prefix[len-1] == len AND is_prefix_distinct[len-1] is true,
    // then it must be a permutation of length len.
    return true;
}

// Function to check if a suffix of length `len` is a permutation
bool is_permutation_suffix(const std::vector<int>& a, int start_idx, int len, const std::vector<int>& max_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_suffix[start_idx] != len) return false; // Max element must be equal to length

    // Similar logic as prefix, using precomputed `is_suffix_distinct`
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> freq_prefix(n + 1, 0);
    std::vector<bool> is_prefix_distinct(n, false);
    std::vector<int> max_prefix(n, 0);
    int current_max = 0;
    bool distinct_so_far = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || freq_prefix[a[i]] > 0) {
            distinct_so_far = false;
        }
        freq_prefix[a[i]]++;
        current_max = std::max(current_max, a[i]);
        is_prefix_distinct[i] = distinct_so_far;
        max_prefix[i] = current_max;
    }

    // Precompute for suffixes
    std::vector<int> freq_suffix(n + 1, 0);
    std::vector<bool> is_suffix_distinct(n, false);
    std::vector<int> max_suffix(n, 0);
    current_max = 0;
    distinct_so_far = true;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || freq_suffix[a[i]] > 0) {
            distinct_so_far = false;
        }
        freq_suffix[a[i]]++;
        current_max = std::max(current_max, a[i]);
        is_suffix_distinct[i] = distinct_so_far;
        max_suffix[i] = current_max;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;

        // Check if prefix a[0...l1-1] is a permutation of length l1
        // Conditions:
        // 1. All elements are distinct (checked by is_prefix_distinct[l1-1])
        // 2. Max element is l1 (checked by max_prefix[l1-1] == l1)
        // 3. All elements are within [1, l1] (implied by 1 and 2)
        bool p1_is_perm = is_prefix_distinct[l1 - 1] && is_permutation_prefix(a, l1, max_prefix);

        // Check if suffix a[l1...n-1] is a permutation of length l2
        // Conditions:
        // 1. All elements are distinct (checked by is_suffix_distinct[l1])
        // 2. Max element is l2 (checked by max_suffix[l1] == l2)
        // 3. All elements are within [1, l2] (implied by 1 and 2)
        bool p2_is_perm = is_suffix_distinct[l1] && is_permutation_suffix(a, l1, l2, max_suffix);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

