    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If the array is already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append elements.
    // Let's try to append two elements.
    // We want S_new = 2 * X_new
    // S_0 + b1 + b2 = 2 * (X_0 ^ b1 ^ b2)
    // A simple strategy is to make X_new equal to X_0.
    // This can be achieved by appending b1 = X_0 and b2 = 0.
    // Then X_new = X_0 ^ X_0 ^ 0 = 0.
    // This would require S_new = 2 * 0 = 0, which is generally not possible if S_0 > 0.

    // A better strategy:
    // Let's append two elements: X_0 and S_0 + X_0.
    // New XOR sum: X_new = X_0 ^ X_0 ^ (S_0 + X_0) = S_0 + X_0.
    // New sum: S_new = S_0 + X_0 + (S_0 + X_0) = 2 * (S_0 + X_0).
    // This satisfies S_new = 2 * X_new.
    // The elements to append are X_0 and S_0 + X_0.
    // Note that S_0 + X_0 can be large, up to 10^5 * 10^9 + 10^9 approx 10^14.
    // This fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

