int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long N;
        std::cin >> N;
        long long chanek_coins = 0;
        long long opponent_coins = 0;
        bool chanek_turn = true;

        while (N > 0) {
            if (N % 2 != 0) { // N is odd
                if (chanek_turn) {
                    chanek_coins += 1;
                } else {
                    opponent_coins += 1;
                }
                N -= 1;
            } else { // N is even
                if (N == 2) { // Special case for N=2, always take 1
                    if (chanek_turn) {
                        chanek_coins += 1;
                    } else {
                        opponent_coins += 1;
                    }
                    N -= 1;
                } else if ((N / 2) % 2 != 0) { // N/2 is odd
                    // If N/2 is odd, taking N/2 leaves an odd number.
                    // Taking 1 leaves an odd number.
                    // Taking N/2 is better for current player if they want more coins.
                    // Taking 1 is better for current player if they want to leave an even number for opponent.
                    // Since N/2 is odd, taking N/2 leaves N/2 coins.
                    // Taking 1 leaves N-1 coins, which is odd.
                    // If current player takes N/2, they get N/2 coins. Next player faces N/2 (odd).
                    // If current player takes 1, they get 1 coin. Next player faces N-1 (odd).
                    // Since N/2 is odd, the next player will take 1.
                    // So, if current player takes N/2, they get N/2. Next player gets 1.
                    // If current player takes 1, they get 1. Next player gets 1.
                    // N/2 is always greater than 1 for N > 2.
                    // So, current player takes N/2.
                    if (chanek_turn) {
                        chanek_coins += N / 2;
                    } else {
                        opponent_coins += N / 2;
                    }
                    N /= 2;
                } else { // N/2 is even
                    // If N/2 is even, taking N/2 leaves an even number.
                    // Taking 1 leaves an odd number.
                    // Current player wants to maximize their coins.
                    // If current player takes N/2, they get N/2. Next player faces N/2 (even).
                    // If current player takes 1, they get 1. Next player faces N-1 (odd).
                    // Since N/2 is even, the next player might take N/4.
                    // Since N-1 is odd, the next player will take 1.
                    // This is the tricky part.
                    // If N/2 is even, it's always optimal to take N/2.
                    // The current player gets N/2. The opponent then faces N/2, which is even.
                    // The opponent will then take N/4, and so on.
                    // This strategy ensures the current player gets a large chunk.
                    // If the current player takes 1, they get 1. The opponent faces N-1 (odd).
                    // The opponent takes 1.
                    // N/2 is always greater than 1 for N > 2.
                    // So, current player takes N/2.
                    if (chanek_turn) {
                        chanek_coins += N / 2;
                    } else {
                        opponent_coins += N / 2;
                    }
                    N /= 2;
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_coins << "\n";
    }
    return 0;
}

