int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    for (int k = 0; k <= n; ++k) { // k is the number of items taken from the left
        // Items taken from left: w_1, ..., w_k
        // Items taken from right: w_{k+1}, ..., w_n
        // Number of items from left: k
        // Number of items from right: n - k

        long long current_energy = 0;

        // Energy for items taken from left
        current_energy += prefix_sum[k] * l;

        // Energy for items taken from right
        current_energy += (prefix_sum[n] - prefix_sum[k]) * r;

        // Add penalties
        int diff = k - (n - k); // k - (n-k) = 2k - n
        if (diff > 0) { // More items from left than right
            current_energy += (long long)(diff - 1) * Ql;
        } else if (diff < 0) { // More items from right than left
            current_energy += (long long)(-diff - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s[i] is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // This is a definite constraint.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // For each s[i], check if it matches the rule based on our candidate w.
    for (int i = 0; i < n; ++i) {
        bool s_i_should_be_1 = false;
        if (i - x >= 0 && w[i - x] == '1') {
            s_i_should_be_1 = true;
        }
        if (i + x < n && w[i + x] == '1') {
            s_i_should_be_1 = true;
        }

        if ((s[i] == '1' && !s_i_should_be_1) || (s[i] == '0' && s_i_should_be_1)) {
            // Mismatch found:
            // If s[i] is '1' but our w implies s[i] should be '0', then no such w exists.
            // (Because we initialized w[j] to '1' unless forced to '0',
            // if s[i] is '1' and we can't make it '1', it's impossible.)
            // If s[i] is '0' but our w implies s[i] should be '1', then our w is wrong.
            // (This case should not happen if our logic for setting w[j] to '0' is correct,
            // as s[i]=='0' implies w[i-x] and w[i+x] are '0', which would make s_i_should_be_1 false.)
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

