#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 digits long
    // The problem statement says "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // And "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should always consider 18 digits.
    // The pattern string we generate is effectively reversed (rightmost digit first).
    // So we pad with '0's at the end of our string to represent leading '0's in the number.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each 18-digit parity pattern string
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern with '0's to make it 18 digits long
            // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means the pattern string should be padded with '0's at the beginning.
            // Since our internal representation for numbers is right-to-left,
            // padding the pattern from the left means appending '0's to our string representation.
            while (s.length() < 18) {
                s = '0' + s; // Pad from left for the original pattern string
            }
            // Now, reverse the pattern string to match our internal representation (rightmost digit first)
            std::reverse(s.begin(), s.end());

            // The map stores counts for 18-digit patterns.
            // If a pattern is not found, its count is 0 by default.
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    std::vector<long long> prime_factors_q;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    long long max_x = 1;

    for (long long pf : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= pf;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

