int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[0][i] stores count of 'x' up to index i-1
    // prefix_counts[1][i] stores count of 'y' up to index i-1
    // prefix_counts[2][i] stores count of 'z' up to index i-1
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[0][i + 1] = prefix_counts[0][i];
        prefix_counts[1][i + 1] = prefix_counts[1][i];
        prefix_counts[2][i + 1] = prefix_counts[2][i];
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        // The algorithm terminates if and only if it's possible to reach a state
        // where all 3-character substrings are permutations of 'x', 'y', 'z'
        // AND specifically one of "zyx", "xzy", "yxz".
        // This implies that the counts of 'x', 'y', 'z' in the substring
        // must be "balanced" enough such that they can form such permutations.
        // Specifically, the counts must differ by at most 1.
        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_x - count_z) <= 1 &&
            std::abs(count_y - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

