    std::cin >> a >> b;
    long long MOD = 1000000007;

    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;

    // To divide by 2, multiply by modular inverse of 2.
    // MOD is 10^9 + 7, which is prime.
    // Modular inverse of 2 is (MOD + 1) / 2 = (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004;
    sum_r_term = (sum_r_term * inv2) % MOD;

    long long sum_k_term = (a * (a + 1) / 2) % MOD; // Sum of k from 1 to a

    long long term1 = (sum_k_term * b) % MOD; // sum(k*b)
    long long term2 = a % MOD;                // sum(1)

    long long sum_kb_plus_1 = (term1 + term2) % MOD;

    long long total_sum = (sum_r_term * sum_kb_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

