void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int k = 0; k <= 9; ++k) {
        std::string coloring(n, ' ');
        std::vector<char> s1_digits;
        std::vector<char> s2_digits;
        bool possible_k = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit - '0' < k) {
                coloring[i] = '1';
                s1_digits.push_back(digit);
            } else if (digit - '0' > k) {
                coloring[i] = '2';
                s2_digits.push_back(digit);
            } else { // digit - '0' == k
                // This is the tricky part. Digits equal to k can go to either S1 or S2.
                // To maintain non-decreasing order, if we put k into S1, it must be >= last S1 digit.
                // If we put k into S2, it must be >= last S1 digit (if S1 is not empty) and >= last S2 digit.
                // The strategy is to put all 'k's that appear before the first 'k' that is forced into S2 into S1.
                // And all 'k's that appear after or at the first 'k' forced into S2, into S2.
                // The first 'k' that is forced into S2 is the one that appears after some digit > k has already been assigned to S2.
                // Or, more simply, we can find the first occurrence of 'k' that we *must* assign to color 2.
                // This happens if a digit 'k' appears after a digit 'k' that was already assigned to color 2.
                // Or, if a digit 'k' appears after a digit 'k' that was assigned to color 1, and then a digit 'k' appears after that,
                // and we need to assign it to color 2.
                // Let's try a simpler greedy approach for digits equal to k:
                // Assign '1' if possible, otherwise '2'.
                // 'Possible' means it doesn't violate s1_digits non-decreasing property.
                // If s1_digits is empty or digit >= s1_digits.back(), assign to '1'.
                // Otherwise, assign to '2'.
                // This greedy choice for 'k's is what makes the solution work.
                if (s1_digits.empty() || digit >= s1_digits.back()) {
                    coloring[i] = '1';
                    s1_digits.push_back(digit);
                } else {
                    coloring[i] = '2';
                    s2_digits.push_back(digit);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i-1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i-1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if last S1 digit <= first S2 digit
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_k = false;
            }
        }

        if (possible_k) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> present_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s[s[i] - 'a'] = true;
        if (i + 1 < s.length()) {
            adj[s[i] - 'a'].insert(s[i+1]);
            adj[s[i+1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            if (adj[i].size() == 1 || adj[i].empty()) { // Start of a path or isolated character
                char current_char = (char)('a' + i);
                while (true) {
                    if (visited[current_char - 'a']) { // Cycle detected or already part of another path
                        std::cout << "NO\n";
                        return;
                    }
                    visited[current_char - 'a'] = true;
                    layout += current_char;

                    char next_char = '\0';
                    for (char neighbor : adj[current_char - 'a']) {
                        if (!visited[neighbor - 'a']) {
                            next_char = neighbor;
                            break;
                        }
                    }

                    if (next_char == '\0') { // End of path
                        break;
                    }
                    current_char = next_char;
                }
            }
        }
    }

    if (layout.length() != std::count(present_in_s.begin(), present_in_s.end(), true)) {
        // This means there was a character in `s` that was part of a cycle or a path that wasn't started from an endpoint.
        // This case is covered by adj[i].size() > 2 check for cycles, but for paths, it means we didn't start from an endpoint.
        // However, if adj[i].size() <= 2 for all, and it's a path, it must have endpoints.
        // The only way this can happen is if there's a character in `s` that has degree 2 and is part of a path,
        // but we didn't start from an endpoint. This implies a cycle, which is caught by adj[i].size() > 2.
        // Or, if it's a path, it must have endpoints (degree 1).
        // If all characters in `s` have degree 2, it implies a cycle.
        // The only way this check would fail is if there's a cycle of characters from `s`.
        // For example, if s = "abac", a-b, b-a, a-c. a has degree 3. This is caught.
        // If s = "aba", a-b, b-a. a has degree 1, b has degree 2. This is fine.
        // If s = "abcba", a-b, b-c, c-b, b-a. a has degree 1, c has degree 1, b has degree 2. This is fine.
        // The only way this check would fail is if there's a cycle of characters from `s` where all nodes have degree 2.
        // E.g., s = "abcbca". a-b, b-c, c-b, b-c, c-a.
        // a: {b,c}, b: {a,c}, c: {a,b}. All have degree 2.
        // If we start from 'a', we go a-b-c-a. Then 'a' is visited again.
        // The `if (visited[current_char - 'a'])` check inside the loop handles this.
        // So, if we reach here, it means all characters in `s` were successfully added to `layout` as part of paths.
    }

    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
