#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;
    long long second_min_a = elements[1].value;
    long long second_max_a = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // No elements are in different subsequences, so f(a_i, a_j) = a_i + a_j for all pairs.
    // min_f = min_a + second_min_a
    // max_f = max_a + second_max_a
    // goodness = (max_a + second_max_a) - (min_a + second_min_a)
    long long goodness1 = (max_a + second_max_a) - (min_a + second_min_a);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in each subsequence.
    // This means there will be pairs (a_i, a_j) where a_i and a_j are in different subsequences.
    // For such pairs, f(a_i, a_j) = a_i + a_j + h.
    // The minimum possible value for f is min_a + second_min_a.
    // The maximum possible value for f is max_a + second_max_a + h.
    //
    // Consider the partition where elements[0] is in one subsequence (e.g., 1)
    // and elements[n-1] is in the other subsequence (e.g., 2).
    // All other elements can be in either subsequence.
    //
    // Let's try to put elements[0] in subseq 1 and elements[n-1] in subseq 2.
    // All other elements (elements[1] to elements[n-2]) can be put in subseq 1.
    //
    // Minimum f value:
    //   - If elements[0] and elements[1] are in the same subseq (1): elements[0].value + elements[1].value
    //   - If elements[0] and elements[n-1] are in different subseqs (1 and 2): elements[0].value + elements[n-1].value + h
    //   - If elements[1] and elements[n-1] are in different subseqs (1 and 2): elements[1].value + elements[n-1].value + h
    // The minimum f value will be min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h).
    //
    // Maximum f value:
    //   - If elements[n-2] and elements[n-1] are in the same subseq (2): elements[n-2].value + elements[n-1].value
    //   - If elements[0] and elements[n-1] are in different subseqs (1 and 2): elements[0].value + elements[n-1].value + h
    //   - If elements[0] and elements[n-2] are in different subseqs (1 and 2): elements[0].value + elements[n-2].value + h
    // The maximum f value will be max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h).
    //
    // This is getting complicated. Let's simplify.
    //
    // The minimum possible sum of two elements is `min_a + second_min_a`.
    // The maximum possible sum of two elements is `max_a + second_max_a`.
    //
    // If there are elements in both subsequences, then `min_f` can be `min_a + second_min_a` (if they are in the same subseq)
    // or `min_a + some_other_element + h` (if they are in different subseqs).
    // The smallest possible `a_i + a_j + h` is `min_a + min_a_in_other_subseq + h`.
    //
    // The overall minimum `f` value will be `min(min_a + second_min_a, min_a + max_a + h)` if `min_a` and `max_a` are in different subsequences.
    // The overall maximum `f` value will be `max(max_a + second_max_a, min_a + max_a + h)` if `min_a` and `max_a` are in different subsequences.
    //
    // Let's consider a specific partition:
    // Put elements[0] in subsequence 1.
    // Put elements[n-1] in subsequence 2.
    // Put all other elements (elements[1] to elements[n-2]) in subsequence 1.
    //
    // Subsequence 1: {elements[0], elements[1], ..., elements[n-2]}
    // Subsequence 2: {elements[n-1]}
    //
    // Values of f:
    // 1. Pairs within subsequence 1: `a_i + a_j` where `i, j < n-1`.
    //    Min: `elements[0].value + elements[1].value`
    //    Max: `elements[n-2].value + elements[n-3].value` (if n-2 >= 1, i.e., n >= 3)
    //         If n=2, this subseq has only elements[0], so no pairs.
    // 2. Pairs within subsequence 2: `a_i + a_j` where `i, j = n-1`.
    //    No pairs possible as only one element.
    // 3. Pairs across subsequences: `a_i + a_j + h` where `a_i` is from subseq 1 and `a_j` is from subseq 2.
    //    This means `a_i` is one of `elements[0], ..., elements[n-2]` and `a_j` is `elements[n-1]`.
    //    Min: `elements[0].value + elements[n-1].value + h`
    //    Max: `elements[n-2].value + elements[n-1].value + h`
    //
    // Overall min_f for this partition:
    // `min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h)`
    // (The `elements[0].value + elements[1].value` term only exists if n >= 3. If n=2, it's just `elements[0].value + elements[1].value + h`)
    //
    // Overall max_f for this partition:
    // `max(elements[n-2].value + elements[n-3].value, elements[n-2].value + elements[n-1].value + h)`
    // (The `elements[n-2].value + elements[n-3].value` term only exists if n >= 3. If n=2, it's just `elements[0].value + elements[1].value + h`)
    //
    // Let's be precise for n=2:
    // Subseq 1: {elements[0]}, Subseq 2: {elements[1]}
    // Only one pair: (elements[0], elements[1]), they are in different subseqs.
    // f = elements[0].value + elements[1].value + h.
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    //
    // For n >= 3:
    // min_f = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
    // max_f = std::max(elements[n-2].value + elements[n-3].value, elements[n-2].value + elements[n-1].value + h);
    //
    // This is the "greedy" partition where we try to keep the range of values in one subseq small.
    //
    // Let's consider the values:
    // A = min_a + second_min_a
    // B = max_a + second_max_a
    // C = min_a + max_a + h
    //
    // If we put all elements in one subsequence, min_f = A, max_f = B. Goodness = B - A.
    //
    // If we put min_a in subseq 1, max_a in subseq 2, and all others in subseq 1:
    // Subseq 1: {a_0, a_1, ..., a_{n-2}}
    // Subseq 2: {a_{n-1}}
    //
    // min_f = min(a_0 + a_1, a_0 + a_{n-1} + h)
    // max_f = max(a_{n-2} + a_{n-3}, a_{n-2} + a_{n-1} + h)
    //
    // This is the partition we need to check.
    //
    // Let's calculate the goodness for this specific partition.
    long long current_min_f, current_max_f;
    if (n == 2) {
        current_min_f = elements[0].value + elements[1].value + h;
        current_max_f = elements[0].value + elements[1].value + h;
    } else {
        current_min_f = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
        current_max_f = std::max(elements[n-2].value + elements[n-3].value, elements[n-2].value + elements[n-1].value + h);
    }
    long long goodness2 = current_max_f - current_min_f;
    std::vector<int> partition2(n);
    for (int i = 0; i < n - 1; ++i) {
        partition2[elements[i].original_index] = 1;
    }
    partition2[elements[n-1].original_index] = 2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

