    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem statement guarantees that a solution exists.
        // Reversing the permutation always yields the same fingerprint.
        // If the reversed permutation is different from the original, it's a valid answer.
        // The only case where the reversed permutation is the same as the original
        // is if the permutation is a palindrome (p_i = p_{n-i-1}).
        // The problem statement implies that such palindromic permutations
        // either don't exist for n >= 2, or if they do, there's another simple transformation.
        // However, for any permutation p, its reverse p_rev has the same fingerprint.
        // If p_rev is different from p, it's a valid answer.
        // The problem guarantees a solution exists, and reversing is the simplest.
        // It's highly likely that for n >= 2, a permutation and its reverse are different
        // unless it's a very specific palindromic structure.
        // Even if p is a palindrome, the problem guarantees a solution exists,
        // implying that reversing is either always different or there's another simple trick.
        // The simplest approach is to just reverse and print.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

