void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_val_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_val_idx]) {
            min_val_idx = i;
        }
    }

    long long min_val = a[min_val_idx];
    long long total_spells = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_val_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // until a[i] + X * min_val > k
        // X * min_val <= k - a[i]
        // X <= (k - a[i]) / min_val
        // The number of times we can add is floor((k - a[i]) / min_val)
        total_spells += (k - a[i]) / min_val;
    }

    std::cout << total_spells << std::endl;
}

