        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // Iterate through powers of two from smallest to largest
    // 1, 2, 4, ..., 1024
    for (int current_val = 1; current_val < 2048; current_val *= 2) {
        if (counts[current_val] >= 2) {
            // If we have at least two of current_val, we can merge them
            // and add one to the next power of two.
            // The number of pairs is counts[current_val] / 2.
            // We add this many to counts[current_val * 2].
            counts[current_val * 2] += counts[current_val] / 2;
        }
    }

    if (counts[2048] > 0) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

