#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // If a[i] was 1 or -1, it contributes to has_one/has_minus_one for elements before it.
            // If a[i] was 0, it doesn't affect has_one/has_minus_one.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a '1' to be available from an earlier index.
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a '-1' to be available from an earlier index.
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // Update has_one and has_minus_one for the next iteration (i-1).
        // If a[i] was 1 or -1, it can no longer be used for elements at indices < i.
        // So, we remove its contribution from the available '1's or '-1's.
        // This is implicitly handled by iterating backwards and checking the original a[k] values.
        // The `has_one` and `has_minus_one` flags track if there's *any* 1 or -1 at an index < current_i.
        // When we process index `i`, we need to know if there's a 1 or -1 at `k < i`.
        // So, `has_one` and `has_minus_one` should reflect elements from `0` to `i-1`.
        // When we move from `i` to `i-1`, the element `a[i]` is no longer available for operations on `a[i-1]`.
        // The current `has_one` and `has_minus_one` flags are correct for checking `a[i]`.
        // For the next iteration `i-1`, we need to update these flags to exclude `a[i]`.
        // However, the problem states "choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means the *original* values of a_k are used for operations.
        // The example confirms this: [1, -1, 0] -> [1, -1, -2] by (2,3) twice.
        // Then [1, -1, -2] -> [1, 1, -2] by (1,2) twice.
        // The value of a_1 (which is 1) is used to change a_2.
        // The value of a_2 (which is -1) is used to change a_3.
        // The crucial observation is that `a_k` (original value) is added to `a_j` (current value).
        // So, `has_one` and `has_minus_one` should track if there's *any* 1 or -1 in `a[0...i-1]`.
        // The current logic of updating `has_one` and `has_minus_one` by checking `a[i]` and then moving to `i-1` is correct.
        // If `a[i]` was 1, then for `i-1`, `has_one` might become false if `a[i]` was the last 1.
        // This is exactly what we need.
        if (a[i] == 1) {
            has_one = false; // This 1 is now "behind" us, cannot be used for indices < i.
            // We need to re-scan or maintain counts.
            // A simpler way is to just check if there's any 1 in a[0...i-1].
            // Let's re-evaluate the flags for the prefix a[0...i-1] for the next iteration.
            // This is done by the loop below.
        } else if (a[i] == -1) {
            has_minus_one = false; // This -1 is now "behind" us.
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

