int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_for_i = std::max(max_val_for_i, a[i][j]);
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is 0. If so, it means all a[i][j] for j!=i were 0.
    // This implies p[i] must be 1 (the smallest possible value in a permutation).
    // This happens if n=2 and p={1,2} or p={2,1}.
    // If p[i] is 0, it means max_{j!=i} a[i][j] was 0.
    // In a permutation of 1..n, the smallest value is 1.
    // If p[i] was 1, then for any j where p[j] > 1, a[i][j] = min(p[i], p[j]) = min(1, p[j]) = 1.
    // If p[i] was 1 and p[j] was also 1, this is not possible in a permutation.
    // So if p[i] is 1, all other p[j] must be > 1.
    // If max_val_for_i is 0, it means p[i] must be 1.
    // This logic is only needed if n=2 and p={1,2} or p={2,1}.
    // For n=2, if p={1,2}, a={0,1;1,0}. max_val_for_0 = 1, max_val_for_1 = 1.
    // p_candidate = {1,1}. This is wrong.
    // The problem states values are 1 to n.
    // If max_val_for_i is 0, it means p_i must be 1.
    // This happens if n=2, p={1,2}. Then a[0][1]=1, a[1][0]=1.
    // max_val_for_0 = a[0][1] = 1. p[0]=1.
    // max_val_for_1 = a[1][0] = 1. p[1]=1.
    // This is not a permutation.
    // The logic is: if max_{j!=i} a[i][j] is less than n, then p[i] is max_{j!=i} a[i][j].
    // If max_{j!=i} a[i][j] is n-1, then p[i] could be n-1 or n.
    // If p[i] is n, then for all j!=i, a[i][j] = min(n, p[j]) = p[j].
    // So max_{j!=i} a[i][j] would be max_{j!=i} p[j].
    // This means if p[i] is n, then max_{j!=i} a[i][j] would be n-1.
    // So if max_{j!=i} a[i][j] is n-1, p[i] could be n.
    // The problem guarantees a solution exists.
    // The maximum value in the permutation is n.
    // For the element p_k that is n, for any j != k, a_{k,j} = min(p_k, p_j) = min(n, p_j) = p_j.
    // So, max_{j!=k} a_{k,j} = max_{j!=k} p_j = n-1.
    // For any other element p_i (where p_i < n), max_{j!=i} a_{i,j} = max(max_{j!=i, p_j<p_i} p_j, max_{j!=i, p_j>=p_i} p_i).
    // This simplifies to max(max_{j!=i, p_j<p_i} p_j, p_i).
    // This is just p_i.
    // So, if p_i < n, then p_i = max_{j!=i} a_{i,j}.
    // If p_i = n, then max_{j!=i} a_{i,j} = n-1.
    // So, we can reconstruct p_i as:
    // if max_{j!=i} a_{i,j} == n-1, then p_i = n.
    // else p_i = max_{j!=i} a_{i,j}.

    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_for_i = std::max(max_val_for_i, a[i][j]);
        }
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

