int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and disables synchronization,
    // which can significantly speed up I/O operations.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a std::vector to store prices.
        // Since n can be up to 150,000, a dynamic array is suitable.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices into the vector
        }

        if (n <= 1) {
            // If there's only one day or no days, no price can be "bad"
            // because there are no later days to compare with.
            std::cout << 0 << "\n";
            continue; // Move to the next test case
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the price of the last day.
        // This variable will store the minimum price encountered
        // from the current position to the end of the array.
        int min_suffix = a[n - 1];

        // Iterate from the second-to-last day backwards to the first day.
        // The last day (a[n-1]) can never be bad as there are no days after it.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                // If the current day's price is greater than the minimum
                // price found in any subsequent day, then this price is "bad".
                bad_prices_count++;
            } else {
                // If the current day's price is not bad, it means it's
                // less than or equal to min_suffix.
                // This price might become the new minimum for days before it.
                min_suffix = a[i];
            }
            // Note: The `else` block above is equivalent to `min_suffix = std::min(min_suffix, a[i]);`
            // because if `a[i] > min_suffix`, `min_suffix` doesn't change,
            // and if `a[i] <= min_suffix`, `min_suffix` becomes `a[i]`.
            // So, `min_suffix = std::min(min_suffix, a[i]);` can be used unconditionally.
            // Let's use the unconditional update for clarity and correctness.
            // min_suffix = std::min(min_suffix, a[i]); // This line would replace the if/else logic for min_suffix update.
            // However, the current if/else is also correct and perhaps slightly more explicit about the logic.
            // The key is that min_suffix should always represent the minimum of a[i+1...n-1] when considering a[i].
            // When we are at index i, min_suffix holds min(a[i+1], ..., a[n-1]).
            // After processing a[i], for the next iteration (i-1), min_suffix should hold min(a[i], a[i+1], ..., a[n-1]).
            // So, min_suffix = std::min(min_suffix, a[i]); is the correct update.
            // Let's re-evaluate the update logic.
            // When we are at index `i`, `min_suffix` holds `min(a[i+1], ..., a[n-1])`.
            // We compare `a[i]` with this `min_suffix`.
            // After this comparison, for the next iteration (index `i-1`), `min_suffix` needs to hold `min(a[i], a[i+1], ..., a[n-1])`.
            // This is exactly `std::min(current_min_suffix, a[i])`.
            min_suffix = std::min(min_suffix, a[i]);
        }

        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' cell or the starting cell 0.
                            // The frog can always jump from 0.
                            // If it lands on an 'R' cell, it can jump right from there.
                            // If it lands on an 'L' cell, it cannot jump right from there.
                            // So, we are interested in the distance between consecutive 'R' cells (or 0)
                            // and the target n+1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i, it means the frog can jump from cell i.
                // The gap we need to cover is from the last 'R' cell (or 0) to this 'R' cell.
                // The distance is (i + 1) - last_R_pos.
                // For example, if last_R_pos = 0 and i = 2, s[2] = 'R'.
                // The cells are 0, 1, 2. The gap is 0 -> 1 -> 2.
                // The distance from 0 to 2 is 2.
                // The jump from 0 must cover cell 1 to reach cell 2.
                // The distance is i - last_R_pos.
                // If last_R_pos = 0, i = 0, s[0] = 'R'. Gap is 0.
                // If last_R_pos = 0, i = 1, s[1] = 'R'. Gap is 1.
                // If last_R_pos = 0, i = 2, s[2] = 'R'. Gap is 2.
                // The required d must be at least (i - last_R_pos) + 1 to jump over all cells between last_R_pos and i.
                // No, this is simpler. The frog is at last_R_pos. It wants to reach i.
                // The distance is i - last_R_pos.
                // If it jumps from last_R_pos to i, the jump distance is i - last_R_pos.
                // The maximum jump distance d must be at least this value.
                // We are looking for the maximum distance between any two consecutive 'R' cells (or 0 and first 'R').
                // The actual cells are 0, 1, ..., n, n+1.
                // The string s has indices 0, ..., n-1.
                // Cell 0 is the start.
                // Cell i corresponds to s[i].
                // If s[i] is 'R', the frog can jump from cell i.
                // The previous "safe" cell (from which it could jump right) was last_R_pos.
                // The current "safe" cell is i.
                // The distance between these two cells is i - last_R_pos.
                // The frog must be able to jump from last_R_pos to i.
                // So, d must be at least i - last_R_pos.
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // (or 0 if no 'R's) to the target cell n+1.
        // The distance is (n + 1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' must satisfy:
        // 1. k <= c (at least k coders needed)
        // 2. k <= m (at least k mathematicians needed)
        // 3. 3k <= c + m + x (total students available)
        // So, k <= min(c, m, (c + m + x) / 3)
        // This condition is also sufficient.
        // If we form k teams, we use k coders and k mathematicians.
        // The remaining k spots in the teams can be filled by:
        // (c - k) additional coders
        // (m - k) additional mathematicians
        // x students with no specialization
        // The total number of available "flexible" students is (c - k) + (m - k) + x.
        // We need to fill k spots.
        // So, we need (c - k) + (m - k) + x >= k.
        // This simplifies to c + m + x >= 3k.
        // Which is exactly the third condition.
        // Thus, the maximum k is indeed min(c, m, (c + m + x) / 3).
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (x_i)
        // should be i times the area of a single piece.
        // Total area = h/2. Area of one piece = (h/2)/n.
        // Area_x_i = i * (h / (2n)) = (i * h) / (2n).
        // We know Area_x = x^2 / (2h).
        // So, x_i^2 / (2h) = (i * h) / (2n).
        // x_i^2 = (i * h * 2h) / (2n) = (i * h^2) / n.
        // x_i = sqrt((i * h^2) / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

