#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int low = 1;
    int high = k + 1; // The numbers from 1 to k+1 will be used to generate k distinct differences.
                      // The differences will be k, k-1, ..., 1.

    // Generate the first k+1 elements to get k distinct differences.
    // The differences will be k, k-1, ..., 1.
    // Example: n=5, k=2
    // low=1, high=3
    // Print 1 (low)
    // Print 3 (high)
    // Print 2 (low)
    // Differences: |3-1|=2, |2-3|=1. We have 2 distinct differences (2, 1).
    // The remaining numbers are 4, 5. Print them in increasing order.
    // Result: 1 3 2 4 5

    // Example: n=3, k=2
    // low=1, high=3
    // Print 1 (low)
    // Print 3 (high)
    // Print 2 (low)
    // Differences: |3-1|=2, |2-3|=1. We have 2 distinct differences (2, 1).
    // Result: 1 3 2

    // Example: n=4, k=3
    // low=1, high=4
    // Print 1 (low)
    // Print 4 (high)
    // Print 2 (low)
    // Print 3 (high)
    // Differences: |4-1|=3, |2-4|=2, |3-2|=1. We have 3 distinct differences (3, 2, 1).
    // Result: 1 4 2 3

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...) -> take from low end
            std::cout << low++;
        } else { // Odd index (1, 3, 5, ...) -> take from high end
            std::cout << high--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k + 1) elements, print them in increasing order.
    // This ensures that the differences generated by these elements are 1,
    // and thus do not introduce new distinct differences.
    // The last element printed from the alternating sequence was either low-1 or high+1.
    // If it was low-1, then low is now the smallest unused number.
    // If it was high+1, then high is now the largest unused number.
    // In either case, 'low' now holds the smallest unused number from the original 1 to k+1 range.
    // The numbers from k+2 to n are still unused.
    // So, we continue printing from 'low' up to 'n'.
    for (int i = k + 1; i < n; ++i) {
        std::cout << low++;
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

