}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because if we split the sorted array into two halves of size n,
        // the largest element of the first half is a[n-1] and the smallest of the second half is a[n].
        // To make a[n-1] the median of a class, that class must contain a[n-1] and n-1 elements smaller than it.
        // To make a[n] the median of a class, that class must contain a[n] and n-1 elements larger than it.
        // This specific partition strategy ensures that the two medians are adjacent in the sorted full array.
        // The first class consists of elements a[0], ..., a[n-1] and n-1 other elements.
        // The second class consists of elements a[n], ..., a[2n-1] and n-1 other elements.
        // The optimal strategy is to pick a[n-1] as the median of one class and a[n] as the median of the other.
        // This is achieved by forming one class with elements a[0], ..., a[n-1] and the other with a[n], ..., a[2n-1].
        // Both classes have size n. If n is odd, this is a valid partition.
        // If n is even, this is not a valid partition.
        // However, the problem states that the total number of students is 2n.
        // The median of an array of size 2k+1 is the (k+1)-th element.
        // For a class of size S1 = 2k1+1, its median is b_{k1+1}.
        // For a class of size S2 = 2k2+1, its median is c_{k2+1}.
        // We need to find min |b_{k1+1} - c_{k2+1}|.
        // The minimum difference will always be between a[n-1] and a[n] in the sorted full array.
        // This is because any other pair of medians would involve elements further apart.
        // For example, if we pick a[i] and a[j] as medians, and i < n-1 or j > n, then |a[i]-a[j]| >= |a[n-1]-a[n]|.
        // We can always construct a valid partition where a[n-1] and a[n] are the medians.
        // Class 1: {a[0], ..., a[n-1]} (size n)
        // Class 2: {a[n], ..., a[2n-1]} (size n)
        // If n is odd, then both classes have odd size, and a[n/2] is median of class 1, a[n + n/2] is median of class 2.
        // This is not what the problem asks.
        // The problem asks for *any* partition into two odd-sized classes.
        // The key insight is that the minimum difference will always be between a[n-1] and a[n].
        // We can always form two classes of size n.
        // If n is odd, then we can take the first n elements for class 1 and the next n elements for class 2.
        // The median of class 1 would be a[(n-1)/2]. The median of class 2 would be a[n + (n-1)/2].
        // This is not necessarily a[n-1] and a[n].
        //
        // Let's re-evaluate. We have $2n$ students.
        // We need to pick $S_1$ students for class 1 and $S_2$ students for class 2, where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        // The smallest possible odd size is 1. The largest is $2n-1$.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // We want to find two medians $M_1, M_2$ such that $|M_1 - M_2|$ is minimized.
        //
        // Let's try to make $a_{n-1}$ the median of one class and $a_n$ the median of the other.
        // To make $a_{n-1}$ the median of a class, say $C_1$, $C_1$ must contain $a_{n-1}$.
        // It must also contain $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // So $S_1 = 2k_1+1$.
        // To make $a_n$ the median of a class, say $C_2$, $C_2$ must contain $a_n$.
        // It must also contain $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        // So $S_2 = 2k_2+1$.
        //
        // We can always construct a partition where $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        // Let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // Both classes have size $n$.
        // If $n$ is odd, then $C_1$ and $C_2$ are valid classes.
        // The median of $C_1$ is $a_{(n-1)/2}$. The median of $C_2$ is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler than that.
        // We have $2n$ students. We sort them: $a_0, a_1, \dots, a_{2n-1}$.
        // We need to pick $S_1$ students for class 1 and $S_2$ students for class 2, where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // Can we always make $a_{n-1}$ the median of one class and $a_n$ the median of the other?
        // Yes.
        // Let $C_1$ be the class with median $a_{n-1}$.
        // Let $C_2$ be the class with median $a_n$.
        //
        // To make $a_{n-1}$ the median of $C_1$:
        // We need to pick $k_1$ elements from $a_0, \dots, a_{n-2}$ to be in $C_1$.
        // We need to pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ to be in $C_1$.
        // The total size of $C_1$ is $2k_1+1$.
        //
        // To make $a_n$ the median of $C_2$:
        // We need to pick $k_2$ elements from $a_0, \dots, a_{n-1}$ to be in $C_2$.
        // We need to pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ to be in $C_2$.
        // The total size of $C_2$ is $2k_2+1$.
        //
        // The simplest way to achieve this is to make $k_1 = n-1$ and $k_2 = 0$.
        // Class 1: $\{a_0, a_1, \dots, a_{2n-2}\}$. Size $2n-1$. Median is $a_{n-1}$.
        // Class 2: $\{a_{2n-1}\}$. Size $1$. Median is $a_{2n-1}$.
        // This is a valid partition. The difference is $|a_{n-1} - a_{2n-1}|$.
        //
        // Or, make $k_1 = 0$ and $k_2 = n-1$.
        // Class 1: $\{a_0\}$. Size $1$. Median is $a_0$.
        // Class 2: $\{a_1, a_2, \dots, a_{2n-1}\}$. Size $2n-1$. Median is $a_n$.
        // This is a valid partition. The difference is $|a_0 - a_n|$.
        //
        // The minimum difference will always be achieved when the two medians are $a_{n-1}$ and $a_n$.
        // We can construct the classes as follows:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$ (size $n$)
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$ (size $n$)
        // This is a partition of all students.
        // If $n$ is odd, then both classes have odd size.
        // The median of Class 1 is $a_{(n-1)/2}$.
        // The median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $|a_{(n-1)/2} - a_{n + (n-1)/2}|$.
        //
        // The problem statement implies that we can choose the sizes of the classes.
        // "The number of students in the classes may be equal or different, by your choice."
        //
        // The crucial observation is that if we sort all $2n$ skill levels $a_0, a_1, \dots, a_{2n-1}$,
        // then the minimum possible difference between any two medians will be $|a_n - a_{n-1}|$.
        //
        // To prove this:
        // Let $M_1$ be the median of class $C_1$ (size $2k_1+1$) and $M_2$ be the median of class $C_2$ (size $2k_2+1$).
        // $M_1$ is the $(k_1+1)$-th element of $C_1$ when sorted.
        // $M_2$ is the $(k_2+1)$-th element of $C_2$ when sorted.
        //
        // Suppose $M_1 < M_2$.
        // $M_1$ must be at least $k_1$ elements from $C_1$ that are smaller than $M_1$.
        // $M_2$ must be at least $k_2$ elements from $C_2$ that are larger than $M_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ (the first $n$ elements) and $a_n, \dots, a_{2n-1}$ (the last $n$ elements).
        //
        // If $M_1$ is chosen from $a_0, \dots, a_{n-1}$ and $M_2$ is chosen from $a_n, \dots, a_{2n-1}$,
        // then $M_1 \le a_{n-1}$ and $M_2 \ge a_n$.
        // So $M_2 - M_1 \ge a_n - a_{n-1}$.
        //
        // Can we always construct a partition such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other?
        // Yes.
        // Let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is a partition of all $2n$ students into two classes of size $n$.
        // If $n$ is odd, then this is a valid partition. The medians are $a_{(n-1)/2}$ and $a_{n+(n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler. The $2n$ students are sorted.
        // The $n$-th student (0-indexed $a_{n-1}$) and $(n+1)$-th student (0-indexed $a_n$) are the two "middle" students.
        // The minimum difference will always be between these two.
        //
        // Example 1: n=1, a = [1, 1]. Sorted: [1, 1]. $a_{n-1} = a_0 = 1$, $a_n = a_1 = 1$. Difference = 0.
        // Example 2: n=3, a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6]. $a_{n-1} = a_2 = 3$, $a_n = a_3 = 4$. Difference = 1.
        // Example 3: n=5, a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16]. Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // $2n=10$, $n=5$. $a_{n-1} = a_4 = 8$, $a_n = a_5 = 13$. Difference = 5.
        //
        // This pattern holds for all examples.
        // The logic is that to minimize the difference between two medians, you want to pick them as close as possible in the overall sorted list.
        // The closest two elements in the overall sorted list are $a_{i}$ and $a_{i+1}$.
        // We need to show that we can always make $a_{n-1}$ and $a_n$ the medians of two valid classes.
        //
        // Let $M_1 = a_{n-1}$ and $M_2 = a_n$.
        // Class 1: $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$. This class has $n$ elements.
        // Class 2: $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$. This class has $n$ elements.
        //
        // If $n$ is odd:
        // $C_1$ has size $n$ (odd). Its median is $a_{(n-1)/2}$.
        // $C_2$ has size $n$ (odd). Its median is $a_{n+(n-1)/2}$.
        // This is a valid partition, but the medians are not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // This is a known property for problems asking to split a sorted array into two parts to minimize median difference.
        // The two medians will be $a_{n-1}$ and $a_n$.
        //
        // Let's prove that we can always make $a_{n-1}$ and $a_n$ the medians of two valid classes.
        // Let $C_1$ be the class with median $a_{n-1}$.
        // Let $C_2$ be the class with median $a_n$.
        //
        // We need to form $C_1$ with $2k_1+1$ students, where $a_{n-1}$ is the $(k_1+1)$-th student.
        // We need to form $C_2$ with $2k_2+1$ students, where $a_n$ is the $(k_2+1)$-th student.
        // And $C_1 \cup C_2 = \{a_0, \dots, a_{2n-1}\}$, $C_1 \cap C_2 = \emptyset$.
        //
        // Consider the following construction:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // Both classes have size $n$.
        // If $n$ is odd, this is a valid partition. The medians are $a_{(n-1)/2}$ and $a_{n+(n-1)/2}$.
        // The difference is $|a_{n+(n-1)/2} - a_{(n-1)/2}|$. This is not necessarily $a_n - a_{n-1}$.
        //
        // The problem is asking for the minimum possible absolute difference.
        // The minimum difference between any two elements in the sorted array is $a_{i+1} - a_i$.
        // We need to find $a_i$ and $a_j$ such that $a_i$ can be a median of $C_1$ and $a_j$ can be a median of $C_2$.
        //
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        // Assume $M_1 < M_2$.
        // $C_1$ has $k_1$ elements smaller than $M_1$ and $k_1$ elements larger than $M_1$.
        // $C_2$ has $k_2$ elements smaller than $M_2$ and $k_2$ elements larger than $M_2$.
        //
        // The total number of elements smaller than $M_1$ is at least $k_1$.
        // The total number of elements larger than $M_2$ is at least $k_2$.
        // The total number of elements between $M_1$ and $M_2$ (exclusive) is $X$.
        //
        // The total number of elements is $2n$.
        // The number of elements in $C_1$ is $2k_1+1$.
        // The number of elements in $C_2$ is $2k_2+1$.
        // $(2k_1+1) + (2k_2+1) = 2n \implies 2(k_1+k_2) + 2 = 2n \implies k_1+k_2 = n-1$.
        //
        // So, we need to find $M_1, M_2$ such that $M_1$ is the $(k_1+1)$-th element of $C_1$ and $M_2$ is the $(k_2+1)$-th element of $C_2$,
        // where $k_1+k_2 = n-1$.
        //
        // Consider the elements $a_0, \dots, a_{2n-1}$.
        // $M_1$ must be at least $k_1$ elements from $a_0, \dots, M_1-1$.
        // $M_2$ must be at least $k_2$ elements from $M_2+1, \dots, a_{2n-1}$.
        //
        // The total number of elements less than or equal to $M_1$ is $pos(M_1)+1$.
        // The total number of elements greater than or equal to $M_2$ is $2n - pos(M_2)$.
        //
        // The number of elements in $C_1$ that are $\le M_1$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\ge M_2$ is $k_2+1$.
        //
        // The total number of elements in the entire array that are $\le M_1$ is at least $k_1+1$.
        // So $M_1$ must be at least $a_{k_1}$.
        // The total number of elements in the entire array that are $\ge M_2$ is at least $k_2+1$.
        // So $M_2$ must be at most $a_{2n-(k_2+1)}$.
        //
        // We have $k_1+k_2 = n-1$.
        // So $M_1 \ge a_{k_1}$.
        // $M_2 \le a_{2n-(n-1-k_1+1)} = a_{2n-(n-k_1)} = a_{n+k_1}$.
        //
        // So we are looking for $M_1, M_2$ such that $M_1 \ge a_{k_1}$ and $M_2 \le a_{n+k_1}$ for some $k_1 \in [0, n-1]$.
        // To minimize $|M_1 - M_2|$, we want $M_1$ and $M_2$ to be as close as possible.
        // The smallest possible value for $M_2 - M_1$ would be when $M_1 = a_{k_1}$ and $M_2 = a_{n+k_1}$.
        // So we want to minimize $a_{n+k_1} - a_{k_1}$ for $k_1 \in [0, n-1]$.
        //
        // This is not quite right. $M_1$ and $M_2$ are elements from the original array $a$.
        // Let $M_1 = a_i$ and $M_2 = a_j$.
        // For $a_i$ to be a median of $C_1$ (size $2k_1+1$), there must be $k_1$ elements in $C_1$ smaller than $a_i$ and $k_1$ elements in $C_1$ larger than $a_i$.
        // This means that $i \ge k_1$ (at least $k_1$ elements $a_0, \dots, a_{i-1}$ are available to be smaller than $a_i$).
        // And $2n-1-i \ge k_1$ (at least $k_1$ elements $a_{i+1}, \dots, a_{2n-1}$ are available to be larger than $a_i$).
        // So $k_1 \le i$ and $k_1 \le 2n-1-i$.
        //
        // Similarly for $a_j$ to be a median of $C_2$ (size $2k_2+1$):
        // $k_2 \le j$ and $k_2 \le 2n-1-j$.
        //
        // We also have $k_1+k_2 = n-1$.
        //
        // We want to minimize $|a_j - a_i|$.
        //
        // Consider $i=n-1$ and $j=n$.
        // For $a_{n-1}$ to be a median of $C_1$: $k_1 \le n-1$ and $k_1 \le 2n-1-(n-1) = n$.
        // So $k_1 \le n-1$.
        // For $a_n$ to be a median of $C_2$: $k_2 \le n$ and $k_2 \le 2n-1-n = n-1$.
        // So $k_2 \le n-1$.
        //
        // We need to find $k_1, k_2$ such that $k_1+k_2 = n-1$, $k_1 \le n-1$, $k_2 \le n-1$.
        // This is always possible. For example, pick $k_1 = n-1$ and $k_2 = 0$.
        // Then $a_{n-1}$ can be median of $C_1$ (size $2(n-1)+1 = 2n-1$).
        // $a_n$ can be median of $C_2$ (size $2(0)+1 = 1$).
        //
        // Let's construct the classes for $M_1 = a_{n-1}$ and $M_2 = a_n$.
        // We need to pick $k_1$ elements smaller than $a_{n-1}$ for $C_1$. We can pick $a_0, \dots, a_{k_1-1}$.
        // We need to pick $k_1$ elements larger than $a_{n-1}$ for $C_1$.
        // We need to pick $k_2$ elements smaller than $a_n$ for $C_2$.
        // We need to pick $k_2$ elements larger than $a_n$ for $C_2$.
        //
        // Let's try to make $k_1 = 0$ and $k_2 = n-1$.
        // $C_1$ has size $2(0)+1 = 1$. Its median is $a_{n-1}$. So $C_1 = \{a_{n-1}\}$.
        // $C_2$ has size $2(n-1)+1 = 2n-1$. Its median is $a_n$.
        // For $C_2$, we need $n-1$ elements smaller than $a_n$ and $n-1$ elements larger than $a_n$.
        // We have $a_0, \dots, a_{n-2}$ (total $n-1$ elements) available to be smaller than $a_n$.
        // We have $a_{n+1}, \dots, a_{2n-1}$ (total $n-1$ elements) available to be larger than $a_n$.
        // So we can form $C_2 = \{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is a valid partition. $C_1 = \{a_{n-1}\}$ and $C_2 = \{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // The medians are $a_{n-1}$ and $a_n$. The difference is $|a_n - a_{n-1}|$.
        //
        // This construction always works.
        // The minimum possible absolute difference is indeed $a_n - a_{n-1}$.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of pages divisible by m

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for one full cycle (10 multiples of m)
        // The last digits of m, 2m, ..., 10m repeat for 11m, 12m, ..., 20m, etc.
        std::vector<int> cycle_last_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            cycle_sum += cycle_last_digits[i - 1];
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Add the sum for the remaining multiples
        long long remaining_multiples = k % 10;
        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');
    int min_idx = pos[1];
    int max_idx = pos[1];

    // For m=1, the subsegment is [p[pos[1]]], which is [1].
    // Its length is 1, min is 1, max is 1. So m=1 is always beautiful.
    result[0] = '1';

    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // Check if the current range [min_idx, max_idx] forms a permutation of 1...m
        // The length of this range must be exactly m.
        // The minimum value in this range is 1 (since we started with 1 and expanded).
        // The maximum value in this range is m (since we expanded up to m).
        // If the length is m, then all numbers from 1 to m must be present exactly once.
        if (max_idx - min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The equations are:
        // a + b = d
        // a * b = d
        // Substitute b = d - a into the second equation:
        // a * (d - a) = d
        // a*d - a^2 = d
        // a^2 - a*d + d = 0
        // This is a quadratic equation of the form Ax^2 + Bx + C = 0, where x = a, A = 1, B = -d, C = d.
        // The solutions for a are given by the quadratic formula:
        // a = (-B +/- sqrt(B^2 - 4AC)) / (2A)
        // a = (d +/- sqrt((-d)^2 - 4*1*d)) / (2*1)
        // a = (d +/- sqrt(d^2 - 4d)) / 2

        // For real solutions, the discriminant (d^2 - 4d) must be non-negative.
        // d^2 - 4d >= 0
        // d * (d - 4) >= 0
        // Since d is non-negative, this implies either d = 0 or d >= 4.
        // If 0 < d < 4, there are no real solutions.

        if (d == 0) {
            // If d = 0, then a + b = 0 and a * b = 0.
            // Since a and b must be non-negative, the only solution is a = 0, b = 0.
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4) {
            // Discriminant d^2 - 4d would be negative, no real solutions.
            std::cout << "N\n";
        } else {
            // d >= 4, so d^2 - 4d >= 0. Real solutions exist.
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // We need non-negative a and b.
            // Let's choose the '+' sign for a:
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant is real and non-negative.
            // d + sqrt_discriminant is clearly non-negative. So a1 >= 0.
            // For b1 = d - a1 = d - (d + sqrt_discriminant) / 2 = (2d - d - sqrt_discriminant) / 2 = (d - sqrt_discriminant) / 2.
            // We need b1 >= 0, which means d - sqrt_discriminant >= 0, or d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a1 and b1 will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the increasing prefix
    // such that a_i >= i-1 for i from 0 to L-1
    int L = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            L = i + 1;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the decreasing suffix
    // such that a_i >= n-1-i for i from R to n-1
    int R = n - 1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            R = i;
        } else {
            break;
        }
    }

    // If the increasing prefix and decreasing suffix overlap or touch,
    // it's possible. The peak 'k' would be in the range [R, L-1].
    // We need L > R for a valid peak to exist.
    // If L <= R, it means the increasing part ends before or at the same index
    // as the decreasing part starts, which means there's no common peak index.
    // For example, if L=1, R=n-1, it means only a[0] can be 0, and only a[n-1] can be 0.
    // If L=1, R=0, it means a[0] can be 0, and a[0] can be 0. This is valid for n=1.
    // For n > 1, we need L > R.
    // The indices are 0-based.
    // L is the count of elements in the prefix, so the last index is L-1.
    // R is the first index of the suffix.
    // We need L-1 >= R for an overlap.
    if (L > R) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

