#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    // If Chanek takes N/2, opponent faces odd N/2. Opponent takes 1.
                    // If Chanek takes 1, opponent faces N-1 (odd). Opponent takes 1.
                    // In this case, taking N/2 is better for Chanek.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // If Chanek takes N/2, opponent faces even N/2. Opponent can take (N/2)/2.
                    // If Chanek takes 1, opponent faces N-1 (odd). Opponent takes 1.
                    // Taking 1 is better for Chanek as it leaves opponent with an odd number.
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if (n == 2) { // Special case for N=2, opponent takes 1
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    // Opponent takes N/2, leaving Chanek with odd N/2.
                    n /= 2;
                } else { // N/2 is even
                    // Opponent takes 1, leaving Chanek with odd N-1.
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

