#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> max_prefix(n);
    std::vector<bool> is_prefix_perm(n, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    int distinct_count = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, it can be a[i] > i+1
            // This element makes it impossible for any longer prefix to be a permutation
            // Or it's a duplicate
            break;
        }
        seen_prefix[a[i]] = true;
        distinct_count++;
        current_max = std::max(current_max, a[i]);
        max_prefix[i] = current_max;
        if (distinct_count == i + 1 && current_max == i + 1) {
            is_prefix_perm[i] = true;
        }
    }

    std::vector<int> max_suffix(n);
    std::vector<bool> is_suffix_perm(n, false);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    current_max = 0;
    distinct_count = 0;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, it can be a[i] > n-i
            // This element makes it impossible for any longer suffix to be a permutation
            // Or it's a duplicate
            break;
        }
        seen_prefix[a[i]] = true;
        distinct_count++;
        current_max = std::max(current_max, a[i]);
        max_suffix[i] = current_max;
        if (distinct_count == n - i && current_max == n - i) {
            is_suffix_perm[i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1 - 1] && is_suffix_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

