    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char move : s) {
            if (move == 'R') {
                countR++;
            } else if (move == 'S') {
                countS++;
            } else { // move == 'P'
                countP++;
            }
        }

        char most_frequent_bot_move;
        if (countR >= countS && countR >= countP) {
            most_frequent_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            most_frequent_bot_move = 'S';
        } else { // countP is the largest
            most_frequent_bot_move = 'P';
        }

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
