int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Create pairs (B_i, original_index_i) and sort them by B_i in ascending order
    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create a map to store counts of each B_i value
    // This map will be used to assign A_i values to B_i values
    // The key is B_i, the value is a min-priority queue of A_i values
    // We want to assign larger A_i values to smaller B_i values to maximize F(A_i, B_i)
    // F(n, k) = k * (n+1) / (k+1)
    // F(n, k) = (n+1) / (1 + 1/k)
    // To maximize sum F(A_i, B_i), we need to pair largest A_i with smallest B_i.
    // However, the problem states F(n, k) = (n+1)/(k+1) * k.
    // This is equivalent to (n+1) / (1 + 1/k).
    // The derivative with respect to k is negative, meaning F decreases as k increases.
    // The derivative with respect to n is positive, meaning F increases as n increases.
    // So, we want to pair largest A_i with smallest B_i.
    // This is a standard rearrangement inequality type problem.
    // Sort A in ascending order. Sort B in ascending order.
    // To maximize sum(f(A_i, B_i)), if f is increasing in A_i and decreasing in B_i,
    // we should pair largest A_i with smallest B_i.
    // So, A should be sorted ascending, B should be sorted descending.
    // Or A descending, B ascending.
    // Let's re-evaluate F(n, k) = k * (n+1) / (k+1).
    // F(n, k) = (n+1) * (1 - 1/(k+1)).
    // Let's check the derivative with respect to k:
    // dF/dk = (n+1) * (0 - (-1)*(k+1)^(-2)) = (n+1) / (k+1)^2.
    // This is always positive for n >= 1, k >= 1.
    // So F(n, k) is an increasing function of k.
    // This means to maximize F(A_i, B_i), we should pair largest A_i with largest B_i.
    // And smallest A_i with smallest B_i.
    // So, sort A ascending, sort B ascending.
    // Then A_i' = A[i] for B_i' = B[i].
    // The problem asks to rearrange A.
    // So, we sort A ascending.
    // We sort B_indexed ascending by B_i.
    // Then we assign A[i] to the original position of b_indexed[i].second.
    // This means the smallest A value goes to the original position that had the smallest B value.
    // The second smallest A value goes to the original position that had the second smallest B value.
    // And so on.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // a[i] is the i-th smallest value from original A
        // b_indexed[i].second is the original index of the i-th smallest value from original B
        result_a_prime[b_indexed[i].second] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

