int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_b = 0;
    long long mod = 1000000007;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            count_b = (count_b + 1) % mod;
        } else { // s[i] == 'a'
            // An 'a' at this position will interact with all 'b's to its right.
            // Each 'b' to its right will cause this 'a' to perform 'count_b' operations.
            // After these operations, this 'a' effectively moves past all 'count_b' 'b's,
            // and each of those 'b's effectively duplicates, adding 'count_b' new 'b's
            // to the left of this 'a' (which are now to the left of the original 'b's).
            // So, the number of 'b's that future 'a's (to the left) will see doubles.
            total_steps = (total_steps + count_b) % mod;
            count_b = (count_b * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

