void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // First pass: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Second pass: Verify if the constructed w can produce the given s
    std::string s_reconstructed(n, '0'); // Build s_reconstructed from our candidate w
    for (int i = 0; i < n; ++i) {
        // s_reconstructed[i] is '1' if w[i-x] is '1' OR w[i+x] is '1'
        bool found_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            found_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            found_one = true;
        }
        if (found_one) {
            s_reconstructed[i] = '1';
        }
    }

    // Compare the reconstructed s with the original s
    if (s == s_reconstructed) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a non-negative integer to its parity pattern string
// Example: 241 -> "001", 92 -> "10", 50 -> "10"
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    // The problem statement implies padding with 0s from the left for shorter numbers/patterns.
    // This means we need a fixed length representation for map keys.
    // Max length of number is 18 (for 10^18-1), max pattern length is 18.
    // So, we can pad to 18 characters.
    // The current pattern is built from right to left, so it's already in the correct order for comparison.
    // We just need to pad it to a fixed length.
    // Example: 241 -> "001". Padded to 18: "000000000000000001"
    // Example: 92 -> "10". Padded to 18: "000000000000000010"
    // The pattern string from the query is also processed similarly.
    // For example, query "010" means "000000000000000010"
    // This fixed length approach simplifies matching.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    // The key will be the 18-character parity pattern string
    // The value will be the count of numbers in the multiset that generate this pattern
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // The query pattern 's' also needs to be converted to the fixed 18-character format.
            // 's' is given from left to right, but represents digits from right to left.
            // Example: s = "010" means rightmost digit even, next odd, next even.
            // Our `to_parity_pattern` function builds the string from right to left.
            // So, we need to reverse 's' and then pad it.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // `i` represents the number of items taken from the left (w_1 to w_i)
    // `n-i` represents the number of items taken from the right (w_{i+1} to w_n)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w_1, ..., w_i
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // These are w_{i+1}, ..., w_n
        // The sum of these weights is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for imbalance
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            current_energy += (long long)(left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            current_energy += (long long)(right_count - left_count - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

