// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must be divisible by f_i^a_i for all i.
        // To make x not divisible by q, we need to make x not divisible by at least one f_i^a_i.
        // The strategy is to remove just enough factors of some f_i from p to make it not divisible by q,
        // while keeping the resulting number as large as possible.
        // This means for each prime factor f_i of q, we try to divide p by f_i until p is no longer divisible by f_i^a_i.
        // More precisely, we find the largest power of f_i that divides p, say f_i^b_i.
        // If b_i >= a_i, then p is divisible by f_i^a_i.
        // We want to find the largest x such that x | p and x % q != 0.
        // This means for some prime factor f of q, the exponent of f in x is less than the exponent of f in q.

        std::vector<long long> prime_factors_q = get_prime_factors(q);
        long long max_x = 1;

        for (long long f : prime_factors_q) {
            long long current_p = p;
            // Count how many times f divides q
            long long count_f_in_q = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % f == 0) {
                count_f_in_q++;
                temp_q /= f;
            }

            // Divide current_p by f until it's no longer divisible by f^count_f_in_q
            // We need to find the largest divisor of p that is not divisible by q.
            // For a specific prime factor f of q, we can try to construct x by removing
            // all factors of f from p until p is no longer divisible by f^count_f_in_q.
            // This means we divide p by f until the exponent of f in p is less than count_f_in_q.
            // The simplest way to achieve this is to divide p by f until p is no longer divisible by q.
            // Or, more precisely, divide p by f until the number of factors of f in p is exactly count_f_in_q - 1.
            // This means we divide p by f for (exponent of f in p) - (exponent of f in q) + 1 times.

            long long temp_val = p;
            while (temp_val > 0 && temp_val % q == 0) {
                temp_val /= f;
            }
            max_x = std::max(max_x, temp_val);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
