void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int x = 0; x <= 9; ++x) {
        std::vector<int> colors(n);
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_x = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                colors[i] = 1;
                s1_digits.push_back(d[i]);
            } else if (d[i] > x) {
                colors[i] = 2;
                s2_digits.push_back(d[i]);
            } else { // d[i] == x
                // Try to assign to color 2 first, if possible
                // This ensures that digits equal to x are assigned to color 2
                // as long as the sequence for color 1 remains non-decreasing.
                // Once a digit equal to x is assigned to color 1, all subsequent
                // digits equal to x must also be assigned to color 1.
                // This is equivalent to finding the first occurrence of x that
                // is assigned to color 1. All x's before it go to color 2,
                // all x's after it go to color 1.
                // The current loop structure implicitly handles this by
                // assigning to color 2 if s2_digits is empty or d[i] >= s2_digits.back()
                // and to color 1 if s1_digits is empty or d[i] >= s1_digits.back().
                // A simpler approach for d[i] == x:
                // All d[i] == x that appear before the first d[j] > x go to color 2.
                // All d[i] == x that appear after the first d[j] > x go to color 1.
                // This is not quite right.
                // The correct logic for d[i] == x is:
                // If we have already started putting digits into s2_digits (i.e., s2_digits is not empty
                // or we have encountered a d[k] > x for some k < i), then d[i] = x must go to s1_digits.
                // Otherwise, d[i] = x can go to s2_digits.
                // This is equivalent to finding the "split point" for digits equal to x.
                // All x's before this split point go to color 2, all x's after go to color 1.
                // The split point is determined by the first digit d[k] > x.
                // All d[i] = x for i < k go to color 2.
                // All d[i] = x for i >= k go to color 1.
                // This is the strategy implemented below.
                if (!s2_digits.empty() || (s1_digits.empty() && s2_digits.empty())) {
                    // If s2_digits is not empty, it means we've already put a digit into color 2.
                    // This implies that any subsequent 'x' must go to color 1 to maintain the
                    // non-decreasing property of s1_digits and s2_digits.
                    // If both are empty, we can put 'x' into color 2.
                    colors[i] = 1;
                    s1_digits.push_back(d[i]);
                } else {
                    colors[i] = 2;
                    s2_digits.push_back(d[i]);
                }
            }
        }

        // Check if s1_digits is non-decreasing
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i - 1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        // Check if s2_digits is non-decreasing
        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i - 1]) {
                possible_x = false;
                break;
            }
        }
        if (!possible_x) continue;

        // Check if last of s1_digits <= first of s2_digits
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_x = false;
            }
        }

        if (possible_x) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

