void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 0 means cannot move left (x-1). So target X must be >= current x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // f2 = 0 means cannot move up (y+1). So target Y must be <= current y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
        // f3 = 0 means cannot move right (x+1). So target X must be <= current x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 0 means cannot move down (y-1). So target Y must be >= current y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
        // Our calculated min_x, max_x, min_y, max_y can be outside this range if all robots
        // have full movement capabilities or only restrict movement in one direction.
        // However, any point (X, Y) within [min_x, max_x] x [min_y, max_y] is a valid target.
        // We can just pick min_x and min_y as the target, as they are guaranteed to be within
        // the [-10^5, 10^5] range if a solution exists.
        // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
        // This implies that if min_x is, say, 10^6, but a valid point exists, then there must
        // be another valid point within [-10^5, 10^5].
        // The simplest approach is to clamp the chosen point to the guaranteed range.
        // However, the problem statement "it is guaranteed that if there exists at least one point
        // reachable by all robots, then at least one of such points has both coordinates not
        // exceeding 10^5 by absolute value" means we don't need to clamp.
        // We can just output min_x and min_y directly.
        // If min_x is 10^6, it means all robots require X >= 10^6.
        // If a solution exists, then min_x must be <= 10^5.
        // So, we can just output min_x and min_y.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

