#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> present_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting character for a chain (degree 1 or an isolated character)
    char start_char = '\0';
    for (char c : present_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }
    // If no degree 1 character, it means all present characters have degree 2 (a cycle)
    // or all present characters are isolated (degree 0).
    // If it's a cycle, it's impossible because a linear layout cannot represent a cycle.
    // If it's isolated characters, any can be a start.
    if (start_char == '\0' && !present_in_s.empty()) {
        // Check if it's a cycle. If all present_in_s chars have degree 2, it's a cycle.
        // A linear layout cannot represent a cycle.
        bool all_degree_2 = true;
        for (char c : present_in_s) {
            if (adj[c].size() != 2) {
                all_degree_2 = false;
                break;
            }
        }
        if (all_degree_2) {
            std::cout << "NO\n";
            return;
        }
        // If not all degree 2, then there must be some degree 0 characters.
        // Pick any present character as a start.
        start_char = *present_in_s.begin();
    }

    if (start_char != '\0') { // If there are characters from 's' to process
        char current = start_char;
        char prev = '\0'; // To keep track of the previous character in the chain

        while (visited_in_layout.find(current) == visited_in_layout.end()) {
            layout_str += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
            if (current == '\0') break; // End of chain
        }
    }

    // Add remaining characters not in 's' or not part of the main chain
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

