void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total counts
    int total_s = 0;
    int total_b = 0;
    for (int x : a) {
        if (x == 1) {
            total_s++;
        } else {
            total_b++;
        }
    }

    // Calculate prefix sums for differences (S - B)
    // For left side (jars 0 to n-1)
    // For right side (jars n to 2n-1)

    // diff_left[k] = (S - B) for jars a[n-k]...a[n-1]
    // diff_right[k] = (S - B) for jars a[n]...a[n+k-1]

    // Map to store the minimum number of jars eaten from the left side
    // to achieve a certain difference (S-B).
    // Key: difference (S-B)
    // Value: number of jars eaten from the left (k)
    std::map<int, int> left_diff_to_k;
    left_diff_to_k[0] = 0; // 0 jars eaten from left, diff is 0

    int current_s_left = 0;
    int current_b_left = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n - k; // Jars are 0-indexed, so n-1 is the first to the left, n-k is the k-th to the left
        if (a[jar_idx] == 1) {
            current_s_left++;
        } else {
            current_b_left++;
        }
        int diff = current_s_left - current_b_left;
        if (left_diff_to_k.find(diff) == left_diff_to_k.end()) {
            left_diff_to_k[diff] = k;
        }
    }

    // Initialize minimum jars to eat
    // If total_s == total_b initially, 0 jars need to be eaten.
    // Otherwise, we need to find a combination.
    int min_jars_eaten = 2 * n; // Max possible jars to eat

    // Case 1: No jars eaten from the right side (R=0)
    // We need to find if we can achieve total_s - total_b = 0 by eating only from the left.
    // The difference we need to achieve from the left side is (total_s - total_b).
    // If we eat k jars from the left, the remaining jars have (total_s - current_s_left) strawberry
    // and (total_b - current_b_left) blueberry.
    // The difference for remaining jars is (total_s - current_s_left) - (total_b - current_b_left)
    // = (total_s - total_b) - (current_s_left - current_b_left).
    // We want this to be 0, so (current_s_left - current_b_left) must be equal to (total_s - total_b).
    if (left_diff_to_k.count(total_s - total_b)) {
        min_jars_eaten = std::min(min_jars_eaten, left_diff_to_k[total_s - total_b]);
    }

    // Iterate through possible number of jars eaten from the right side (R)
    current_s_right = 0;
    current_b_right = 0;
    for (int R = 1; R <= n; ++R) {
        int jar_idx = n + R - 1; // Jars are 0-indexed, so n is the first to the right, n+R-1 is the R-th to the right
        if (a[jar_idx] == 1) {
            current_s_right++;
        } else {
            current_b_right++;
        }

        // If we eat R jars from the right, the total counts become:
        // S_new = total_s - current_s_right
        // B_new = total_b - current_b_right
        // The target difference for the remaining jars (after eating R from right) is S_new - B_new.
        // We need to find L jars from the left such that their (S-B) difference
        // (current_s_left - current_b_left) makes the final remaining difference zero.
        //
        // Let S_rem_total = total_s - current_s_right
        // Let B_rem_total = total_b - current_b_right
        // We need to find L jars from left such that
        // (S_rem_total - S_eaten_left) - (B_rem_total - B_eaten_left) = 0
        // (S_rem_total - B_rem_total) - (S_eaten_left - B_eaten_left) = 0
        // So, (S_eaten_left - B_eaten_left) must be equal to (S_rem_total - B_rem_total).
        // This is the difference we need to find in left_diff_to_k.
        int target_diff_from_left = (total_s - current_s_right) - (total_b - current_b_right);

        if (left_diff_to_k.count(target_diff_from_left)) {
            int L = left_diff_to_k[target_diff_from_left];
            min_jars_eaten = std::min(min_jars_eaten, L + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

