    // state_1[bit_idx] = final value of bit_idx if initial bit_idx was 1
    // Initially, if input bit is 0, output is 0. If input bit is 1, output is 1.
    std::vector<int> state_0(10); // Represents the output bit if input bit is 0
    std::vector<int> state_1(10); // Represents the output bit if input bit is 1
    for (int i = 0; i < 10; ++i) {
        state_0[i] = 0;
        state_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // The i-th bit of the constant 'val'

            if (op_char == '&') {
                state_0[i] &= bit_val;
                state_1[i] &= bit_val;
            } else if (op_char == '|') {
                state_0[i] |= bit_val;
                state_1[i] |= bit_val;
            } else if (op_char == '^') {
                state_0[i] ^= bit_val;
                state_1[i] ^= bit_val;
            }
        }
    }

    // Now, state_0[i] and state_1[i] hold the final transformation for bit i.
    // We need to find a minimal set of operations to achieve this.
    // There are 4 possible transformations for each bit:
    // 1. (0->0, 1->0): Always 0. Achieved by &0.
    // 2. (0->0, 1->1): Identity. Achieved by &1, |0, ^0.
    // 3. (0->1, 1->0): Flip. Achieved by ^1.
    // 4. (0->1, 1->1): Always 1. Achieved by |1.

    // We can combine these into at most 3 operations:
    // One AND operation: to force some bits to 0.
    // One OR operation: to force some bits to 1.
    // One XOR operation: to flip some bits.

    // Let's determine the constants for these three operations.
    int and_const = 1023; // Initially, all bits are 1 for AND (no effect)
    int or_const = 0;     // Initially, all bits are 0 for OR (no effect)
    int xor_const = 0;    // Initially, all bits are 0 for XOR (no effect)

    for (int i = 0; i < 10; ++i) {
        if (state_0[i] == 0 && state_1[i] == 0) {
            // (0->0, 1->0): Bit must become 0 regardless of input.
            // This means the final value of this bit must be 0.
            // We can achieve this by setting the i-th bit of and_const to 0.
            and_const &= ~(1 << i);
        } else if (state_0[i] == 0 && state_1[i] == 1) {
            // (0->0, 1->1): Identity. Bit remains unchanged.
            // This means the final value of this bit should be the same as input.
            // No change needed for and_const, or_const, xor_const for this bit.
            // and_const already has 1, or_const already has 0, xor_const already has 0.
        } else if (state_0[i] == 1 && state_1[i] == 0) {
            // (0->1, 1->0): Flip. Bit is inverted.
            // This means the final value of this bit should be flipped.
            // We can achieve this by setting the i-th bit of xor_const to 1.
            xor_const |= (1 << i);
        } else if (state_0[i] == 1 && state_1[i] == 1) {
            // (0->1, 1->1): Bit must become 1 regardless of input.
            // This means the final value of this bit must be 1.
            // We can achieve this by setting the i-th bit of or_const to 1.
            or_const |= (1 << i);
        }
    }

    // Construct the output program
    std::vector<std::pair<char, int>> result_ops;
    if (or_const != 0) {
        result_ops.push_back({'|', or_const});
    }
    if (xor_const != 0) {
        result_ops.push_back({'^', xor_const});
    }
    if (and_const != 1023) { // 1023 is all 1s for 10 bits, so &1023 is no-op
        result_ops.push_back({'&', and_const});
    }

    // The order of operations matters.
    // The sequence `(x | OR_C) ^ XOR_C & AND_C` is equivalent to `x` transformed.
    // This is because:
    // 1. OR_C sets bits to 1.
    // 2. XOR_C flips bits.
    // 3. AND_C sets bits to 0.
    // The order (OR, XOR, AND) is crucial.
    // Let's re-evaluate the constants based on this order.

    // Re-calculate constants for the fixed order: OR, XOR, AND
    // We need to find OR_C, XOR_C, AND_C such that for any bit i:
    // ((input_bit_i | OR_C_i) ^ XOR_C_i) & AND_C_i == state_X[i]
    // where state_X[i] is state_0[i] if input_bit_i=0, and state_1[i] if input_bit_i=1.

    // Let's simulate the process for each bit to find the constants.
    // We want to find (OR_C_i, XOR_C_i, AND_C_i) for each bit i.
    // For each bit i:
    // If input_bit_i = 0: ((0 | OR_C_i) ^ XOR_C_i) & AND_C_i == state_0[i]
    // If input_bit_i = 1: ((1 | OR_C_i) ^ XOR_C_i) & AND_C_i == state_1[i]

    // Initialize constants for the final program
    int final_or_const = 0;
    int final_xor_const = 0;
    int final_and_const = 1023;

    for (int i = 0; i < 10; ++i) {
        // Case 1: input bit is 0
        // Let x0 = 0. We want ((x0 | OR_C_i) ^ XOR_C_i) & AND_C_i == state_0[i]
        // Case 2: input bit is 1
        // Let x1 = 1. We want ((x1 | OR_C_i) ^ XOR_C_i) & AND_C_i == state_1[i]

        // Determine OR_C_i
        // If state_0[i] == 1 and state_1[i] == 1, then the bit must become 1 regardless of input.
        // This can be achieved by setting OR_C_i = 1.
        // If OR_C_i = 1, then (0|1)=1 and (1|1)=1.
        // So, after OR, both 0 and 1 become 1.
        if (state_0[i] == 1 && state_1[i] == 1) {
            final_or_const |= (1 << i);
        }
        // If state_0[i] == 0 and state_1[i] == 0, then the bit must become 0 regardless of input.
        // This can be achieved by setting AND_C_i = 0.
        // If state_0[i] == 0 and state_1[i] == 1, then the bit must remain unchanged.
        // If state_0[i] == 1 and state_1[i] == 0, then the bit must be flipped.

        // Now consider the state after the OR operation.
        // Let current_0 = (0 | (final_or_const >> i & 1))
        // Let current_1 = (1 | (final_or_const >> i & 1))

        // Determine XOR_C_i
        // If current_0 needs to be flipped to match state_0[i], or current_1 needs to be flipped to match state_1[i].
        // If (current_0 ^ 0) == state_0[i] and (current_1 ^ 0) == state_1[i], then XOR_C_i = 0.
        // If (current_0 ^ 1) == state_0[i] and (current_1 ^ 1) == state_1[i], then XOR_C_i = 1.

        // Let's simplify:
        // We want to find OR_C_i, XOR_C_i, AND_C_i such that:
        // f(0) = ((0 | OR_C_i) ^ XOR_C_i) & AND_C_i = state_0[i]
        // f(1) = ((1 | OR_C_i) ^ XOR_C_i) & AND_C_i = state_1[i]

        // The strategy is to determine the constants greedily for each bit.
        // For each bit i:
        // 1. If state_0[i] == 1 and state_1[i] == 1:
        //    This bit must end up as 1. The easiest way is to set OR_C_i = 1.
        //    Then (0|1)=1, (1|1)=1. After OR, both become 1.
        //    To keep them 1, XOR_C_i=0, AND_C_i=1.
        //    So, final_or_const |= (1 << i).
        // 2. If state_0[i] == 0 and state_1[i] == 0:
        //    This bit must end up as 0. The easiest way is to set AND_C_i = 0.
        //    Then (x | 0) ^ 0 & 0 = 0.
        //    So, final_and_const &= ~(1 << i).
        // 3. If state_0[i] == 0 and state_1[i] == 1: (Identity)
        //    This bit must remain unchanged.
        //    (x | 0) ^ 0 & 1 = x.
        //    So, OR_C_i=0, XOR_C_i=0, AND_C_i=1. (Default values)
        // 4. If state_0[i] == 1 and state_1[i] == 0: (Flip)
        //    This bit must be flipped.
        //    (x | 0) ^ 1 & 1 = ~x.
        //    So, final_xor_const |= (1 << i).

        // This greedy assignment works because the operations are ordered.
        // OR sets bits to 1.
        // XOR flips bits.
        // AND sets bits to 0.

        // Let's re-derive the constants for the fixed order: OR, XOR, AND
        // For each bit i:
        // Target: (state_0[i], state_1[i])
        //
        // If (state_0[i], state_1[i]) == (0,0):
        //   We need to force both 0 and 1 to become 0.
        //   This is achieved by `&0`. So, `final_and_const &= ~(1 << i)`.
        //   For OR and XOR, we want them to pass through the value to be ANDed.
        //   So, `OR_C_i = 0`, `XOR_C_i = 0`.
        //   `((x | 0) ^ 0) & 0 = x & 0 = 0`. Correct.
        //
        // If (state_0[i], state_1[i]) == (0,1):
        //   We need to keep the bit as is (identity).
        //   This is achieved by `|0 ^ 0 & 1`.
        //   So, `OR_C_i = 0`, `XOR_C_i = 0`, `AND_C_i = 1`. (Default values)
        //   `((x | 0) ^ 0) & 1 = x & 1 = x`. Correct.
        //
        // If (state_0[i], state_1[i]) == (1,0):
        //   We need to flip the bit.
        //   This is achieved by `|0 ^ 1 & 1`.
        //   So, `OR_C_i = 0`, `XOR_C_i = 1`, `AND_C_i = 1`.
        //   `final_xor_const |= (1 << i)`.
        //   `((x | 0) ^ 1) & 1 = (~x) & 1 = ~x`. Correct.
        //
        // If (state_0[i], state_1[i]) == (1,1):
        //   We need to force both 0 and 1 to become 1.
        //   This is achieved by `|1`.
        //   So, `final_or_const |= (1 << i)`.
        //   After `|1`, both 0 and 1 become 1.
        //   To keep them 1, `XOR_C_i = 0`, `AND_C_i = 1`.
        //   `((x | 1) ^ 0) & 1 = 1 & 1 = 1`. Correct.

        // This logic is sound. Let's apply it.
        if (state_0[i] == 0 && state_1[i] == 0) { // (0->0, 1->0)
            final_and_const &= ~(1 << i);
        } else if (state_0[i] == 1 && state_1[i] == 0) { // (0->1, 1->0)
            final_xor_const |= (1 << i);
        } else if (state_0[i] == 1 && state_1[i] == 1) { // (0->1, 1->1)
            final_or_const |= (1 << i);
        }
        // Case (0->0, 1->1) requires no changes to default constants for this bit.
    }

    // Collect the operations
    std::vector<std::pair<char, int>> final_ops;
    if (final_or_const != 0) {
        final_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) {
        final_ops.push_back({'^', final_xor_const});
    }
    if (final_and_const != 1023) {
        final_ops.push_back({'&', final_and_const});
    }

    std::cout << final_ops.size() << "\n";
    for (const auto& op : final_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

