// Using long long for y and a_i to prevent overflow
using ll = long long;

// Structure to store the result of a path: final y value and termination status
struct Result {
    ll final_y;
    bool terminates;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_val stores a_2, ..., a_n. a_val[0] corresponds to a_2, a_val[n-2] to a_n.
    std::vector<ll> a_val(n - 1);
    for (int i = 0; i < n - 1; ++i) {
        std::cin >> a_val[i];
    }

    // dp[i] will store the Result for starting at index i+1 (0-indexed)
    // dp[i] means starting with x = i+1, y = 0, and then applying step 2 and 3.
    // The values a_x used in the problem are 1-indexed.
    // So, if x is the current 1-indexed position, a_x is a_val[x-2] if x >= 2.
    // If x = 1, a_x is the initial 'i' value.
    std::vector<Result> dp(n + 1); // dp[0] unused, dp[1] to dp[n]

    // Iterate backwards from n to 1 to fill DP table
    // dp[k] stores the result if we are at position k (1-indexed) and are about to perform step 2.
    // This means x=k, y=current_y. We want to find the total y accumulated from this point.
    // The problem states: "The program now increases y by a_x while decreasing x by a_x."
    // This means the a_x for step 3 is based on the x *after* step 2.
    // Let's define dp[k] as the (additional_y, terminates) if we start at x=k and perform step 2 then step 3.
    // The initial y for this subproblem is 0.
    //
    // If we are at x=k (1-indexed) and about to perform step 2:
    // 1. x_after_step2 = k + a_k
    // 2. y_after_step2 = a_k
    //
    // Check termination after step 2:
    // If x_after_step2 <= 0 or x_after_step2 > n, then the program terminates.
    // The total y accumulated from this point is a_k.
    // So, dp[k] = {a_k, true}.
    //
    // If not terminated:
    // 3. x_after_step3 = x_after_step2 - a_x_after_step2
    // 4. y_after_step3 = y_after_step2 + a_x_after_step2 = a_k + a_x_after_step2
    //
    // Check termination after step 3:
    // If x_after_step3 <= 0 or x_after_step3 > n, then the program terminates.
    // The total y accumulated from this point is a_k + a_x_after_step2.
    // So, dp[k] = {a_k + a_x_after_step2, true}.
    //
    // If not terminated:
    // The program continues from x_after_step3.
    // The additional y accumulated from this point is a_k + a_x_after_step2 + dp[x_after_step3].final_y.
    // The termination status is dp[x_after_step3].terminates.
    // So, dp[k] = {a_k + a_x_after_step2 + dp[x_after_step3].final_y, dp[x_after_step3].terminates}.
    //
    // Note: a_k is a_val[k-2] for k >= 2. For k=1, a_k is the initial 'i' value.
    // The DP table `dp` stores results for `a_k` being the *actual* value at index `k`.
    // So, `dp[k]` will be computed using `a_val[k-2]` for `k >= 2`.

    for (int k = n; k >= 2; --k) {
        ll current_a_k = a_val[k - 2]; // a_k for the current k (1-indexed)

        ll x_after_step2 = k + current_a_k;
        ll y_after_step2 = current_a_k;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            dp[k] = {y_after_step2, true};
        } else {
            ll a_x_after_step2 = a_val[x_after_step2 - 2]; // a_val is 0-indexed, x_after_step2 is 1-indexed
            ll x_after_step3 = x_after_step2 - a_x_after_step2;
            ll y_after_step3 = y_after_step2 + a_x_after_step2;

            if (x_after_step3 <= 0 || x_after_step3 > n) {
                dp[k] = {y_after_step3, true};
            } else {
                // Program continues from x_after_step3.
                // We need the result for starting at x_after_step3.
                // This is exactly what dp[x_after_step3] stores.
                if (dp[x_after_step3].terminates) {
                    dp[k] = {y_after_step3 + dp[x_after_step3].final_y, true};
                } else {
                    dp[k] = {-1, false}; // If subsequent path doesn't terminate, this one doesn't either
                }
            }
        }
    }

    // Now, for each initial i (1 to n-1), calculate the result.
    // Here, a_1 = i.
    for (int i = 1; i < n; ++i) {
        ll current_a_1 = i; // a_1 for this run

        ll x_after_step2 = 1 + current_a_1;
        ll y_after_step2 = current_a_1;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << y_after_step2 << "\n";
        } else {
            ll a_x_after_step2 = a_val[x_after_step2 - 2]; // a_val is 0-indexed, x_after_step2 is 1-indexed
            ll x_after_step3 = x_after_step2 - a_x_after_step2;
            ll y_after_step3 = y_after_step2 + a_x_after_step2;

            if (x_after_step3 <= 0 || x_after_step3 > n) {
                std::cout << y_after_step3 << "\n";
            } else {
                // Program continues from x_after_step3.
                // We need the result for starting at x_after_step3.
                // This is exactly what dp[x_after_step3] stores.
                if (dp[x_after_step3].terminates) {
                    std::cout << y_after_step3 + dp[x_after_step3].final_y << "\n";
                } else {
                    std::cout << -1 << "\n";
                }
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_j values.
    // For each type 2 query (l, r, m), we know that max(b_j + current_delta_j) = m.
    // This implies b_j + current_delta_j <= m for all j in [l, r].
    // So, b_j <= m - current_delta_j.
    // We want to maximize b_j to satisfy the max condition more easily.
    // Let's initialize b_j to a very large value (effectively infinity)
    // and then take minimums based on type 2 queries.
    // A safe upper bound for b_j is 10^9.
    std::vector<long long> b(n, 1000000000LL); // Initial b_j values

    // Calculate prefix sums of d_i for each index.
    // This is the total delta applied to an index up to a certain point.
    // We need to iterate through operations to find the maximum possible b_j for each index.
    // For each type 2 query (l, r, m_k):
    // For each j in [l, r], we must have b_j + current_delta_j <= m_k.
    // So, b_j <= m_k - current_delta_j.
    // We want to find the largest possible b_j that satisfies all such constraints.
    // So, b_j = min(b_j, m_k - current_delta_j) for all relevant k.

    std::vector<long long> current_delta_at_idx(n, 0); // Sum of d_i applied to index j up to current op
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // This operation adds d_i to a_j for j in [l, r].
            // This affects current_delta_at_idx for future type 2 queries.
            // We don't update b_j directly here.
        } else { // ops[i].type == 2
            // This is a query (l, r, m_k).
            // We need to know the current_delta_j for each j in [l, r] *at this point*.
            // To do this, we can simulate the deltas up to this point.
            std::vector<long long> temp_delta_at_idx(n, 0);
            std::vector<long long> diff_array(n + 1, 0);
            for (int k = 0; k < i; ++k) { // Only consider operations before current one
                if (ops[k].type == 1) {
                    diff_array[ops[k].l] += ops[k].val;
                    if (ops[k].r + 1 < n) {
                        diff_array[ops[k].r + 1] -= ops[k].val;
                    }
                }
            }
            long long current_sum_d = 0;
            for (int j = 0; j < n; ++j) {
                current_sum_d += diff_array[j];
                temp_delta_at_idx[j] = current_sum_d;
            }

            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - temp_delta_at_idx[j]);
            }
        }
    }

    // Now we have the candidate b_j values.
    // We need to verify if these b_j values satisfy all operations.
    // Specifically, for each type 2 query (l, r, m_k), we must have:
    // max_{j=l_k}^{r_k} (b_j + current_delta_j) = m_k.
    // We already ensured b_j + current_delta_j <= m_k.
    // We need to check if max is exactly m_k.

    std::vector<long long> a_current(n); // The array a at any point in simulation
    std::vector<long long> diff_array(n + 1, 0); // For efficient range updates

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            diff_array[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n) {
                diff_array[ops[i].r + 1] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // Reconstruct a_current based on b and diff_array up to this point
            long long current_sum_d = 0;
            for (int j = 0; j < n; ++j) {
                current_sum_d += diff_array[j];
                a_current[j] = b[j] + current_sum_d;
            }

            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, a_current[j]);
            }

            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to the dentist

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d_j from children leaving due to chain reaction

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effect from child i crying in office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply accumulated d_j effect from previous children leaving
            children[j].p -= total_d_effect;

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false; // Child j leaves the line
                total_d_effect += children[j].d; // Add j's d to the accumulated effect for subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

