//    - The condition `ones_b <= max_reachable_ones_a` is sufficient because we can always adjust the length and the number of ones (by removing leading characters) to match 'b'. The only hard constraint is the maximum number of ones we can ever achieve in the string 'a' itself.

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, 0); // left_ones[i] = length of consecutive 1s ending at i
    std::vector<int> right_ones(n, 0); // right_ones[i] = length of consecutive 1s starting at i

    if (a[0] == 1) left_ones[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = left_ones[i - 1] + 1;
        } else {
            left_ones[i] = 0;
        }
    }

    if (a[n - 1] == 1) right_ones[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = right_ones[i + 1] + 1;
        } else {
            right_ones[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int l = left_ones[i];
            int r = right_ones[i];
            if (l > 0 && r > 0) { // This 0 is surrounded by 1s
                max_k = std::max(max_k, std::min(l, r) + 1);
            }
        }
    }

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            int l = left_ones[i];
            int r = right_ones[i];
            if (l > 0 && r > 0) {
                if (std::min(l, r) >= max_k) {
                    b[i] = 1;
                }
            }
        }
    }

    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

