void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition: current_sum = 2 * current_xor_sum
    // If it's already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // Let the two elements be x and y.
    // New sum: S' = current_sum + x + y
    // New XOR sum: X' = current_xor_sum ^ x ^ y
    // We want S' = 2 * X'
    // current_sum + x + y = 2 * (current_xor_sum ^ x ^ y)

    // A common strategy for these problems is to append elements that simplify the XOR sum.
    // Let's try to make the final XOR sum equal to current_xor_sum.
    // This can be done by appending current_xor_sum and 0.
    // Or by appending current_xor_sum and current_xor_sum (if we want to cancel it out).

    // Strategy: Append two elements.
    // Let the first appended element be current_xor_sum.
    // New XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
    // New sum becomes current_sum + current_xor_sum.
    // Now we need to append a second element, say 'z', such that:
    // (current_sum + current_xor_sum + z) = 2 * (0 ^ z)
    // current_sum + current_xor_sum + z = 2 * z
    // current_sum + current_xor_sum = z
    // So, the second element 'z' should be current_sum + current_xor_sum.

    // The two elements to append are:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum

    // Let's verify this:
    // Original: S_0, X_0
    // Appended: X_0, S_0 + X_0
    // New sum: S' = S_0 + X_0 + (S_0 + X_0) = 2 * S_0 + 2 * X_0
    // New XOR sum: X' = X_0 ^ X_0 ^ (S_0 + X_0) = 0 ^ (S_0 + X_0) = S_0 + X_0
    // Check condition: S' = 2 * X'
    // (2 * S_0 + 2 * X_0) = 2 * (S_0 + X_0)
    // This is always true.

    // The problem states that appended elements are non-negative.
    // current_xor_sum is always non-negative.
    // current_sum is always non-negative (since initial elements are non-negative).
    // So, S_0 + X_0 is also non-negative.
    // Thus, this strategy always works and appends 2 elements.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

