// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s_left | s_right.
    // The only rearrangement is s_right + s_left.
    // We need to check if s_right + s_left is a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the length of s_left
        std::string s_left = s.substr(0, i);
        std::string s_right = s.substr(i);
        std::string new_s = s_right + s_left;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check k=2.
    // With k=2, we have 3 pieces: s_0 | s_1 | s_2.
    // The total length of the string is N.
    // If N is odd, say N = 2m + 1, then s[m] is the center character.
    // If all characters in s are the same (e.g., "qqqq", "aaaaa"),
    // then any rearrangement of pieces will result in the same string,
    // which is also a palindrome. In this case, it's impossible to get a new string.
    // We can check this by seeing if s[0] == s[N/2]. If s[0] == s[N/2] and N > 1,
    // it implies that all characters in s are the same.
    // (Because s is a palindrome, s[0] == s[N-1], s[1] == s[N-2], etc.
    // If s[0] == s[N/2], then s[0] == s[1] == ... == s[N/2] == ... == s[N-1].)
    // This is not entirely correct. Example: "ababa". s[0]='a', s[N/2]='a'. But not all chars are same.
    // A more robust check for all characters being the same:
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }
    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible.
    // Consider the string s. Since not all characters are the same,
    // there must be at least two distinct characters.
    // Since s is a palindrome, s[0] == s[N-1], s[1] == s[N-2], etc.
    // If N is odd, the middle character s[N/2] is unique.
    // If we cut s into s[0...N/2-1] | s[N/2] | s[N/2+1...N-1],
    // and rearrange them as s[N/2+1...N-1] | s[N/2] | s[0...N/2-1],
    // this forms a new palindrome.
    // Example: "nolon" (N=5). s[0..1]="no", s[2]="l", s[3..4]="on".
    // Rearrange to "on" | "l" | "no" -> "onlno". This is a palindrome and != "nolon".
    // This is a valid strategy for k=2.
    // The problem statement guarantees that s is a palindrome.
    // If k=1 fails, and not all characters are the same, then k=2 is the answer.
    std::cout << 2 << std::endl;

    return 0;
}

