    //
    // This is one specific partition.
    // What if we put a_1 into S1 and a_2, ..., a_n into S2?
    // Min_f = a_2 + a_3
    // Max_f = max(a_{n-1} + a_n, a_1 + a_n + h)
    // Goodness = Max_f - Min_f

    // Let's consider the four "extreme" elements: a_1, a_2, a_{n-1}, a_n.
    // The minimum possible sum is a_1 + a_2.
    // The maximum possible sum is a_{n-1} + a_n.
    // The minimum possible sum with h is a_1 + a_2 + h.
    // The maximum possible sum with h is a_{n-1} + a_n + h.

    // The key insight is that the minimum and maximum values of f will always involve the smallest and largest elements.
    // Let S1 be the set of elements assigned to subsequence 1, and S2 to subsequence 2.
    // min_f = min(min_{x,y in S1} (x+y), min_{x,y in S2} (x+y), min_{x in S1, y in S2} (x+y+h))
    // max_f = max(max_{x,y in S1} (x+y), max_{x,y in S2} (x+y), max_{x in S1, y in S2} (x+y+h))

    // The minimum possible sum of two elements is a[0] + a[1].
    // The maximum possible sum of two elements is a[n-2] + a[n-1].

    // Consider the partition where a[0] is in S1 and all other elements a[1]...a[n-1] are in S2.
    // S1 = {a[0]}
    // S2 = {a[1], ..., a[n-1]}
    //
    // Pairs within S1: None (if n=1, but n>=2)
    // Pairs within S2:
    //   Min: a[1] + a[2]
    //   Max: a[n-2] + a[n-1]
    // Pairs across S1 and S2:
    //   Min: a[0] + a[1] + h
    //   Max: a[0] + a[n-1] + h
    //
    // Overall min_f = min(a[1] + a[2], a[0] + a[1] + h)
    // Overall max_f = max(a[n-2] + a[n-1], a[0] + a[n-1] + h)
    //
    // This partition is only valid if n >= 3 for a[1]+a[2] to exist.
    // If n=2, S1={a[0]}, S2={a[1]}. Only cross-subsequence pair: a[0]+a[1]+h. Min_f=Max_f=a[0]+a[1]+h. Goodness=0.
    // For n=2, goodness_all_same = (a[1]+a[0]) - (a[0]+a[1]) = 0.
    // So for n=2, both strategies give 0.

    // Let's analyze the "split" partition: a[0] in S1, a[1]...a[n-1] in S2.
    // Min_f_split = a[0].value + a[1].value + h; // Smallest cross-subsequence sum
    // Max_f_split = a[n-2].value + a[n-1].value; // Largest same-subsequence sum (if n>=3)
    // If n=2, S1={a[0]}, S2={a[1]}. Min_f=Max_f=a[0]+a[1]+h. Goodness=0.
    // If n>=3:
    //   Min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //   Max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //   Goodness_split = Max_f - Min_f

    // Let's consider the two main candidates for optimal partition:
    // 1. All elements in one subsequence (e.g., all in S1).
    //    Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    //    Partition: all 1s.
    //
    // 2. One element in S1, all others in S2.
    //    Specifically, a[0] in S1, a[1]...a[n-1] in S2.
    //    Min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h) (if n>=3)
    //    Max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h) (if n>=3)
    //    If n=2: Min_f = Max_f = a[0].value + a[1].value + h. Goodness = 0.
    //    If n>=3:
    //      long long current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    //      long long current_max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    //      long long goodness_one_split = current_max_f - current_min_f;
    //
    // The problem states "minimal possible goodness".
    // The two cases above cover the most likely optimal scenarios.
    // Case 1: All elements in one group.
    // Case 2: One element in one group, rest in another.
    // Case 3: Two elements in one group, rest in another.
    // Case 4: n-1 elements in one group, one in another. (Same as Case 2 by swapping S1/S2)
    // Case 5: n-2 elements in one group, two in another. (Same as Case 3 by swapping S1/S2)

    // Let's re-evaluate the "split" partition more carefully.
    // Consider the partition where a[0] is in S1, and a[1], ..., a[n-1] are in S2.
    // The values of f are:
    // - a[i] + a[j] for 1 <= i < j <= n-1 (both in S2)
    // - a[0] + a[k] + h for 1 <= k <= n-1 (a[0] in S1, a[k] in S2)
    //
    // Min_f for this partition:
    //   If n=2: a[0].value + a[1].value + h
    //   If n>=3: std::min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Max_f for this partition:
    //   If n=2: a[0].value + a[1].value + h
    //   If n>=3: std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //
    // Let's call this `goodness_split_min_max`.
    long long goodness_split_min_max;
    std::vector<int> partition_split_min_max(n);
    partition_split_min_max[a[0].original_index] = 1; // a[0] in S1
    for (int i = 1; i < n; ++i) {
        partition_split_min_max[a[i].original_index] = 2; // a[1]...a[n-1] in S2
    }

    if (n == 2) {
        goodness_split_min_max = 0;
    } else {
        long long min_f_split = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        long long max_f_split = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
        goodness_split_min_max = max_f_split - min_f_split;
    }

    // Compare the two main strategies
    if (goodness_all_same <= goodness_split_min_max) {
        std::cout << goodness_all_same << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_all_same[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_split_min_max << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_split_min_max[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_pos = h; // Current positions of heads, can be moved
    std::vector<bool> head_used(n, false); // Track if a head has been assigned to cover a range

    int p_idx = 0; // Current target track index
    int h_idx = 0; // Current head index

    while (p_idx < m) {
        // Find the first available head that can reach p[p_idx]
        // An available head is one that hasn't been used yet, or one that was used for a previous track
        // but can still cover p[p_idx] and potentially further tracks.

        // We need to find a head h_k such that h_k - T <= p[p_idx] <= h_k + T.
        // And this head should be "available".
        // The greedy strategy is to use the leftmost available head that can cover p[p_idx].
        // If multiple heads can cover p[p_idx], we want to use the one that extends furthest to the right
        // to cover as many subsequent tracks as possible.

        // Let's re-evaluate the greedy strategy.
        // We iterate through p_idx. For each p[p_idx], we need to cover it.
        // We want to use a head that is "optimal".
        // The optimal head is one that can cover p[p_idx] and also extends furthest to the right.
        // This is because we want to cover as many p_j's as possible with one head.

        // Let's maintain a set of available heads, sorted by their current position.
        // Or, more simply, iterate through heads.
        // For each p[p_idx], we need to find a head h_k such that h_k - T <= p[p_idx].
        // Among such heads, we want to pick one that maximizes h_k + T.
        // This is equivalent to picking the largest h_k such that h_k - T <= p[p_idx].

        // This is a standard interval covering problem.
        // We have points p_j to cover.
        // We have heads h_i. Each head h_i can cover an interval [h_i - T, h_i + T].
        // We need to select at most n such intervals to cover all p_j.

        // A more robust greedy approach:
        // Iterate through target tracks p_j.
        // For each p_j, we need to cover it.
        // We look for a head h_k that can cover p_j.
        // If multiple heads can cover p_j, which one to pick?
        // The one that can reach furthest to the right.
        // This means we want to pick a head h_k such that h_k + T is maximized,
        // subject to h_k - T <= p_j.

        // Let's use a two-pointer approach.
        // `p_idx` iterates through target tracks.
        // `h_idx` iterates through heads.
        // `last_covered_p_idx` stores the index of the last target track covered by the current head.

        // For each head, we want to cover a contiguous block of p_j's.
        // A head h_i can cover tracks in range [h_i - T, h_i + T].
        // We want to assign heads to cover segments of p.

        // Let's try a different greedy strategy:
        // We iterate through the target tracks `p_idx` from left to right.
        // For each `p[p_idx]`, we need to cover it.
        // We find the *first* head `h[h_ptr]` (from left to right) that can cover `p[p_idx]`.
        // If `h[h_ptr] + T < p[p_idx]`, this head cannot cover `p[p_idx]`, so we move to the next head `h_ptr++`.
        // If `h[h_ptr] - T > p[p_idx]`, this head is too far to the right to cover `p[p_idx]`, and any subsequent heads will also be too far.
        // This means `p[p_idx]` cannot be covered by any remaining heads. This case should not happen if we pick heads correctly.

        // The correct greedy strategy for interval covering:
        // We need to cover points p_0, p_1, ..., p_{m-1}.
        // We have heads h_0, h_1, ..., h_{n-1}.
        // Each head h_i can cover an interval [h_i - T, h_i + T].
        // We want to use minimum number of heads to cover all p_j.
        // This is not exactly minimum number of heads, but rather, can we cover all p_j using at most N heads.

        // Let's use a two-pointer approach for `p` and `h`.
        // `p_ptr` is the index of the current target track we need to cover.
        // `h_ptr` is the index of the current head we are considering.

        int current_p_idx = 0;
        int current_h_idx = 0;

        while (current_p_idx < m) {
            // Find the first head that can potentially cover p[current_p_idx]
            // This head must be to the right of or at p[current_p_idx] - T
            while (current_h_idx < n && h[current_h_idx] + T < p[current_p_idx]) {
                current_h_idx++; // This head is too far left to cover p[current_p_idx]
            }

            if (current_h_idx == n) {
                return false; // No more heads available to cover p[current_p_idx]
            }

            // Now, h[current_h_idx] is the first head such that h[current_h_idx] + T >= p[current_p_idx].
            // Check if it can actually cover p[current_p_idx].
            if (h[current_h_idx] - T > p[current_p_idx]) {
                return false; // This head is too far right to cover p[current_p_idx], and all subsequent heads are even further right.
            }

            // h[current_h_idx] can cover p[current_p_idx].
            // This head covers the range [h[current_h_idx] - T, h[current_h_idx] + T].
            // We use this head to cover as many subsequent p_j's as possible.
            long long max_reach = h[current_h_idx] + T;
            while (current_p_idx < m && p[current_p_idx] <= max_reach) {
                current_p_idx++;
            }
            current_h_idx++; // Move to the next head for the next uncovered p_j
        }
        return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2*10^10.
                               // A safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

