    std::vector<int> last_bad_r(n + 1, 0); // last_bad_r[i] stores the maximum r such that (i, r) is a bad pair.
                                          // 0-indexed for string, 1-indexed for l, r in problem.
                                          // last_bad_r[l] means for a fixed l, what is the largest r such that (l, r) is bad.
                                          // If last_bad_r[l] = 0, it means no bad triplet starts at or before l and ends at or after l.

    // Iterate through all possible x and k to find bad triplets
    // x is 0-indexed, k is step.
