#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem statement guarantees a solution exists.
        // Reversing the permutation always produces a different permutation
        // (unless n=1, but n>=2) and preserves the set of adjacent sums.
        // The sorted list of adjacent sums (fingerprint) will thus be the same.

        // Create p' by reversing p
        std::vector<int> p_prime(n);
        for (int i = 0; i < n; ++i) {
            p_prime[i] = p[n - 1 - i];
        }

        // Output p'
        for (int i = 0; i < n; ++i) {
            std::cout << p_prime[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

