    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Use 5s as much as possible
        ans += diff / 5;
        diff %= 5;

        // Remaining diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No remaining diff
        } else if (diff == 1) {
            ans += 1; // Use one 1
        } else if (diff == 2) {
            ans += 1; // Use one 2
        } else if (diff == 3) {
            ans += 2; // Use one 2 and one 1
        } else if (diff == 4) {
            ans += 2; // Use two 2s
        }

        std::cout << ans << "\n";
    }
    return 0;
}

