int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = 2000000000LL; // k can be up to 10^4, a_i up to k. Max possible sum of a_i is n*k.
                                        // min_val will be at most k.
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it multiple times.
            // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
            // This is because a[i] + x * min_val <= k
            // x * min_val <= k - a[i]
            // x <= (k - a[i]) / min_val
            operations += (k - a[i]) / min_val;
        }
        std::cout << operations << "\n";
    }
    return 0;
}

