int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d;
        std::cin >> n >> d;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long max_a1 = a[0]; // Initial haybales in pile 1

        for (int i = 1; i < n; ++i) { // Iterate through piles from 2 to n (index 1 to n-1)
            long long pile_idx = i + 1; // 1-based index of the current pile
            long long cost_per_haybale = pile_idx - 1; // Days to move one haybale to pile 1

            if (d >= cost_per_haybale) { // If we have enough days to move at least one haybale
                long long haybales_to_move = std::min(a[i], d / cost_per_haybale);
                max_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile,
                // nor from any subsequent piles (which would have higher cost).
                break; 
            }
        }
        std::cout << max_a1 << std::endl;
    }
    return 0;
}

