#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // Create frequency maps for characters in s and t
    // A std::vector<bool> or std::array<bool, 26> would also work
    // std::vector<bool> s_chars(26, false);
    // std::vector<bool> t_chars(26, false);

    // Using a simple boolean flag to track if a common character is found
    bool common_char_found = false;

    // Iterate through all possible lowercase Latin letters 'a' through 'z'
    for (char c = 'a'; c <= 'z'; ++c) {
        // Check if character 'c' exists in string s
        bool c_in_s = false;
        for (char sc : s) {
            if (sc == c) {
                c_in_s = true;
                break;
            }
        }

        // Check if character 'c' exists in string t
        bool c_in_t = false;
        for (char tc : t) {
            if (tc == c) {
                c_in_t = true;
                break;
            }
        }

        // If character 'c' exists in both strings, then it's possible
        // to make them equal. We only need to find one such common character.
        if (c_in_s && c_in_t) {
            common_char_found = true;
            break; // No need to check other characters
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

