            p[i] = 1; // Assign to black (d)
        } else { // a[i] == T / 2.0
            // This condition is true if T is even and a[i] == T/2
            // Or if T is odd, this branch is never reached because a[i] cannot be T/2.0
            // (a[i] is integer, T/2.0 would be X.5, so a[i] < T/2.0 or a[i] > T/2.0)
            p[i] = color_for_half;
            color_for_half = 1 - color_for_half; // Alternate color for next T/2 element
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
