#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Because if p[i] < n, then there must be some p[k] > p[i].
        // For such k, a[i][k] = min(p[i], p[k]) = p[i].
        // But there must also be some p[j] < p[i].
        // For such j, a[i][j] = min(p[i], p[j]) = p[j].
        // The maximum value in the row would be p[i] if p[i] is the largest among all p[k] where p[k] < p[i].
        // Or it would be p[i] if p[i] is the largest among all p[j] where p[j] > p[i].
        // This logic is a bit convoluted.
        //
        // A simpler observation:
        // For each i, p[i] is either the maximum value in its row (excluding a[i][i])
        // OR it is n.
        //
        // If p[i] = n, then for all j != i, p[j] < p[i].
        // So a[i][j] = min(p[i], p[j]) = p[j].
        // In this case, the set {a[i][j] | j != i} is {p[1], ..., p[i-1], p[i+1], ..., p[n]}.
        // The maximum value in this set is n-1.
        // So, if max_val_in_row == n-1, then p[i] must be n.
        //
        // If p[i] < n, then there must be some p[k] = n.
        // For this k, a[i][k] = min(p[i], p[k]) = min(p[i], n) = p[i].
        // For any other j where p[j] < p[i], a[i][j] = p[j].
        // For any other j where p[j] > p[i] (and p[j] != n), a[i][j] = p[i].
        // So, the maximum value in row i (excluding a[i][i]) will be p[i].
        //
        // Therefore, p[i] = max_val_in_row, UNLESS max_val_in_row is n-1, in which case p[i] = n.
        // This covers all cases.

        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

