#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long n = 1; // Represents the number of stairs in the current staircase
        while (true) {
            // Calculate the cost for a staircase with 'n' stairs
            // The cost is (2^n - 1) * (2^n) / 2
            // This is equivalent to (2^n - 1) * 2^(n-1)
            // Let k = 2^n. Then cost is (k-1)*k/2.
            // For n=1, k=2, cost = (2-1)*2/2 = 1.
            // For n=2, k=4, cost = (4-1)*4/2 = 6.
            // For n=3, k=8, cost = (8-1)*8/2 = 28.
            // For n=4, k=16, cost = (16-1)*16/2 = 120.

            // We need to calculate 2^n.
            // Since n can go up to ~60 for x=10^18, 2^n can be very large.
            // Let's use a variable for 2^n.
            // The sequence of costs is 1, 6, 28, 120, 496, ...
            // This is (2^n - 1) * 2^(n-1)
            // Let's maintain 2^n as `power_of_2_n`.
            // For n=1, power_of_2_n = 2. Cost = (2-1)*1 = 1.
            // For n=2, power_of_2_n = 4. Cost = (4-1)*2 = 6.
            // For n=3, power_of_2_n = 8. Cost = (8-1)*4 = 28.
            // For n=4, power_of_2_n = 16. Cost = (16-1)*8 = 120.

            // The cost for a staircase with `n` stairs is `(2^n - 1) * 2^(n-1)`.
            // Let `k = 2^n`. Then the cost is `(k - 1) * (k / 2)`.
            // We can compute `k` iteratively.
            // For n=1, k=2. Cost = (2-1)*(2/2) = 1.
            // For n=2, k=4. Cost = (4-1)*(4/2) = 6.
            // For n=3, k=8. Cost = (8-1)*(8/2) = 28.

            // Let's use `k` to represent `2^n`.
            // Initial `k` for n=1 is 2.
            // In each iteration, `k` doubles.

            long long k_val = (1LL << n); // k_val = 2^n
            long long cost_for_n_stairs = (k_val - 1) * (k_val / 2);

            if (current_cost + cost_for_n_stairs <= x) {
                current_cost += cost_for_n_stairs;
                count++;
                n++;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

