    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part of the carrot (from apex to cut x_i)
        // should be i times the area of a single piece.
        // Total area of carrot = (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n.
        // Area of top part up to x_i = i * (h/2) / n = i * h / (2n).
        //
        // For a triangle with height x_i, its base b_i is found by similar triangles:
        // b_i / x_i = 1 / h  => b_i = x_i / h.
        // Area of this triangle = (1/2) * b_i * x_i = (1/2) * (x_i / h) * x_i = x_i^2 / (2h).
        //
        // Equating the two expressions for the area:
        // x_i^2 / (2h) = i * h / (2n)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

