int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs 3 students).
        // So, a naive upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low' for binary search.
        // The actual answer can be at most min(c, m) because each team needs at least one of each.
        // The total number of students is c + m + x. Each team needs 3 students.
        // So, the total number of teams cannot exceed (c + m + x) / 3.
        // Therefore, the maximum possible answer is min(c, m, (c + m + x) / 3).
        // We can binary search for the answer 'k'.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Upper bound for k
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining no-specialization students: x

            // Total students available to fill the third slot in each team:
            // (c - mid) + (m - mid) + x

            // Each of the 'mid' teams needs 1 coder and 1 mathematician.
            // This leaves 'mid' slots to be filled by any remaining student.
            // The total number of students available for these 'mid' slots is
            // (c - mid) + (m - mid) + x.

            // If we have enough students to fill these 'mid' slots, then 'mid' teams are possible.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

