    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the "zig-zag" part to generate k distinct differences.
                       // The differences will be k, k-1, ..., 1.
                       // So we need numbers from 1 to k+1.

    // Generate k distinct differences: k, k-1, ..., 1
    // We use numbers from 1 to k+1.
    // The pattern is: low, high, low+1, high-1, ...
    // Example: k=2. Numbers 1, 2, 3.
    // 1, 3, 2. Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}.
    // Example: k=3. Numbers 1, 2, 3, 4.
    // 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, print from left (increasing)
            std::cout << left << " ";
            left++;
        } else { // Odd index, print from right (decreasing)
            std::cout << right << " ";
            right--;
        }
    }

    // After generating k distinct differences using numbers 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // To avoid introducing new distinct differences, we print these remaining numbers
    // in increasing order. This will only generate a difference of 1 (e.g., |(k+1) - (k+2)| = 1).
    // Since 1 is already among the k distinct differences generated, no new distinct difference is added.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

