    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the initial non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i - 1] >= a[i]) {
        i--;
    }
    // Now `a[i...n-1]` is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the initial non-increasing suffix (from right)
    int j = i; // Start searching from `i`
    while (j > 0 && a[j - 1] <= a[j]) {
        j--;
    }
    // Now `a[j...i-1]` is non-increasing.
    // The segment `a[j...n-1]` is a candidate for a "good" array.
    // The prefix to remove has length `j`.

    std::cout << j << std::endl;
}

