#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index seen so far (for 1 to m-1)
        // to the maximum index seen so far (for 1 to m-1), AND also include 'm'.
        // So, the new minimum index will be min(current_min_idx, pos[m])
        // and the new maximum index will be max(current_max_idx, pos[m]).
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if there exists a subsegment [l, r]
        // such that it contains exactly numbers 1, 2, ..., m.
        // This implies:
        // 1. The minimum value in p[l...r] is 1.
        // 2. The maximum value in p[l...r] is m.
        // 3. The length of the subsegment (r - l + 1) is m.
        //
        // By maintaining current_min_idx and current_max_idx, we are tracking
        // the smallest and largest indices that contain all numbers from 1 to m.
        // If the segment p[current_min_idx ... current_max_idx] contains exactly
        // numbers 1 to m, then its length must be m.
        // The length of this segment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

