}

#include <iostream>
#include <cmath>
#include <iomanip>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The quadratic equation for 'a' is a^2 - d*a + d = 0
        // Discriminant delta = (-d)^2 - 4*1*d = d^2 - 4d
        double discriminant = d * d - 4 * d;

        if (discriminant < 0) {
            // No real solutions if discriminant is negative
            std::cout << "N\n";
        } else {
            // Solutions for 'a' are (d +/- sqrt(discriminant)) / 2
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double a2 = (d - sqrt_discriminant) / 2.0;

            // We need non-negative a and b.
            // If a is a solution, then b = d - a.
            // If a1 is a solution, b1 = d - a1.
            // If a2 is a solution, b2 = d - a2.
            // Note that a1 + a2 = d, so b1 = a2 and b2 = a1.
            // We just need to pick one pair (a, b) such that a, b >= 0.
            // Since d >= 0, and sqrt_discriminant >= 0:
            // a1 = (d + sqrt_discriminant) / 2.0 will always be >= 0.
            // For a2 = (d - sqrt_discriminant) / 2.0 to be >= 0, we need d - sqrt_discriminant >= 0,
            // which means d >= sqrt_discriminant, or d^2 >= discriminant.
            // d^2 >= d^2 - 4d, which simplifies to 0 >= -4d, or 4d >= 0, which is true for d >= 0.
            // So both a1 and a2 are always non-negative.
            // We can just pick a1 and b1 (which is a2).

            // The problem asks for a and b such that a+b=d and a*b=d.
            // The solutions from the quadratic formula directly give such a pair.
            // Let's use a = a1 and b = a2.
            // To match example output format, print the larger one first if they are different.
            // The example output for d=5 is Y 3.618033989 1.381966011, which is (d+sqrt)/2 and (d-sqrt)/2.
            // So a = (d + sqrt(d^2 - 4d)) / 2
            //    b = (d - sqrt(d^2 - 4d)) / 2
            // Or vice versa. The problem statement doesn't specify order, but example does.
            // Let's ensure a >= b.
            double a_val = std::max(a1, a2);
            double b_val = std::min(a1, a2);

            std::cout << "Y " << std::fixed << std::setprecision(9) << a_val << " " << b_val << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix minimums for the increasing part
    // min_val_prefix[i] stores the minimum possible value for a[i]
    // if it's part of an increasing sequence starting from a[0]=0.
    // That is, a[i] >= i.
    // We can achieve a[i] = i if a[i] (original) >= i.
    // If a[i] (original) < i, we cannot make a[i] = i.
    // So, min_val_prefix[i] = min(a[i], i).
    // However, we need a[i] to be strictly increasing.
    // So, a[i] must be at least i.
    // If a[i] (original) < i, it's impossible to make a[i] >= i.
    // So, we can just check if a[i] >= i for all i in the prefix.
    // The actual value we can achieve for a[i] is a[i] (original).
    // We need to find the longest prefix where a[i] >= i.
    int prefix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            prefix_len++;
        } else {
            break;
        }
    }

    // Calculate suffix minimums for the decreasing part
    // min_val_suffix[i] stores the minimum possible value for a[i]
    // if it's part of a decreasing sequence ending at a[n-1]=0.
    // That is, a[i] >= (n-1-i).
    // We can achieve a[i] = (n-1-i) if a[i] (original) >= (n-1-i).
    // If a[i] (original) < (n-1-i), we cannot make a[i] = (n-1-i).
    // So, we can just check if a[i] >= (n-1-i) for all i in the suffix.
    // We need to find the longest suffix where a[i] >= (n-1-i).
    int suffix_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            suffix_len++;
        } else {
            break;
        }
    }

    // If the sum of lengths of the valid prefix and suffix is greater than or equal to n,
    // it means there's at least one element that can be part of both,
    // which implies a valid peak k exists.
    // For example, if prefix_len = 3 and suffix_len = 3 for n=4:
    // prefix covers indices 0, 1, 2.
    // suffix covers indices 1, 2, 3.
    // Index 2 is covered by both.
    // The peak can be at index 2.
    // The condition is prefix_len + suffix_len >= n.
    if (prefix_len + suffix_len >= n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (smaller elements)
        // We want to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, we can advance j.
        // If a[j] is not greater than a[i], we need a larger element, so we increment j.
        // If a[j] is greater than a[i], we found a match. We increment count and move to the next element for both.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] > a[i]
            count++;
            j++; // Move to the next element for placement
        } else {
            // No more elements in 'a' are greater than a[i] or any subsequent a[k] (k > i)
            // because 'a' is sorted. So we can break.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to partition 2n students into two classes,
        // each with an odd number of students.
        // Let the sizes be S1 and S2. S1 + S2 = 2n.
        // S1 must be odd, S2 must be odd.
        // If S1 is odd, then S2 = 2n - S1 is also odd (even - odd = odd).
        // The smallest odd size is 1.
        // The median of a class of size 2k+1 is the (k+1)-th element after sorting.
        //
        // Consider the sorted array of all 2n skill levels: a[0], a[1], ..., a[2n-1].
        //
        // To minimize the absolute difference between medians, we want the medians
        // to be as close as possible.
        //
        // Let's try to make the two classes of size n (if n is odd) or n-1 and n+1 (if n is even).
        // However, the problem states that each class must have an odd number of students.
        //
        // The key insight for this problem is that to minimize the difference between medians,
        // we should pick the medians from the middle of the sorted full list.
        //
        // If we sort all 2n students, the students are a[0], a[1], ..., a[2n-1].
        //
        // Consider the partition where one class takes students a[0], ..., a[n-1]
        // and the other class takes students a[n], ..., a[2n-1].
        // This is a partition into two classes of size n.
        // If n is odd, then both classes have odd size.
        // The median of the first class (a[0]...a[n-1]) would be a[(n-1)/2].
        // The median of the second class (a[n]...a[2n-1]) would be a[n + (n-1)/2].
        // The difference would be a[n + (n-1)/2] - a[(n-1)/2].
        //
        // If n is even, this partition is not allowed because class sizes are even.
        //
        // However, the problem statement implies that we can choose any odd sizes S1, S2.
        //
        // Let's consider the students a[n-1] and a[n].
        // If we can make a[n-1] the median of one class and a[n] the median of the other class,
        // then the difference would be a[n] - a[n-1]. This is the smallest possible difference
        // between any two distinct skill levels that are adjacent in the sorted list.
        //
        // Can we always achieve this?
        //
        // To make a[n-1] the median of a class, say Class 1, this class must have an odd size, say 2k+1.
        // And a[n-1] must be the (k+1)-th element. This means there must be k elements smaller than or equal to a[n-1]
        // in Class 1, and k elements larger than or equal to a[n-1] in Class 1.
        //
        // To make a[n] the median of a class, say Class 2, this class must have an odd size, say 2j+1.
        // And a[n] must be the (j+1)-th element. This means there must be j elements smaller than or equal to a[n]
        // in Class 2, and j elements larger than or equal to a[n] in Class 2.
        //
        // Consider the specific partition where:
        // Class 1 consists of students a[0], a[1], ..., a[n-1].
        // Class 2 consists of students a[n], a[n+1], ..., a[2n-1].
        //
        // Both classes have exactly n students.
        // If n is odd, then both classes have an odd number of students.
        // The median of Class 1 is a[(n-1)/2].
        // The median of Class 2 is a[n + (n-1)/2].
        // The difference is a[n + (n-1)/2] - a[(n-1)/2].
        //
        // The problem statement example for n=1 (2 students) has a=[1,1].
        // Sorted: a=[1,1]. n=1.
        // Class 1: [1], Class 2: [1]. Both size 1 (odd).
        // Median 1: a[0]=1. Median 2: a[1]=1. Difference = 0.
        // Our formula a[n + (n-1)/2] - a[(n-1)/2] for n=1 gives a[1 + (1-1)/2] - a[(1-1)/2] = a[1] - a[0].
        // This is 1-1=0. Correct.
        //
        // The problem statement example for n=3 (6 students) has a=[6,5,4,1,2,3].
        // Sorted: a=[1,2,3,4,5,6]. n=3.
        // Class 1: [1,2,3], Class 2: [4,5,6]. Both size 3 (odd).
        // Median 1: a[(3-1)/2] = a[1] = 2.
        // Median 2: a[3 + (3-1)/2] = a[3+1] = a[4] = 5.
        // Difference = |5-2| = 3.
        //
        // However, the example output is 1.
        // The example says: "one of the possible partitions is to make the first class of students with skill levels [6, 4, 2], so that the skill level of the first class will be 4, and second with [5, 1, 3], so that the skill level of the second class will be 3. Absolute difference will be |4 - 3| = 1."
        //
        // This means my assumption about partitioning into a[0...n-1] and a[n...2n-1] is not necessarily optimal.
        //
        // The crucial observation is that the median of a set of $2k+1$ numbers is the $(k+1)$-th smallest.
        // If we have $2n$ students, and we want to pick two medians $m_1$ and $m_2$.
        // Let $m_1$ be $a_i$ and $m_2$ be $a_j$ from the sorted list.
        // To minimize $|a_j - a_i|$, we want $i$ and $j$ to be as close as possible.
        // The closest possible distinct elements in a sorted array are $a_k$ and $a_{k+1}$.
        //
        // Can we always make $a_{n-1}$ and $a_n$ the medians of the two classes?
        //
        // Let's try to make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        //
        // Class 1:
        // We need $k$ elements smaller than or equal to $a_{n-1}$ and $k$ elements larger than or equal to $a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are smaller than $a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are larger than $a_{n-1}$.
        //
        // To make $a_{n-1}$ the median of Class 1, we need to pick $k$ elements from $a_0, \dots, a_{n-2}$
        // and $k$ elements from $a_n, \dots, a_{2n-1}$.
        // The size of Class 1 would be $2k+1$.
        // The maximum $k$ we can pick from $a_0, \dots, a_{n-2}$ is $n-1$.
        // The maximum $k$ we can pick from $a_n, \dots, a_{2n-1}$ is $n$.
        // So, we can pick $k$ up to $n-1$.
        // If we pick $k=n-1$, Class 1 would have size $2(n-1)+1 = 2n-1$.
        // This class would consist of $a_0, \dots, a_{n-2}$, then $a_{n-1}$, then $n-1$ elements from $a_n, \dots, a_{2n-1}$.
        // For example, $a_n, \dots, a_{2n-2}$.
        // So Class 1 could be $\{a_0, \dots, a_{n-2}, a_{n-1}, a_n, \dots, a_{2n-2}\}$.
        // Its median would be $a_{n-1}$.
        // The remaining student is $a_{2n-1}$. This forms Class 2 of size 1. Its median is $a_{2n-1}$.
        // The difference would be $|a_{2n-1} - a_{n-1}|$. This is generally large.
        //
        // What if we make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2?
        //
        // Class 1: must contain $a_{n-1}$. It needs $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ available that are smaller than $a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ available that are larger than $a_{n-1}$.
        //
        // Class 2: must contain $a_n$. It needs $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ available that are smaller than $a_n$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ available that are larger than $a_n$.
        //
        // We need to partition all $2n$ students.
        //
        // Let's try to construct the classes such that $a_{n-1}$ and $a_n$ are the medians.
        //
        // Class 1 (median $a_{n-1}$):
        // We must include $a_{n-1}$.
        // We need to pick $k_1$ elements from $\{a_0, \dots, a_{n-2}\}$ (smaller than $a_{n-1}$).
        // We need to pick $k_1$ elements from $\{a_{n+1}, \dots, a_{2n-1}\}$ (larger than $a_n$, and thus larger than $a_{n-1}$).
        // We also have $a_n$ available, but if $a_n$ is in Class 1, it would be larger than $a_{n-1}$.
        //
        // This is getting complicated. Let's simplify.
        //
        // The problem asks for the minimum possible absolute difference.
        // The smallest possible difference between any two elements in a sorted array is between adjacent elements.
        // So, the minimum possible difference is at least $a_i - a_{i-1}$ for some $i$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // Can we always make $a_{n-1}$ the median of one class and $a_n$ the median of the other class?
        //
        // Let Class 1 be $\{a_0, a_1, \dots, a_{n-1}\}$ and Class 2 be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // Both classes have size $n$.
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        //
        // This is what I calculated for n=3, giving 3. But the example output is 1.
        // This means the partition into two equal halves (if n is odd) is not necessarily optimal.
        //
        // The example for n=3: a=[1,2,3,4,5,6]. Output 1.
        // This means we need to find two classes whose medians differ by 1.
        // The only way to get a difference of 1 is if the medians are 3 and 4.
        // So, one class has median 3, the other has median 4.
        //
        // Class 1 (median 3): [1,3,5] (size 3). Median is 3.
        // Class 2 (median 4): [2,4,6] (size 3). Median is 4.
        // This is a valid partition. Both classes have odd size 3. All students are assigned.
        // The difference is $|4-3|=1$.
        //
        // Notice that in this example, $a_{n-1} = a_{3-1} = a_2 = 3$. And $a_n = a_3 = 4$.
        // So, the medians are exactly $a_{n-1}$ and $a_n$.
        //
        // Let's generalize this. Can we always make $a_{n-1}$ and $a_n$ the medians?
        //
        // To make $a_{n-1}$ the median of Class 1:
        // We need to pick $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ available that are smaller than $a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ available that are larger than $a_{n-1}$.
        //
        // To make $a_n$ the median of Class 2:
        // We need to pick $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ available that are smaller than $a_n$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ available that are larger than $a_n$.
        //
        // Let's try to construct the classes:
        // Class 1: $\{a_0, a_2, \dots, a_{2(n-1)}, a_{n-1}\}$
        // This is not a simple construction.
        //
        // The problem is simpler than trying to construct the classes.
        // We need to find the minimum possible absolute difference.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        //
        // The key insight is that the median of a class of size $2k+1$ is the $(k+1)$-th element.
        //
        // Let's consider the elements $a_{n-1}$ and $a_n$.
        // Can we always form two classes, each of odd size, such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other?
        //
        // Let Class 1 be $C_1$ and Class 2 be $C_2$.
        // We want $median(C_1) = a_{n-1}$ and $median(C_2) = a_n$.
        //
        // To make $a_{n-1}$ the median of $C_1$:
        // $C_1$ must contain $a_{n-1}$.
        // $C_1$ must have $k_1$ elements $< a_{n-1}$ and $k_1$ elements $> a_{n-1}$.
        // The elements available for $C_1$ that are $< a_{n-1}$ are $a_0, \dots, a_{n-2}$ (total $n-1$ elements).
        // The elements available for $C_1$ that are $> a_{n-1}$ are $a_n, \dots, a_{2n-1}$ (total $n$ elements).
        //
        // To make $a_n$ the median of $C_2$:
        // $C_2$ must contain $a_n$.
        // $C_2$ must have $k_2$ elements $< a_n$ and $k_2$ elements $> a_n$.
        // The elements available for $C_2$ that are $< a_n$ are $a_0, \dots, a_{n-1}$ (total $n$ elements).
        // The elements available for $C_2$ that are $> a_n$ are $a_{n+1}, \dots, a_{2n-1}$ (total $n-1$ elements).
        //
        // We need to partition all $2n$ students.
        //
        // Let's try to construct $C_1$ and $C_2$ using $a_{n-1}$ and $a_n$ as medians.
        //
        // $C_1$ will contain $a_{n-1}$.
        // $C_2$ will contain $a_n$.
        //
        // We have $n-1$ elements $L = \{a_0, \dots, a_{n-2}\}$ (strictly less than $a_{n-1}$).
        // We have $n-1$ elements $R = \{a_{n+1}, \dots, a_{2n-1}\}$ (strictly greater than $a_n$).
        //
        // We need to distribute $L$ and $R$ between $C_1$ and $C_2$.
        //
        // Let $C_1$ take $k_1$ elements from $L$ and $k_1$ elements from $R$.
        // Let $C_2$ take $k_2$ elements from $L$ and $k_2$ elements from $R$.
        // This is not quite right, because $C_2$ needs elements smaller than $a_n$, and $C_1$ needs elements larger than $a_{n-1}$.
        //
        // The elements $a_0, \dots, a_{n-2}$ are available to be "smaller" elements for $a_{n-1}$ in $C_1$ AND "smaller" elements for $a_n$ in $C_2$.
        // The elements $a_{n+1}, \dots, a_{2n-1}$ are available to be "larger" elements for $a_{n-1}$ in $C_1$ AND "larger" elements for $a_n$ in $C_2$.
        //
        // Let's try to make $C_1$ have $a_{n-1}$ as median and $C_2$ have $a_n$ as median.
        //
        // $C_1$ must contain $a_{n-1}$.
        // $C_2$ must contain $a_n$.
        //
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ to the left of $a_{n-1}$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ to the right of $a_n$.
        //
        // Let $C_1$ take $k$ elements from $a_0, \dots, a_{n-2}$ and $k$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        // This is possible if $k \le n-1$.
        // The size of $C_1$ would be $2k+1$. This is always odd.
        //
        // The remaining students are:
        // $(n-1-k)$ students from $a_0, \dots, a_{n-2}$.
        // $(n-1-k)$ students from $a_{n+1}, \dots, a_{2n-1}$.
        // These, along with $a_n$, must form $C_2$.
        // The size of $C_2$ would be $1 + (n-1-k) + (n-1-k) = 1 + 2(n-1-k)$.
        // This is also always odd.
        //
        // So, we can always form two classes with $a_{n-1}$ and $a_n$ as medians.
        // For example, pick $k=0$.
