#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<ElementB> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // The optimal strategy is to pair the largest A_i with the largest B_i,
    // the second largest A_i with the second largest B_i, and so on.
    // This means if A is sorted ascending and B is sorted ascending,
    // we pair A[i] with B[i].
    // However, the problem asks for A' to be a permutation of A,
    // and the output should be A' in the original order of B.
    // So, if B_sorted[j] was originally B[k], then A_sorted[j] should be A'[k].

    std::vector<long long> result_a_prime(m);

    for (int i = 0; i < m; ++i) {
        // a_elements[i] is the i-th smallest value from original A.
        // b_elements[i] is the i-th smallest value from original B.
        // We want to assign a_elements[i].value to the position corresponding to b_elements[i].original_index.
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> max_prefix(n + 1, 0);
    std::vector<bool> seen_prefix(n + 1, false);
    bool is_prefix_perm = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > i + 1 || seen_prefix[a[i]]) {
            is_prefix_perm = false;
        }
        seen_prefix[a[i]] = true;
        max_prefix[i + 1] = std::max(max_prefix[i], a[i]);
        if (max_prefix[i + 1] != i + 1) { // If max element is not current length, it's not a permutation
            is_prefix_perm = false;
        }
        // Store whether prefix a[0...i] is a permutation of length i+1
        // This is true if is_prefix_perm is true AND max_prefix[i+1] == i+1
        // The max_prefix[i+1] == i+1 check is already incorporated into is_prefix_perm logic
        // by checking a[i] > i+1. If a[i] <= i+1 and seen_prefix[a[i]] is false,
        // and all previous elements were valid, then max_prefix[i+1] will be i+1.
        // The only way max_prefix[i+1] != i+1 is if some a[j] > i+1 for j <= i,
        // or if some number from 1 to i+1 is missing.
        // The `a[i] > i+1` check handles the first.
        // The `seen_prefix[a[i]]` check handles distinctness.
        // If all elements are distinct and <= i+1, and max is i+1, it's a permutation.
        // The `is_prefix_perm` flag correctly tracks this.
        max_prefix[i + 1] = is_prefix_perm; // Use max_prefix to store boolean for convenience
    }

    std::vector<int> max_suffix(n + 1, 0);
    std::vector<bool> seen_suffix(n + 1, false);
    bool is_suffix_perm = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > current_len || seen_suffix[a[i]]) {
            is_suffix_perm = false;
        }
        seen_suffix[a[i]] = true;
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
        if (max_suffix[i] != current_len) {
            is_suffix_perm = false;
        }
        max_suffix[i] = is_suffix_perm; // Use max_suffix to store boolean for convenience
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (max_prefix[l1] && max_suffix[l1]) { // max_prefix[l1] is true if a[0...l1-1] is perm of length l1
                                                 // max_suffix[l1] is true if a[l1...n-1] is perm of length l2
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
