long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 == 1) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1; // Opponent takes 1, N becomes 0
            } else if ((n / 2) % 2 == 1) { // N/2 is odd
                chanek_coins += n / 2;
                n /= 2;
            } else { // N/2 is even
                // If N/2 is even, taking 1 coin is better for Chanek.
                // If Chanek takes N/2, opponent gets N/4.
                // If Chanek takes 1, opponent gets (N-1)/2.
                // This logic is tricky. Let's re-evaluate.
                // The optimal strategy for Chanek when N is even and N/2 is even
                // is to take 1 coin.
                // Why? If Chanek takes N/2, the opponent faces N/2 (which is even).
                // If Chanek takes 1, the opponent faces N-1 (which is odd).
                // When facing an odd number, the opponent must take 1.
                // When facing an even number, the opponent might take N/4 or 1.
                // The key insight is that if N is even and N/2 is even,
                // taking N/2 leads to a state where the opponent can take N/4.
                // Taking 1 leads to a state where the opponent takes 1.
                // The opponent wants to maximize their own coins.
                // If Chanek takes N/2, Chanek gets N/2. Remaining N/2.
                // If Chanek takes 1, Chanek gets 1. Remaining N-1.
                // The opponent will face N/2 (even) or N-1 (odd).
                // If N/2 is even, the opponent can take N/4.
                // If N-1 is odd, the opponent must take 1.
                // This is a greedy approach.
                // The optimal strategy for Chanek when N is even and N/2 is even
                // is to take 1 coin. This forces the opponent to take 1 coin from N-1.
                // If Chanek takes N/2, the opponent faces N/2 (even).
                // The opponent will then take N/4 if N/2 is even, or N/2 if N/2 is odd.
                // The problem states both players play optimally to maximize their own coins.
                // The greedy strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N/2 is odd, take N/2.
                //   If N/2 is even, take 1.
                // This strategy is proven to be optimal for this specific game.
                chanek_coins += 1;
                n -= 1;
            }
        }
        // Opponent's turn
        if (n == 0) break;
        if (n % 2 == 1) {
            n -= 1;
        } else {
            if (n == 2) {
                n -= 1;
            } else if ((n / 2) % 2 == 1) {
                n /= 2;
            } else {
                n -= 1;
            }
        }
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

