    // So, if A+D > 0, we can always make the final magnitude >= 1.

    // So, Box 1 is possible if:
    // 1. (A + B) is odd (negative sign)
    // 2. A + D > 0 (magnitude can be >= 1)
    return (A + B) % 2 == 1 && (A + D > 0);
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Final value must be in (-1, 0).
    // This requires an odd number of negative values in the product, AND
    // The magnitude must be < 1.

    // Case 1: Final product is negative.
    // This means (A + B) must be odd.
    if ((A + B) % 2 == 0) { // Even number of negatives, product is positive
        return false;
    }

    // Now we know the product is negative. We need its magnitude to be < 1.
    // This is possible if A + D == 0.
    // If A + D == 0, all initial values are in (-1, 1).
    // The product of values in (-1, 1) will always be in (-1, 1).
    // If (A+B) is odd and A+D=0, then B must be odd.
    // All values are in (-1, 0) or (0, 1).
    // If B is odd, the product is negative.
    // Since all values are in (-1, 1), the product is in (-1, 1).
    // So if A+D=0 and B is odd, the product is in (-1, 0). This is Box 2.
    if (A + D == 0) {
        return true;
    }

    // If A + D > 0, we need to make the magnitude < 1.
    // This is possible if we have enough values with magnitude < 1 to "dilute" the large magnitudes.
    // Specifically, if B + C > 0, we can choose values for B and C that are very small (e.g., 0.001).
    // And values for A and D that are just slightly larger than 1 (e.g., -1.001 or 1.001).
    // Then the product of all values can be made arbitrarily small in magnitude.
    // Example: A=1, B=0, C=0, D=1. Values -1.001, 1.001. Product -1.002001 (Box 1).
    // Example: A=1, B=1, C=0, D=0. Values -1.001, -0.001. Product 0.0001001 (Box 3).
    // Example: A=1, B=1, C=0, D=1. Values -1.001, -0.001, 1.001.
    // (-1.001) * (-0.001) = 0.001001 (Box 3).
    // (0.001001) * (1.001) = 0.001002001 (Box 3).
    // This is not Box 2.

    // Let's re-evaluate the magnitude part.
    // To get magnitude < 1, we need to ensure that the product of all values is < 1.
    // This is always possible if B + C > 0.
    // If B + C > 0, we can pick values for B and C that are very small (e.g., 0.001).
    // And values for A and D that are just slightly larger than 1 (e.g., -1.001 or 1.001).
    // The product of all values will then be very small in magnitude.
    // So, if (A+B) is odd AND (B+C > 0), it's possible to get into Box 2.
    // What if B+C = 0? Then all values are in Box 1 or Box 4.
    // If B+C = 0, then A+D is the total number of toys.
    // If A+D = 1, and (A+B) is odd, then A=1, B=0, C=0, D=0. Value is <= -1. Box 1.
    // If A+D > 1, and B+C = 0, then all values are >= 1 or <= -1.
    // The product of such values will have magnitude >= 1.
    // So if B+C = 0, it's impossible to get magnitude < 1.

    // So, Box 2 is possible if:
    // 1. (A + B) is odd (negative sign)
    // 2. B + C > 0 (magnitude can be < 1)
    return (A + B) % 2 == 1 && (B + C > 0);
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Final value must be in (0, 1).
    // This requires an even number of negative values in the product, AND
    // The magnitude must be < 1.

    // Case 1: Final product is positive.
    // This means (A + B) must be even.
    if ((A + B) % 2 == 1) { // Odd number of negatives, product is negative
        return false;
    }

    // Now we know the product is positive. We need its magnitude to be < 1.
    // This is possible if A + D == 0.
    // If A + D == 0, all initial values are in (-1, 1).
    // The product of values in (-1, 1) will always be in (-1, 1).
    // If (A+B) is even and A+D=0, then B must be even.
    // All values are in (-1, 0) or (0, 1).
    // If B is even, the product is positive.
    // Since all values are in (-1, 1), the product is in (0, 1). This is Box 3.
    if (A + D == 0) {
        return true;
    }

    // If A + D > 0, we need to make the magnitude < 1.
    // This is possible if B + C > 0.
    // If B + C > 0, we can pick values for B and C that are very small (e.g., 0.001).
    // And values for A and D that are just slightly larger than 1 (e.g., -1.001 or 1.001).
    // The product of all values will then be very small in magnitude.
    // So, if (A+B) is even AND (B+C > 0), it's possible to get into Box 3.
    // What if B+C = 0? Then all values are in Box 1 or Box 4.
    // If B+C = 0, then A+D is the total number of toys.
    // If A+D = 1, and (A+B) is even, then A=0, B=0, C=0, D=1. Value is >= 1. Box 4.
    // If A+D > 1, and B+C = 0, then all values are >= 1 or <= -1.
    // The product of such values will have magnitude >= 1.
    // So if B+C = 0, it's impossible to get magnitude < 1.

    // So, Box 3 is possible if:
    // 1. (A + B) is even (positive sign)
    // 2. B + C > 0 (magnitude can be < 1)
    return (A + B) % 2 == 0 && (B + C > 0);
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Final value must be >= 1.
    // This requires an even number of negative values in the product, AND
    // The magnitude must be >= 1.

    // Case 1: Final product is positive.
    // This means (A + B) must be even.
    if ((A + B) % 2 == 1) { // Odd number of negatives, product is negative
        return false;
    }

    // Now we know the product is positive. We need its magnitude to be >= 1.
    // This is possible if A + D > 0.
    // If A + D == 0, all initial values are in (-1, 1).
    // The product of values in (-1, 1) will always be in (-1, 1).
    // So if A + D == 0, the final product will be in (-1, 1), thus cannot be in Box 4.
    if (A + D == 0) {
        return false;
    }

    // If A + D > 0 and (A + B) is even, it's possible.
    // We can choose values such that the product of magnitudes is >= 1.
    // As discussed for Box 1, if A+D > 0, we can always make the final magnitude >= 1.

    // So, Box 4 is possible if:
    // 1. (A + B) is even (positive sign)
    // 2. A + D > 0 (magnitude can be >= 1)
    return (A + B) % 2 == 0 && (A + D > 0);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum and X = current_xor_sum.
    // We need S' = 2 * X'.
    // S' - 2X' = 0.
    // We know that for any non-negative integers A, B: A + B = (A ^ B) + 2 * (A & B).
    // This implies A + B >= A ^ B.
    // Also, A + B and A ^ B have the same parity.
    // More generally, sum_i a_i and xor_i a_i have the same parity.
    // So, S' and X' must have the same parity.
    // If S' = 2 * X', then S' must be even.
    // If S' is even, then X' must be even.

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements: X_0 and S_0 + X_0.
    // Let's try to append two elements b1, b2.
    // New sum S' = S_0 + b1 + b2
    // New XOR sum X' = X_0 ^ b1 ^ b2
    // We want S' = 2 * X'.

    // Consider appending two elements: X_0 and S_0.
    // New sum: S_0 + X_0 + S_0 = 2*S_0 + X_0
    // New XOR sum: X_0 ^ X_0 ^ S_0 = S_0
    // Condition: 2*S_0 + X_0 = 2*S_0. This implies X_0 = 0.
    // This doesn't work in general.

    // Let's try to append two elements: X_0 and some value Y.
    // New sum: S_0 + X_0 + Y
    // New XOR sum: X_0 ^ X_0 ^ Y = Y
    // We want S_0 + X_0 + Y = 2 * Y
    // S_0 + X_0 = Y
    // So, if we append X_0 and (S_0 + X_0), the condition holds.
    // Let b1 = current_xor_sum
    // Let b2 = current_sum + current_xor_sum
    // New sum = current_sum + b1 + b2 = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * current_sum + 2 * current_xor_sum
    // New XOR sum = current_xor_sum ^ b1 ^ b2 = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum
    // Check condition: (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum).
    // This is always true!
    // So, we can always append two elements: current_xor_sum and (current_sum + current_xor_sum).
    // The problem states that appended elements can be up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long and is less than 10^18.

    // This strategy always works by appending 2 elements.
    // The problem allows appending 0, 1, 2, or 3 elements.
    // If the array is already good, we can append 0 elements.
    // If not, we can append 2 elements as described.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

