#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's to a fixed length (e.g., 18 for max 10^18-1, or 19 for 10^18)
    // The problem states pattern length no more than 18.
    // If a number is 10^18, it has 19 digits. The example 92, 2212, 50, 414 match 010.
    // 92: 010 (padded 092) -> 010. Matches.
    // 2212: 010 (padded 02212) -> 0010. Matches.
    // 50: 010 (padded 050) -> 010. Matches.
    // 414: 010 (padded 0414) -> 010. Matches.
    // This implies padding with 0s from the left for both number and pattern.
    // So, we need to store the pattern for the number up to a maximum length, say 18.
    // If a number is 10^18, its parity pattern is 1 followed by 18 '0's.
    // The problem states "length no more than 18" for the pattern.
    // Let's use a fixed length of 18 for internal storage.
    // If a number is 10^18, its pattern is 100...0 (19 digits).
    // The problem implies we should consider the pattern up to the length of the query pattern.
    // However, to use a map, we need a canonical form.
    // The example 10^18 is not explicitly handled for its 19th digit.
    // Let's assume the maximum relevant length is 18 digits.
    // For 10^18, it's 1 followed by 18 zeros. The parity pattern would be '1' followed by 18 '0's.
    // If we truncate to 18 digits, it would be 18 '0's. This is incorrect.
    // The problem says "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // "Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should align from the right.
    // A number like 10^18 (1 followed by 18 zeros) has 19 digits.
    // Its parity pattern is '1' (for the 1) followed by 18 '0's.
    // If the query pattern is "0", it matches the last digit. 10^18 ends in 0 (even), so it matches.
    // If the query pattern is "1", it matches the last digit. 10^18 ends in 0 (even), so it does not match.
    // If the query pattern is "00", it matches the last two digits. 10^18 ends in 00 (even, even), so it matches.
    // This implies we need to store the full parity pattern for the number.
    // The maximum length of a number is 19 digits (for 10^18).
    // So, we should pad to 19 digits.
    while (pattern_str.length() < 19) { // Max 19 digits for 10^18
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to match the fixed length
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means we should pad the query pattern to the same fixed length as the stored patterns.
            // The stored patterns are 19 characters long.
            std::string padded_s = s;
            std::reverse(padded_s.begin(), padded_s.end()); // Reverse to align from right
            while (padded_s.length() < 19) {
                padded_s += '0';
            }
            // No need to reverse back, map keys are already reversed.
            // The get_parity_pattern function generates a reversed string.
            // So, if s = "010", it means 0 for 1st digit, 1 for 2nd, 0 for 3rd.
            // The stored pattern for 92 is "0100...0" (reversed).
            // So, we need to reverse the query pattern s to match the stored keys.
            // Example: s = "010". Reversed s is "010". Padded to 19: "01000...0".
            // This matches the reversed pattern of 92.
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_total_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Cost for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Cost for items taken from the right
        // These are w[n-(n-i)]...w[n-1]
        // Which is w[i]...w[n-1]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive same-side picks
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items from left. The last item taken must be from the left.
            // The difference is left_count - right_count.
            // If left_count - right_count > 1, there are (left_count - right_count - 1) extra left items
            // that must have been taken consecutively after a right item, or at the very beginning.
            // The penalty applies if the number of left items exceeds the number of right items by more than 1.
            // The number of "extra" left items that must have been taken consecutively is (left_count - right_count - 1).
            // Each such extra item incurs a Ql penalty.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items from right. The last item taken must be from the right.
            // The difference is right_count - left_count.
            // If right_count - left_count > 1, there are (right_count - left_count - 1) extra right items
            // that must have been taken consecutively after a left item, or at the very beginning.
            // The penalty applies if the number of right items exceeds the number of left items by more than 1.
            // The number of "extra" right items that must have been taken consecutively is (right_count - left_count - 1).
            // Each such extra item incurs a Qr penalty.
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count or |left_count - right_count| == 1, no penalty is added.
        // This is because we can always alternate or end with the side that has one more item,
        // avoiding consecutive picks of the same side beyond the first one.

        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    // q can be up to 10^9, so its prime factors are at most sqrt(10^9) approx 31622
    // or one large prime factor.
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q is still greater than 1, it means it's a prime factor itself
    if (temp_q > 1) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        // The algorithm terminates if and only if it's possible to reach a state
        // where all 3-character substrings are permutations of 'x', 'y', 'z'
        // AND they are specifically "zyx", "xzy", or "yxz".
        // This implies that the counts of 'x', 'y', 'z' in any 3-character substring
        // must be 1, 1, 1.
        // If the counts of 'x', 'y', 'z' in the entire substring s[l..r] are too
        // unbalanced, it's impossible to achieve this state.
        // Specifically, if the difference between the maximum and minimum count
        // of any character ('x', 'y', 'z') is greater than 1, then it's impossible
        // to arrange them such that every 3-char substring has one of each.
        // For example, if counts are (5, 1, 1), then you have 3 'x's left over
        // after forming two 'xyz' groups. These 3 'x's must form a 3-char substring
        // "xxx", which is not "zyx", "xzy", or "yxz".
        // The algorithm would pick "xxx", rearrange it, and continue indefinitely.
        // Thus, the condition for termination is that the counts of 'x', 'y', 'z'
        // in the substring s[l..r] must differ by at most 1.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_val = 0; pivot_val <= 9; ++pivot_val) {
        char last1 = '0' - 1; // Represents a value smaller than any digit
        char first2 = '9' + 1; // Represents a value larger than any digit
        bool possible_pivot = true;

        // First pass: determine colors based on pivot_val
        // Digits < pivot_val are candidates for color 1
        // Digits > pivot_val are candidates for color 2
        // Digits == pivot_val need careful assignment

        // Initialize result with a temporary scheme:
        // < pivot_val -> 1
        // > pivot_val -> 2
        // == pivot_val -> 2 (initially, will be refined)
        for (int i = 0; i < n; ++i) {
            if (s[i] < (char)('0' + pivot_val)) {
                result[i] = '1';
            } else {
                result[i] = '2';
            }
        }

        // Second pass: refine assignments for digits == pivot_val
        // All digits == pivot_val that appear *before* the first digit > pivot_val
        // should be color 1 if possible.
        // All digits == pivot_val that appear *after* the first digit > pivot_val
        // should be color 2.

        // Find the first digit that is strictly greater than pivot_val
        int first_greater_than_pivot_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] > (char)('0' + pivot_val)) {
                first_greater_than_pivot_idx = i;
                break;
            }
        }

        if (first_greater_than_pivot_idx != -1) {
            // If there are digits > pivot_val, then digits == pivot_val
            // before this point can be 1, and after this point must be 2.
            for (int i = 0; i < n; ++i) {
                if (s[i] == (char)('0' + pivot_val)) {
                    if (i < first_greater_than_pivot_idx) {
                        result[i] = '1';
                    } else {
                        result[i] = '2';
                    }
                }
            }
        } else {
            // If all digits are <= pivot_val, then all digits == pivot_val can be 1.
            // (This means all digits are <= pivot_val, and all digits > pivot_val are colored 2,
            // but there are no such digits. So all digits are colored 1 or 2 based on pivot_val.
            // If all digits are <= pivot_val, then all digits == pivot_val can be 1.)
            // The initial assignment (all == pivot_val to 2) is fine, or all to 1 is fine.
            // Let's try to assign all == pivot_val to 1.
            for (int i = 0; i < n; ++i) {
                if (s[i] == (char)('0' + pivot_val)) {
                    result[i] = '1';
                }
            }
        }

        // Validate the constructed coloring
        char last_digit_color1 = '0' - 1;
        char last_digit_color2 = '0' - 1;
        char first_digit_color2 = '9' + 1;

        for (int i = 0; i < n; ++i) {
            if (result[i] == '1') {
                if (s[i] < last_digit_color1) {
                    possible_pivot = false;
                    break;
                }
                last_digit_color1 = s[i];
            } else { // result[i] == '2'
                if (s[i] < last_digit_color2) {
                    possible_pivot = false;
                    break;
                }
                last_digit_color2 = s[i];
                if (first_digit_color2 == '9' + 1) { // If this is the first digit assigned to color 2
                    first_digit_color2 = s[i];
                }
            }
        }

        if (possible_pivot) {
            if (last_digit_color1 <= first_digit_color2) {
                found_solution = true;
                break;
            }
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;

    // (n * (n + 1)) / 2
    // We need to compute (n * (n + 1)) * (2^-1) mod MOD
    // Since MOD is prime (10^9 + 7), 2^-1 mod MOD is (MOD + 1) / 2
    long long inv2 = (MOD + 1) / 2;

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    long long product = (term1 * term2) % MOD;
    long long result = (product * inv2) % MOD;

    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // If b = 1, then x % b is always 0.
    // The condition x % b != 0 cannot be satisfied.
    // So, there are no nice integers.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // The sum is Sum = sum_{k=1 to a} sum_{r=1 to b-1} [r * (k * b + 1)]
    // This can be rewritten as:
    // Sum = (sum_{k=1 to a} (k * b + 1)) * (sum_{r=1 to b-1} r)

    // Calculate sum_{r=1 to b-1} r
    // This is the sum of an arithmetic series: (b-1) * b / 2
    long long sum_r = sum_arithmetic_series(b - 1);

    // Calculate sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * (sum_{k=1 to a} k) + a
    // sum_{k=1 to a} k is a * (a + 1) / 2
    long long sum_k = sum_arithmetic_series(a);

    long long term_b_sum_k = (b % MOD * sum_k) % MOD;
    long long sum_kb_plus_1 = (term_b_sum_k + (a % MOD)) % MOD;

    // Final result is (sum_kb_plus_1 * sum_r) % MOD
    long long total_sum = (sum_kb_plus_1 * sum_r) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> present_in_s(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s[s[i] - 'a'] = true;
        if (i > 0) {
            adj[s[i] - 'a'].insert(s[i-1]);
            adj[s[i-1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i] && adj[i].size() <= 1) { // Start of a chain or isolated char
            char current_char = (char)('a' + i);

            // Build the chain forward
            while (current_char != 0 && !visited[current_char - 'a']) {
                layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                current_char = next_char;
            }
        }
    }

    // Check if all present_in_s characters were included in the layout
    // This implicitly checks for cycles or multiple chains starting from non-degree-1 nodes
    // If a character is present in 's' but not in 'layout', it means it was part of a cycle
    // or a chain that didn't start with a degree-1 node (which is impossible if all degrees are <= 2)
    // or a chain that was already visited from another starting point (which means it's a cycle)
    for(int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in 's'
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

