void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 1 means can move left (x_c - 1, y_c)
        // If f1 = 0, robot cannot move left.
        // This means the target X must be >= current x.
        // So, X >= x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }

        // f2 = 1 means can move up (x_c, y_c + 1)
        // If f2 = 0, robot cannot move up.
        // This means the target Y must be <= current y.
        // So, Y <= y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }

        // f3 = 1 means can move right (x_c + 1, y_c)
        // If f3 = 0, robot cannot move right.
        // This means the target X must be <= current x.
        // So, X <= x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }

        // f4 = 1 means can move down (x_c, y_c - 1)
        // If f4 = 0, robot cannot move down.
        // This means the target Y must be >= current y.
        // So, Y >= y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // The problem guarantees that if a point exists, one exists within [-10^5, 10^5].
        // We need to pick any valid point.
        // The intersection of all valid ranges is [min_x, max_x] for X and [min_y, max_y] for Y.
        // We can pick min_x and min_y as the target coordinates.
        // However, min_x and min_y can be outside [-10^5, 10^5] if the initial coordinates
        // or movement restrictions push them there.
        // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
        // This implies we should clamp the chosen coordinates if they fall outside this range,
        // but only if a valid point exists within the clamped range.
        // A simpler interpretation is that if a solution exists, *at least one* solution
        // has coordinates within [-10^5, 10^5].
        // So, we can just pick min_x and min_y, and if they are within the guaranteed range,
        // they will be valid. If they are outside, but a solution exists, then there must be
        // another solution within [-10^5, 10^5].
        // Let's just pick min_x and min_y. The problem statement implies these will be fine.
        // The maximum coordinate value is 10^5. If a robot is at 10^5 and cannot move right,
        // max_x becomes 10^5. If another robot is at -10^5 and cannot move left, min_x becomes -10^5.
        // So min_x and max_x will be within [-10^5, 10^5] if they are derived from robot positions.
        // The initial large values are just to ensure they don't restrict the range initially.
        // After processing all robots, min_x and max_x will be within the range of robot coordinates.
        // The problem statement guarantees that if a solution exists, one exists with |X|, |Y| <= 10^5.
        // So, simply outputting min_x and min_y (which are valid choices if min_x <= max_x and min_y <= max_y)
        // should be fine.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

