#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_first = 0; k_first < L; ++k_first) { // Iterate through all possible initial shifts k
        char first_char_val = s[k_first]; // This is t[0]

        // Find all k' such that s[k'] == first_char_val
        // These are the candidate shifts for Vasya after seeing t[0]
        std::vector<int> candidate_k_indices;
        for (int idx : char_indices[first_char_val - 'a']) {
            candidate_k_indices.push_back(idx);
        }

        if (candidate_k_indices.size() == 1) {
            // If only one k' matches t[0], Vasya already wins.
            // This k_first is uniquely determined.
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k' match t[0], Vasya needs to pick a position p.
        // He wants to maximize the probability of winning for this specific t[0].
        double max_win_prob_for_t0 = 0.0;

        // Iterate through all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many candidate k' values are uniquely determined.
            int uniquely_determined_count = 0;

            // Group candidates by (s[k'], s[(k'+p)%L])
            // A map from pair<char, char> to vector<int> (list of k' values)
            std::vector<std::vector<int>> groups_by_pair(26 * 26);

            for (int k_prime : candidate_k_indices) {
                char char_at_p = s[(k_prime + p) % L];
                int group_idx = (first_char_val - 'a') * 26 + (char_at_p - 'a');
                groups_by_pair[group_idx].push_back(k_prime);
            }

            for (const auto& group : groups_by_pair) {
                if (group.size() == 1) {
                    // If a group has only one k', it means this k' is uniquely determined
                    // by (t[0], t[p]).
                    // We need to check if this unique k' is the actual k_first.
                    // If it is, then Vasya wins for this k_first.
                    if (group[0] == k_first) {
                        uniquely_determined_count = 1; // Found the actual k_first, it's unique.
                        break; // No need to check other groups for this p, we only care if k_first is unique.
                    }
                }
            }

            // If k_first was uniquely determined by this p, then Vasya wins for this k_first.
            // The probability of winning for this k_first is 1.0 if he chooses this p.
            // We want to maximize this over all p.
            max_win_prob_for_t0 = std::max(max_win_prob_for_t0, (double)uniquely_determined_count);
        }
        total_win_prob += max_win_prob_for_t0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // balance_left[i] = (count of 1s) - (count of 2s) for jars 1 to i
    std::vector<int> balance_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_left[i + 1] = balance_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the right half (jars n+1 to 2n)
    // balance_right[i] = (count of 1s) - (count of 2s) for jars 2n-i+1 to 2n
    // We want to store the balance of suffix of length i, starting from 2n-i+1
    // So, balance_right[k] is the balance of jars 2n-k+1 to 2n
    std::vector<int> balance_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        balance_right[i + 1] = balance_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the right to achieve a certain balance
    // key: balance, value: number of jars eaten from right
    std::map<int, int> right_balance_to_eaten_count;
    for (int k = 0; k <= n; ++k) {
        int current_balance = balance_right[k];
        if (right_balance_to_eaten_count.find(current_balance) == right_balance_to_eaten_count.end()) {
            right_balance_to_eaten_count[current_balance] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with maximum possible jars eaten

    // Iterate through all possible numbers of jars eaten from the left (0 to n)
    for (int k_left = 0; k_left <= n; ++k_left) {
        int current_left_balance = balance_left[k_left];
        // We need to find k_right such that balance_left[k_left] + balance_right[k_right] == 0
        // This means balance_right[k_right] == -balance_left[k_left]
        int target_right_balance = -current_left_balance;

        if (right_balance_to_eaten_count.count(target_right_balance)) {
            int k_right = right_balance_to_eaten_count[target_right_balance];
            min_jars_eaten = std::min(min_jars_eaten, k_left + k_right);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

