int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for two specific inputs: 0 and 1023
    // We need to track how 0 and 1023 transform after all operations.
    // Let's call them current_val_0 and current_val_1023.
    // Initially, current_val_0 = 0 and current_val_1023 = 1023.
    int current_val_0 = 0;
    int current_val_1023 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_val_0 &= val;
            current_val_1023 &= val;
        } else if (op_char == '|') {
            current_val_0 |= val;
            current_val_1023 |= val;
        } else if (op_char == '^') {
            current_val_0 ^= val;
            current_val_1023 ^= val;
        }
    }

    // Now, current_val_0 is the result of applying all operations to 0.
    // And current_val_1023 is the result of applying all operations to 1023.

    // We need to find three constants A, B, C such that:
    // For any input x (0 <= x <= 1023), the final result is ((x | A) & B) ^ C.
    // Let's analyze the effect of these operations on each bit.
    // For a bit 'b' (0 to 9):
    // Let x_b be the b-th bit of x.
    // Let A_b, B_b, C_b be the b-th bits of A, B, C respectively.
    // The b-th bit of the result is ((x_b | A_b) & B_b) ^ C_b.

    // Case 1: Input bit x_b = 0
    // The b-th bit of current_val_0 is ((0 | A_b) & B_b) ^ C_b = (A_b & B_b) ^ C_b.
    // Let's denote this as R0_b.

    // Case 2: Input bit x_b = 1
    // The b-th bit of current_val_1023 is ((1 | A_b) & B_b) ^ C_b = (1 & B_b) ^ C_b = B_b ^ C_b.
    // Let's denote this as R1_b.

    // We need to find A_b, B_b, C_b for each bit b (0 to 9).
