    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n); // Initial array values
    std::vector<long long> current_delta(n, 0); // Sum of d's applied to each index

    // Initialize b_i to a very large value, effectively positive infinity
    // This is because b_i + delta_i <= m_i implies b_i <= m_i - delta_i.
    // We want to find the largest possible b_i that satisfies all constraints.
    // So, b_i will be min(m_k - delta_k) over all type 2 ops k that cover i.
    // If no type 2 op covers i, b_i can be anything, so we set it to 0.
    // However, to correctly handle the min operation, we initialize it to a large value.
    // A value like 10^9 is sufficient as per problem constraints.
    for (int i = 0; i < n; ++i) {
        b[i] = 1'000'000'000LL; // Max allowed initial value
    }

    // First pass: Determine upper bounds for b_i
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Reset current_delta for the second pass
    std::fill(current_delta.begin(), current_delta.end(), 0);

    // Second pass: Verify conditions
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = -2'000'000'000'000'000'000LL; // Sufficiently small
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, b[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

