                total_d_effect += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a_str, b_str;
    std::cin >> a_str >> b_str;

    int count_ones_a = 0;
    for (char c : a_str) {
        if (c == '1') {
            count_ones_a++;
        }
    }

    // If count_ones_a is even, parity is 0. If odd, parity is 1.
    // We can always add a '0' to the end if parity is 0, or a '1' if parity is 1.
    // This means we can always increase the number of '1's by 1 if parity is 1,
    // or keep it the same if parity is 0.
    // The maximum number of '1's we can achieve in a string of length L
    // is L.
    // The minimum number of '1's we can achieve in a string of length L
    // is 0.
    //
    // The key insight is that we can always increase the length of 'a'
    // by appending its parity.
    // If current_parity is 0, we append '0'. The number of '1's remains count_ones_a.
    // If current_parity is 1, we append '1'. The number of '1's becomes count_ones_a + 1.
    //
    // So, if we have `count_ones_a` '1's, we can always reach `count_ones_a` '1's
    // in any string of length >= |a|.
    // If `count_ones_a` is odd, we can also reach `count_ones_a + 1` '1's
    // in any string of length >= |a|+1.
    //
    // Let `max_ones_a` be the maximum number of '1's we can have in a string
    // that is derived from `a` and has length at least `|a|`.
    // If `count_ones_a` is odd, we can append '1', making `count_ones_a + 1` '1's.
    // If `count_ones_a` is even, we can append '0', keeping `count_ones_a` '1's.
    // So, `max_ones_a` is `count_ones_a` if `count_ones_a` is even,
    // and `count_ones_a + 1` if `count_ones_a` is odd.
    // This can be simplified to `count_ones_a + (count_ones_a % 2)`.
    // This is the maximum number of '1's we can have in a string of length
    // at least `|a|` (or `|a|+1` if we appended a '1').
    //
    // Let's rephrase:
    // We can always extend string `a` to any length `L >= |a|`.
    // When we extend `a` by appending `parity(a)`, the number of ones either stays the same (if parity is 0)
    // or increases by one (if parity is 1).
    //
    // Let `current_ones` be the number of ones in the current string.
    // If `current_ones` is even, we append '0', `current_ones` remains even.
    // If `current_ones` is odd, we append '1', `current_ones` becomes even.
    //
    // This means that after at most one append operation, the number of ones in the string
    // will be even.
    //
    // So, if `count_ones_a` is even, we can maintain an even number of ones (by appending '0's)
    // as we extend the string.
    // If `count_ones_a` is odd, we can append '1', making the count `count_ones_a + 1` (which is even).
    // After this, we can maintain an even number of ones.
    //
    // So, the maximum number of '1's we can effectively have in a string of length `L`
    // that is derived from `a` is `count_ones_a` if `count_ones_a` is even,
    // and `count_ones_a + 1` if `count_ones_a` is odd.
    // Let this value be `max_possible_ones_from_a`.
    int max_possible_ones_from_a = count_ones_a + (count_ones_a % 2);

    int count_ones_b = 0;
    for (char c : b_str) {
        if (c == '1') {
            count_ones_b++;
        }
    }

    // For `b` to be a suffix of some `a'`, `a'` must be at least as long as `b`.
    // We can always extend `a` to be at least as long as `b`.
    // The question is whether the number of '1's in `b` is achievable.
    //
    // We need `count_ones_b` to be less than or equal to `max_possible_ones_from_a`.
    // And `count_ones_b` must be less than or equal to `|b|`. (This is always true by definition).
    //
    // Example 1: a="01011", b="0110"
    // |a|=5, count_ones_a=3 (odd)
    // max_possible_ones_from_a = 3 + (3%2) = 3 + 1 = 4.
    // |b|=4, count_ones_b=2.
    // Is count_ones_b <= max_possible_ones_from_a? 2 <= 4. Yes.
    // Output: YES. Correct.
    //
    // Example 2: a="0011", b="1110"
    // |a|=4, count_ones_a=2 (even)
    // max_possible_ones_from_a = 2 + (2%2) = 2 + 0 = 2.
    // |b|=4, count_ones_b=3.
    // Is count_ones_b <= max_possible_ones_from_a? 3 <= 2. No.
    // Output: NO. Correct.

    if (count_ones_b <= max_possible_ones_from_a) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise.
bool apply_median_smoothing(std::vector<int>& a) {
    int n = a.size();
    if (n < 3) return false; // Sequences of length < 3 are always stable by definition (only ends change)

    std::vector<int> b = a;
    bool changed = false;

    for (int i = 1; i < n - 1; ++i) {
        // b_i is the median of a_{i-1}, a_i, a_{i+1}
        // For 0s and 1s, this means b_i = 0 if sum <= 1, b_i = 1 if sum >= 2
        int sum = a[i - 1] + a[i] + a[i + 1];
        int new_val = (sum >= 2) ? 1 : 0;
        if (b[i] != new_val) {
            b[i] = new_val;
            changed = true;
        }
    }
    a = b;
    return changed;
}

