#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = std::numeric_limits<long long>::max();
    std::vector<int> best_partition(n);

    // Strategy 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    if (n >= 2) {
        long long current_goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value);
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                best_partition[a[i].original_index] = 1;
            }
        }
    } else { // n=1, this case is not possible based on constraints (n >= 2)
        min_goodness = 0; // No pairs, so max-min is 0
        best_partition[a[0].original_index] = 1;
    }

    // Strategy 2: a[0] in S1, a[1]...a[n-1] in S2.
    // min_f:
    //   - a[1]+a[2] (in S2)
    //   - a[0]+a[1]+h (a[0] in S1, a[1] in S2)
    //   min_f = min(a[1]+a[2], a[0]+a[1]+h)
    // max_f:
    //   - a[n-2]+a[n-1] (in S2)
    //   - a[0]+a[n-1]+h (a[0] in S1, a[n-1] in S2)
    //   max_f = max(a[n-2]+a[n-1], a[0]+a[n-1]+h)
    if (n >= 2) { // This strategy requires at least 2 elements for a[0] and a[1]
        long long current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        if (n == 2) { // Special case for n=2, only one pair (a[0], a[1])
            current_min_f = a[0].value + a[1].value + h;
        }

        long long current_max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    // Strategy 3: a[0]...a[n-2] in S1, a[n-1] in S2.
    // min_f:
    //   - a[0]+a[1] (in S1)
    //   - a[0]+a[n-1]+h (a[0] in S1, a[n-1] in S2)
    //   min_f = min(a[0]+a[1], a[0]+a[n-1]+h)
    // max_f:
    //   - a[n-3]+a[n-2] (in S1)
    //   - a[n-2]+a[n-1]+h (a[n-2] in S1, a[n-1] in S2)
    //   max_f = max(a[n-3]+a[n-2], a[n-2]+a[n-1]+h)
    if (n >= 2) { // This strategy requires at least 2 elements for a[0] and a[n-1]
        long long current_min_f = std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h);
        if (n == 2) { // Special case for n=2, only one pair (a[0], a[1])
            current_min_f = a[0].value + a[1].value + h;
        }

        long long current_max_f = std::max(a[n-3].value + a[n-2].value, a[n-2].value + a[n-1].value + h);
        if (n == 2) { // Special case for n=2, only one pair (a[0], a[1])
            current_max_f = a[0].value + a[1].value + h;
        } else if (n == 3) { // Special case for n=3, only one pair in S1: (a[0], a[1])
            current_max_f = std::max(a[0].value + a[1].value, a[1].value + a[2].value + h);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 1;
            }
            best_partition[a[n-1].original_index] = 2;
        }
    }

    // Strategy 4: a[0] and a[n-1] in S1, a[1]...a[n-2] in S2.
    // This strategy is only relevant if n >= 4.
    // If n=2, it's all in S1.
    // If n=3, it's a[0], a[2] in S1, a[1] in S2.
    // min_f:
    //   - a[0]+a[n-1] (in S1)
    //   - a[1]+a[2] (in S2)
    //   - a[0]+a[1]+h (a[0] in S1, a[1] in S2)
    //   min_f = min(a[0]+a[n-1], a[1]+a[2], a[0]+a[1]+h)
    // max_f:
    //   - a[0]+a[n-1] (in S1)
    //   - a[n-3]+a[n-2] (in S2)
    //   - a[n-1]+a[n-2]+h (a[n-1] in S1, a[n-2] in S2)
    //   max_f = max(a[0]+a[n-1], a[n-3]+a[n-2], a[n-1]+a[n-2]+h)
    if (n >= 3) { // Need at least 3 elements for a[0], a[1], a[n-1]
        long long current_min_f;
        long long current_max_f;

        if (n == 3) { // a[0], a[2] in S1; a[1] in S2
            current_min_f = std::min(a[0].value + a[2].value, a[0].value + a[1].value + h);
            current_max_f = std::max(a[0].value + a[2].value, a[2].value + a[1].value + h);
        } else { // n >= 4
            current_min_f = std::min({a[0].value + a[n-1].value, a[1].value + a[2].value, a[0].value + a[1].value + h});
            current_max_f = std::max({a[0].value + a[n-1].value, a[n-3].value + a[n-2].value, a[n-1].value + a[n-2].value + h});
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
            best_partition[a[n-1].original_index] = 1;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

